INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70110-0000-0000-0000-000000000001', 'faa70000-0000-0000-0000-000000000001', 'Lesson 1: What Part 107 Is and Who Needs It', '', ARRAY['Part 107 (14 CFR Part 107) is the FAA rulebook for small UAS - drones under 55 lb - flown for non-recreational purposes.','The person responsible for a Part 107 flight is the Remote Pilot in Command (Remote PIC), who must hold a Remote Pilot Certificate.','The commercial-vs-recreational line is drawn by the PURPOSE of the flight, not by whether money changes hands.','Recreational flyers operate under 49 U.S.C. 44809 with the free TRUST test; commercial flyers operate under Part 107.','Break a recreational condition and the flight is judged under Part 107.']::text[], 1, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Define 14 CFR Part 107 and the small UAS it governs.','Distinguish commercial/non-recreational operations from recreational flying under 49 U.S.C. 44809.','Explain why even some ''free'' or non-paid flights still require a Part 107 certificate.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0001-0000-0000-000000000000', 'faa70110-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The rulebook for commercial drones</h3><p><strong>14 CFR Part 107</strong> is the section of the federal aviation regulations that governs <strong>small unmanned aircraft systems (sUAS)</strong> - drones weighing <strong>less than 55 pounds</strong> at takeoff - when they are flown for any purpose other than pure recreation. A drone operated under Part 107 is still an <em>aircraft</em> in the eyes of the FAA, and the person responsible for it is the <strong>Remote Pilot in Command (Remote PIC)</strong>. To act as a Remote PIC, you must hold a <strong>Remote Pilot Certificate with a small UAS rating</strong>, which is what this course prepares you to earn.</p><p>Part 107 exists because the National Airspace System is shared. The same sky used by airliners, helicopters, and crop dusters is also used by drones, so the FAA sets common rules - altitude limits, visibility minimums, airspace authorizations, and pilot knowledge standards - so that everyone can operate safely. Earning the certificate is the FAA''s way of confirming that you understand those rules <em>before</em> you put an aircraft in the air for work.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0001-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Commercial vs. recreational: the line that matters</h3><p>The FAA draws a bright line based on the <strong>purpose</strong> of the flight, not on whether money changes hands. There are two legal frameworks for civilian drones:</p><ul><li><strong>Part 107 (commercial / non-recreational):</strong> Any flight that is <em>not</em> strictly for personal enjoyment. This includes obvious paid work (surveying, real-estate photography, inspections, mapping) but also flights that further a business or organization even when no one is paid - for example, a volunteer taking aerial photos for a nonprofit, or an employee shooting footage for the company website.</li><li><strong>Recreational (49 U.S.C. 44809):</strong> Flights flown <em>strictly</em> for personal enjoyment, under a community-based organization''s safety guidelines, by a pilot who has passed the free <strong>TRUST</strong> test. The moment a recreational flight has any business, work, or other non-hobby purpose, it is no longer covered by 44809.</li></ul><p>If you break any condition of the recreational exception, your flight is judged <strong>under Part 107</strong> - and you may face the greater penalties that come with operating commercially without a certificate.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0001-0000-0000-000000000002', 'faa70110-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"It is the PURPOSE, not the paycheck. A flight done for free can still require Part 107. If the flight furthers a business, employer, or organization in any way, it is not ''strictly recreational'' and you need a Remote Pilot Certificate."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0001-0000-0000-000000000003', 'faa70110-0000-0000-0000-000000000001', 'table', '{"headers":["Topic","Recreational (44809)","Part 107"],"rows":[["Purpose of flight","Strictly hobby / personal enjoyment","Any non-recreational / commercial purpose"],["Pilot credential","TRUST test (free, no expiration)","Remote Pilot Certificate (UAG exam + TSA vetting)"],["Registration","One number can cover all your drones","Each drone individually registered"],["Waivers available?","No waivers","Waivers (107.205) and airspace authorizations"],["If you break a rule","Flight is judged under Part 107","Subject to Part 107 enforcement"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0001-0000-0000-000000000004', 'faa70110-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Part 107 covers small unmanned aircraft that weigh less than 55 lb at takeoff (including payload). Aircraft 55 lb and over fall outside Part 107 and require separate FAA authorization."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0001-0000-0000-000000000005', 'faa70110-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A decision tree asking ''Is the flight strictly for personal enjoyment?'' - Yes leads to the recreational/44809 + TRUST path; No (any business or work purpose) leads to the Part 107 + Remote Pilot Certificate path."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0001-0000-0000-000000000006', 'faa70110-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Part 107 (14 CFR Part 107) is the FAA rulebook for small UAS - drones under 55 lb - flown for non-recreational purposes.","The person responsible for a Part 107 flight is the Remote Pilot in Command (Remote PIC), who must hold a Remote Pilot Certificate.","The commercial-vs-recreational line is drawn by the PURPOSE of the flight, not by whether money changes hands.","Recreational flyers operate under 49 U.S.C. 44809 with the free TRUST test; commercial flyers operate under Part 107.","Break a recreational condition and the flight is judged under Part 107."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70110-0000-0000-0000-000000000002', 'faa70000-0000-0000-0000-000000000001', 'Lesson 2: Eligibility and the Path to Certification', '', ARRAY['Eligibility: at least 16, able to read/speak/write/understand English, in safe physical and mental condition, pass the knowledge test, and pass TSA vetting.','No prior pilot certificate is required for the initial UAG test.','The process: study, get an FTN in IACRA, pass the UAG at a PSI center (70%), file Form 8710-13, clear TSA vetting, receive temporary then permanent certificate.','The temporary certificate (emailed after TSA clears) lets you begin flying commercially right away.','Part 61 pilots may substitute a free online course for the knowledge test.']::text[], 2, 35, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['List the eligibility requirements for a Remote Pilot Certificate.','Walk through the step-by-step certification process from IACRA account to permanent certificate.','Describe the role of PSI testing centers, the 8710-13 application, and TSA security vetting.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0002-0000-0000-000000000000', 'faa70110-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Are you eligible?</h3><p>Before the FAA will issue a Remote Pilot Certificate, you must meet a short list of eligibility requirements found in 14 CFR 107.61-107.65. To be eligible, a person must:</p><ul><li>Be at least <strong>16 years old</strong>.</li><li>Be able to <strong>read, speak, write, and understand English</strong> (this can be waived only for a medical reason such as a hearing or speech condition).</li><li>Be in a <strong>physical and mental condition</strong> to safely operate a small UAS.</li><li><strong>Pass</strong> the initial aeronautical knowledge test (the UAG exam) - or, if you already hold a current Part 61 pilot certificate, complete the equivalent free online course instead.</li><li>Be <strong>vetted by the TSA</strong> through a security background check, which runs automatically during the application.</li></ul><p>Notice what is <em>not</em> on the list: you do <strong>not</strong> need to already be an airplane or helicopter pilot. No prior pilot certificate is required to take the initial UAG test.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0002-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'text', '{"html":"<h3>The path to certification, step by step</h3><p>For someone with no prior pilot certificate, the journey from beginner to certificated Remote Pilot follows a predictable sequence:</p><ul><li><strong>1. Study.</strong> Learn the five knowledge areas (this course). Aim to score consistently above 85% on practice tests before you schedule the real exam.</li><li><strong>2. Get an FTN.</strong> Create an account in <strong>IACRA</strong> (Integrated Airman Certification and Rating Application) to obtain your <strong>FAA Tracking Number</strong>.</li><li><strong>3. Schedule and pass the UAG test</strong> at a <strong>PSI Services</strong> testing center, bringing a government photo ID. You need <strong>70%</strong> to pass.</li><li><strong>4. Apply.</strong> Complete <strong>FAA Form 8710-13</strong> (Remote Pilot Certificate application) through IACRA, using your knowledge test report.</li><li><strong>5. TSA vetting</strong> runs automatically in the background.</li><li><strong>6. Temporary certificate.</strong> Once vetting clears, you receive a <strong>temporary</strong> certificate by email - and may begin flying commercially immediately.</li><li><strong>7. Permanent certificate</strong> arrives later by mail.</li><li><strong>8. Register the drone</strong> (covered in Lesson 5).</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0002-0000-0000-000000000002', 'faa70110-0000-0000-0000-000000000002', 'callout', '{"type":"success","text":"The temporary certificate is what lets you start working. As soon as TSA vetting clears and your temporary certificate is issued by email, you are legally a Remote PIC - you do not have to wait for the plastic card in the mail."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0002-0000-0000-000000000003', 'faa70110-0000-0000-0000-000000000002', 'accordion', '{"sections":[{"title":"What if I already hold a Part 61 pilot certificate?","content":"<p>If you hold a current <strong>Part 61 pilot certificate</strong> (other than student pilot) and have completed a <strong>flight review within the previous 24 months</strong>, you may skip the in-person UAG knowledge test. Instead you complete a <strong>free online training course</strong> on FAASafety.gov, then apply through IACRA the same way. The eligibility, application, and TSA-vetting steps are otherwise the same.</p>","open":false},{"title":"What is IACRA, and what is the 8710-13?","content":"<p><strong>IACRA</strong> is the FAA''s online application system for airman certificates. Inside IACRA you fill out <strong>FAA Form 8710-13</strong>, the application specific to a remote pilot certificate. IACRA also issues your <strong>FAA Tracking Number (FTN)</strong>, which ties your test result to your application.</p>","open":false}]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0002-0000-0000-000000000004', 'faa70110-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A horizontal pipeline showing the certification steps - Study, IACRA/FTN, Pass UAG at PSI, File 8710-13, TSA vetting, Temporary certificate (email), Permanent certificate (mail), Register drone."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0002-0000-0000-000000000005', 'faa70110-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Eligibility: at least 16, able to read/speak/write/understand English, in safe physical and mental condition, pass the knowledge test, and pass TSA vetting.","No prior pilot certificate is required for the initial UAG test.","The process: study, get an FTN in IACRA, pass the UAG at a PSI center (70%), file Form 8710-13, clear TSA vetting, receive temporary then permanent certificate.","The temporary certificate (emailed after TSA clears) lets you begin flying commercially right away.","Part 61 pilots may substitute a free online course for the knowledge test."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70110-0000-0000-0000-000000000003', 'faa70000-0000-0000-0000-000000000001', 'Lesson 3: The UAG Knowledge Exam', '', ARRAY['The UAG exam is 60 multiple-choice questions (3 options each), 120 minutes, 70% to pass (~42 correct).','It is built from the Remote Pilot sUAS ACS and taken at a PSI testing center.','Fail and you must wait 14 calendar days to retake; a passing report is generally valid 24 calendar months to apply.','Five ACS areas: Regulations, Airspace, Weather, Loading & Performance, and Operations - with Operations the largest (35-45%).','Current chart images appear on the exam, so practice reading real sectional excerpts.']::text[], 3, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['State the format of the UAG exam - question count, time limit, and passing score.','Name the five ACS knowledge areas and their approximate weights.','Describe practical exam logistics: PSI centers, retake waiting period, and the modern chart images on the test.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0003-0000-0000-000000000000', 'faa70110-0000-0000-0000-000000000003', 'text', '{"html":"<h3>What the test looks like</h3><p>The initial exam is called the <strong>Unmanned Aircraft General - Small (UAG)</strong> knowledge test. It is built entirely from the <strong>Remote Pilot - Small UAS Airman Certification Standards (ACS)</strong>, the FAA document that lists everything you can be tested on. The format is consistent and worth memorizing:</p><ul><li><strong>60 multiple-choice questions</strong>, each with <strong>three options (A, B, C)</strong> and a single correct answer.</li><li><strong>2 hours (120 minutes)</strong> to complete the test - roughly two minutes per question.</li><li><strong>70% to pass</strong> - that means about <strong>42 of 60</strong> correct.</li><li>Taken at a <strong>PSI</strong> testing center; the fee is set by PSI (commonly around $175, and subject to change).</li></ul><p>If you do not pass, you must wait <strong>14 calendar days</strong> before retaking it. Your passing knowledge-test report is then valid for a period of time (generally 24 calendar months) for you to apply for the certificate, so apply promptly after you pass.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0003-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'text', '{"html":"<h3>The five knowledge areas and their weights</h3><p>The ACS organizes the test into <strong>five Areas of Operation</strong>. The approximate share each contributes to your 60 questions tells you where to focus your study. <strong>Operations</strong> is by far the largest area, and together <strong>Operations + Airspace</strong> make up roughly half to two-thirds of the exam.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0003-0000-0000-000000000002', 'faa70110-0000-0000-0000-000000000003', 'table', '{"headers":["#","Area of Operation","Approx. % of test"],"rows":[["I","Regulations","15-25%"],["II","Airspace & Operating Requirements","15-25%"],["III","Weather","11-16%"],["IV","Loading & Performance","7-11%"],["V","Operations","35-45%"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0003-0000-0000-000000000003', 'faa70110-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"Study strategy: master Operations and Airspace first. Operations alone is the single biggest area, and the two together are about half to two-thirds of the test. The weights are provider-aggregated from the ACS blueprint and can shift, so confirm against the live ACS (currently FAA-S-ACS-10B)."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0003-0000-0000-000000000004', 'faa70110-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Modern chart images: as of the 2025-2026 testing updates, the UAG exam uses current real-world chart excerpts (Sectionals, approach charts, enroute low charts) that are NOT all in the old legacy test supplement. You must be able to read live-style charts, not just memorize the old figures."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0003-0000-0000-000000000005', 'faa70110-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A chart showing the five ACS Areas of Operation and their approximate exam weights - Operations (35-45%) as the largest slice, then Regulations and Airspace (15-25% each), Weather (11-16%), and Loading & Performance (7-11%)."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0003-0000-0000-000000000006', 'faa70110-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["The UAG exam is 60 multiple-choice questions (3 options each), 120 minutes, 70% to pass (~42 correct).","It is built from the Remote Pilot sUAS ACS and taken at a PSI testing center.","Fail and you must wait 14 calendar days to retake; a passing report is generally valid 24 calendar months to apply.","Five ACS areas: Regulations, Airspace, Weather, Loading & Performance, and Operations - with Operations the largest (35-45%).","Current chart images appear on the exam, so practice reading real sectional excerpts."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70110-0000-0000-0000-000000000004', 'faa70000-0000-0000-0000-000000000001', 'Lesson 4: Staying Current — Recurrent Training', '', ARRAY['The Remote Pilot Certificate never expires and has no expiration date printed on it.','Aeronautical knowledge recency must be renewed every 24 calendar months.','Since the 2021 rule change, recency is renewed by a FREE online recurrent course - there is no in-person retest.','The recurrent course includes a night-operations knowledge area.','The FAA issues no new certificate for recurrent training; retain the course-completion certificate as proof of currency.']::text[], 4, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Explain that the certificate does not expire but knowledge recency must be renewed every 24 calendar months.','Describe how the 2021 rule replaced the in-person retest with a free online recurrent course.','Identify what proof of currency a remote pilot must retain.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0004-0000-0000-000000000000', 'faa70110-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The certificate doesn''t expire - but your knowledge recency does</h3><p>This is a point that confuses many new pilots. The Remote Pilot Certificate itself <strong>does not expire</strong> and carries <strong>no printed expiration date</strong>. What <em>does</em> have to be kept current is your <strong>aeronautical knowledge recency</strong>. A remote pilot must renew that recency <strong>every 24 calendar months</strong> in order to keep exercising the privileges of the certificate.</p><p>\"24 calendar months\" means your currency is good through the <strong>last day of the 24th month</strong> after you complete the training. For example, training completed any day in June would keep you current through the end of June two years later.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0004-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The 2021 change: a free online course, not a retest</h3><p>Before 2021, staying current meant going back to a testing center and paying for an in-person recurrent <em>knowledge test</em>. The <strong>2021 rule change</strong> eliminated that. Now you renew your recency by completing a <strong>FREE online recurrent training course</strong> on FAASafety.gov - <strong>there is no in-person retest</strong>. The course is training, not an exam to fail, and it now includes a <strong>night operations</strong> knowledge area added with the 2021 night-flight rule.</p><p>The FAA does <strong>not</strong> mail you a new certificate after you finish recurrent training. Instead, you must <strong>retain the course-completion certificate</strong> and be able to present it as proof that your knowledge recency is current. Keep it with your other operating documents.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0004-0000-0000-000000000002', 'faa70110-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"Initial test vs. recurrent training: the INITIAL UAG exam is an in-person, scored test at a PSI center (70% to pass). RECURRENT training is a free online course you complete every 24 calendar months - you are not ''retested'' and there is no in-person component."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0004-0000-0000-000000000003', 'faa70110-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"No new card is issued for recurrent training. Your one Remote Pilot Certificate stays the same; what you must keep is the recurrent COURSE-COMPLETION certificate as evidence your recency is current. As of this writing the Part 107 recurrent course is hosted on FAASafety.gov - confirm the current course code on the live site."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0004-0000-0000-000000000004', 'faa70110-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["The Remote Pilot Certificate never expires and has no expiration date printed on it.","Aeronautical knowledge recency must be renewed every 24 calendar months.","Since the 2021 rule change, recency is renewed by a FREE online recurrent course - there is no in-person retest.","The recurrent course includes a night-operations knowledge area.","The FAA issues no new certificate for recurrent training; retain the course-completion certificate as proof of currency."]}'::jsonb, 4);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70110-0000-0000-0000-000000000005', 'faa70000-0000-0000-0000-000000000001', 'Lesson 5: Registering the Drone, Remote ID, and the 5 Knowledge Areas Ahead', '', ARRAY['Part 107 drones are registered individually (per-aircraft) through FAADroneZone; all Part 107 aircraft must be registered regardless of weight.','The registration number must be marked on the aircraft''s exterior, and proof of registration carried during operations.','Remote ID has been enforced since September 16, 2023, with three compliance options: a standard RID drone, a broadcast module, or flying within a FRIA.','A standard RID drone broadcasts the live control-station (pilot) location; a broadcast module broadcasts only the take-off location.','The course is organized around the five ACS areas: Regulations, Airspace, Weather, Loading & Performance, and Operations (the largest).']::text[], 5, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Describe Part 107 drone registration and the requirement to mark the registration number on the aircraft.','Explain the three ways to comply with Remote ID.','Preview the five ACS knowledge areas the rest of the course will cover.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0005-0000-0000-000000000000', 'faa70110-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Registering and marking your drone</h3><p>A Remote Pilot Certificate certifies <em>you</em>; the <em>aircraft</em> must be registered separately. Registration is done through <strong>FAADroneZone</strong> (the FAA''s online portal). The key difference from recreational flying is that <strong>Part 107 registration is per-aircraft</strong>: every individual drone you fly commercially gets its <strong>own unique registration number</strong>. (Recreational flyers, by contrast, can register once and apply that single number to every drone they own.)</p><ul><li>Registration costs about $5 and is valid for 3 years (fee subject to change).</li><li>You must register any sUAS from <strong>0.55 lb (250 g) up to 55 lb</strong>. For recreational use, drones under 0.55 lb need not be registered - but <strong>all Part 107 aircraft must be registered regardless of weight</strong>.</li><li>The <strong>registration number must be marked on the exterior</strong> of the aircraft, legible and readable without tools.</li><li>Carry <strong>proof of registration</strong> (digital or paper) during operations.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0005-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Remote ID: a digital license plate</h3><p><strong>Remote ID (RID)</strong> is often described as a \"digital license plate\" for drones - it lets the aircraft broadcast identification and location so authorities can identify drones in the air. Broadcast enforcement began <strong>September 16, 2023</strong>: if a drone requires FAA registration, it must also broadcast Remote ID (unless it is flown inside a FRIA). There are <strong>three ways to comply</strong>:</p><ul><li><strong>1. Standard Remote ID drone:</strong> the broadcast capability is built in. It broadcasts the drone''s ID, the drone''s location and altitude, the <strong>control-station (pilot) location</strong>, velocity, a timestamp, and emergency status.</li><li><strong>2. Remote ID broadcast module:</strong> a retrofit add-on for a drone that lacks built-in RID. It broadcasts the drone''s ID, its <strong>take-off location</strong> (not the moving pilot location), and velocity. When using a module, you must keep the drone within visual line of sight.</li><li><strong>3. Fly within a FRIA:</strong> an <strong>FAA-Recognized Identification Area</strong> - a defined location (sponsored by community organizations or schools) where drones <em>without</em> RID equipment may be flown, as long as the drone stays within visual line of sight of the pilot.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0005-0000-0000-000000000002', 'faa70110-0000-0000-0000-000000000005', 'table', '{"headers":["Remote ID compliance option","What it broadcasts / key condition"],"rows":[["Standard Remote ID drone","Built in: drone ID + drone location/altitude + control-station (pilot) location + velocity + timestamp + emergency status"],["Remote ID broadcast module","Retrofit add-on: drone ID + take-off location + velocity; drone must stay within VLOS"],["Fly within a FRIA","No RID equipment required; drone must stay within VLOS of the FAA-Recognized Identification Area"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0005-0000-0000-000000000003', 'faa70110-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"A broadcast module reports the TAKE-OFF location, while a standard Remote ID drone reports the live CONTROL-STATION (pilot) location. This distinction is a common exam point."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0005-0000-0000-000000000004', 'faa70110-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Three side-by-side panels - a Standard Remote ID drone broadcasting pilot + drone location, a drone with a retrofit broadcast module broadcasting take-off location, and a drone operating inside a FRIA boundary with no broadcast equipment."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0005-0000-0000-000000000005', 'faa70110-0000-0000-0000-000000000005', 'text', '{"html":"<h3>The road ahead: the five knowledge areas</h3><p>The rest of this course is organized around the five ACS Areas of Operation you will be tested on. Here is the map:</p><ul><li><strong>Regulations (15-25%):</strong> the actual rules of Part 107 - operating limits (400 ft AGL, 87 kt / 100 mph, 3 SM visibility, cloud clearance), accident reporting under 107.9, alcohol and drug rules, operations over people, waivers, and Remote ID.</li><li><strong>Airspace & Operating Requirements (15-25%):</strong> airspace classes A-G, reading sectional charts, controlled-airspace authorizations (LAANC and DroneZone), and special-use airspace, TFRs, and NOTAMs.</li><li><strong>Weather (11-16%):</strong> weather sources, decoding METARs and TAFs, density altitude, stability and fronts, and how wind, clouds, and temperature affect a small drone.</li><li><strong>Loading & Performance (7-11%):</strong> weight and balance, payload effects, density-altitude performance, and LiPo battery care.</li><li><strong>Operations (35-45%):</strong> the largest area - crew resource management, aeronautical decision-making and the five hazardous attitudes, physiology, radio and airport operations, maintenance and preflight, emergencies, and night operations.</li></ul>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70120-0005-0000-0000-000000000006', 'faa70110-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["Part 107 drones are registered individually (per-aircraft) through FAADroneZone; all Part 107 aircraft must be registered regardless of weight.","The registration number must be marked on the aircraft''s exterior, and proof of registration carried during operations.","Remote ID has been enforced since September 16, 2023, with three compliance options: a standard RID drone, a broadcast module, or flying within a FRIA.","A standard RID drone broadcasts the live control-station (pilot) location; a broadcast module broadcasts only the take-off location.","The course is organized around the five ACS areas: Regulations, Airspace, Weather, Loading & Performance, and Operations (the largest)."]}'::jsonb, 6);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000001', '14 CFR Part 107', 'The federal regulation governing small unmanned aircraft systems (drones under 55 lb) operated for non-recreational purposes; it sets pilot certification, operating limits, and airspace rules.', 'The commercial drone rulebook.', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000002', 'Small UAS (sUAS)', 'A small unmanned aircraft system weighing less than 55 pounds at takeoff, including everything on board (payload, attachments), together with its control station.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000003', 'Remote Pilot in Command (Remote PIC)', 'The certificated person who is directly responsible for and the final authority over a Part 107 operation; one Remote PIC is responsible for each flight.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000004', '49 U.S.C. 44809', 'The statutory ''Exception for Limited Recreational Operations''; lets hobbyists fly strictly for personal enjoyment under a community-based organization''s safety guidelines after passing TRUST.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000005', 'TRUST', 'The Recreational UAS Safety Test - a free, one-time test (no expiration) required of recreational flyers operating under 44809; it is NOT the same as the Part 107 certificate.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000006', 'IACRA', 'Integrated Airman Certification and Rating Application - the FAA''s online system where you create an account, get an FAA Tracking Number, and file Form 8710-13.', 'Where you apply online.', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000007', 'FAA Form 8710-13', 'The application for a Remote Pilot Certificate, completed (usually in IACRA) after passing the UAG knowledge test.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000008', 'PSI Services', 'The FAA''s testing vendor; you schedule and take the UAG knowledge test at a PSI testing center, bringing a government-issued photo ID.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000009', 'TSA security vetting', 'The automatic background/security check the Transportation Security Administration runs during the certificate application; you cannot be issued a certificate until it clears.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000010', 'Temporary remote pilot certificate', 'The certificate emailed after TSA vetting clears; it authorizes you to act as Remote PIC immediately, before the permanent card arrives by mail.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000011', 'UAG knowledge test', 'The Unmanned Aircraft General - Small exam: 60 multiple-choice questions, 120 minutes, 70% to pass, taken at a PSI center to earn the initial Remote Pilot Certificate.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000012', 'Airman Certification Standards (ACS)', 'The FAA document (currently FAA-S-ACS-10B) that defines exactly what the UAG test covers; the exam is built from its five Areas of Operation.', 'The exam blueprint.', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000013', 'Five ACS Areas of Operation', 'Regulations; Airspace & Operating Requirements; Weather; Loading & Performance; Operations - the five knowledge areas of the UAG exam, with Operations the largest.', 'Operations is the biggest bucket.', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000014', 'Passing score (UAG)', '70%, which is approximately 42 of the 60 questions answered correctly.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000015', '14-day retake rule', 'If you fail the UAG knowledge test, you must wait 14 calendar days before you can retake it.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000016', 'Knowledge recency', 'The currency a remote pilot must maintain to keep exercising certificate privileges; it must be renewed every 24 calendar months.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000017', '24 calendar months', 'The recurrent-training interval; recency is good through the last day of the 24th month after the training is completed.', 'Not ''two years to the day.''', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000018', 'Recurrent training course', 'Since 2021, a free online FAASafety.gov course (not an in-person retest) that renews knowledge recency; it includes a night-operations topic.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000019', 'Course-completion certificate', 'The proof of recurrent-training completion a pilot must retain and be able to present; the FAA does not issue a new pilot certificate after recurrent training.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000020', 'FAADroneZone', 'The FAA''s online portal for registering drones and requesting airspace authorizations and waivers; Part 107 drones are registered here individually.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000021', 'Part 107 registration', 'Per-aircraft registration: every Part 107 drone gets its own unique number, must be registered regardless of weight, and must have the number marked on its exterior.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000022', 'Remote ID (RID)', 'A drone''s ''digital license plate''; required to broadcast since Sept 16, 2023 for any drone that must be registered, unless flown inside a FRIA.', 'Digital license plate.', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000023', 'Remote ID broadcast module', 'A retrofit add-on that broadcasts the drone''s ID, its take-off location (not the live pilot location), and velocity; the drone must stay within VLOS.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70140-0000-0000-0000-000000000024', 'FRIA (FAA-Recognized Identification Area)', 'A defined area where drones without Remote ID equipment may be flown, provided the drone remains within visual line of sight of the pilot.', NULL, 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000001', 'Which best describes when a drone flight must be conducted under 14 CFR Part 107 rather than the recreational exception?', 'multiple_choice', '["Only when the pilot is paid money for the flight","Whenever the flight is for any purpose other than strictly personal enjoyment","Only when the drone weighs more than 25 pounds"]'::jsonb, 'Whenever the flight is for any purpose other than strictly personal enjoyment', 'The dividing line is the PURPOSE of the flight, not whether money changes hands. Any non-recreational purpose - including unpaid work that furthers a business or organization - requires Part 107. Weight thresholds are separate from this purpose test.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000002', 'You volunteer to shoot free aerial photos for a local nonprofit''s fundraising website. Under which framework must you operate?', 'multiple_choice', '["Recreational under 49 U.S.C. 44809, because you are not paid","Part 107, because the flight furthers an organization and is not strictly recreational","Neither - charitable flights are exempt from FAA rules"]'::jsonb, 'Part 107, because the flight furthers an organization and is not strictly recreational', 'Furthering a nonprofit or business is not ''strictly for personal enjoyment,'' so it falls under Part 107 even though no one is paid. The recreational exception requires that the flight be purely a hobby.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000003', 'What is the maximum takeoff weight for an aircraft to be considered a ''small unmanned aircraft system'' under Part 107?', 'multiple_choice', '["Less than 55 pounds","Less than 25 pounds","Less than 0.55 pounds"]'::jsonb, 'Less than 55 pounds', 'A small UAS weighs less than 55 lb at takeoff, including payload. The 0.55 lb figure is the registration threshold for recreational drones, not the definition of a small UAS.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000004', 'A recreational flyer breaks one of the conditions of 49 U.S.C. 44809 during a flight. How is that flight then evaluated?', 'multiple_choice', '["It is automatically forgiven as a first offense","It is judged under Part 107, with the associated penalties","It is still recreational because the pilot intended it to be"]'::jsonb, 'It is judged under Part 107, with the associated penalties', 'If any condition of the recreational exception is broken, the flight loses 44809 protection and is judged under Part 107, exposing the pilot to greater enforcement.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000005', 'Which credential is associated with RECREATIONAL flying, not Part 107?', 'multiple_choice', '["The Remote Pilot Certificate","The TRUST test","FAA Form 8710-13"]'::jsonb, 'The TRUST test', 'Recreational flyers take the free TRUST test (Recreational UAS Safety Test). The Remote Pilot Certificate and Form 8710-13 belong to the Part 107 path.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000006', 'What is the minimum age to be eligible for a Remote Pilot Certificate?', 'multiple_choice', '["14 years old","16 years old","18 years old"]'::jsonb, '16 years old', 'Eligibility under 14 CFR 107.61 requires a person be at least 16 years old, able to read/speak/write/understand English, and in safe physical and mental condition.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000007', 'Which statement about prior pilot experience is correct for the initial Part 107 certificate?', 'multiple_choice', '["You must already hold a Part 61 pilot certificate to take the UAG test","No prior pilot certificate is required to take the initial UAG knowledge test","You must have at least 40 hours of manned flight time"]'::jsonb, 'No prior pilot certificate is required to take the initial UAG knowledge test', 'No existing pilot certificate is required for the initial UAG test. Holding a current Part 61 certificate is only an alternate path that lets you substitute a free online course for the test.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000008', 'In the certification process, what is the purpose of creating an account in IACRA?', 'multiple_choice', '["To schedule the knowledge test with PSI","To obtain an FAA Tracking Number and later file Form 8710-13","To register the drone and obtain a Remote ID"]'::jsonb, 'To obtain an FAA Tracking Number and later file Form 8710-13', 'IACRA issues your FAA Tracking Number (FTN) and is where you complete the 8710-13 application. Scheduling the test is done with PSI; drone registration is done in FAADroneZone.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000009', 'After you pass the UAG test and complete your application, what allows you to begin flying commercially the soonest?', 'multiple_choice', '["The permanent certificate that arrives by mail","The temporary certificate emailed after TSA vetting clears","A receipt from the PSI testing center"]'::jsonb, 'The temporary certificate emailed after TSA vetting clears', 'Once TSA security vetting clears, you receive a temporary remote pilot certificate by email and may begin operating immediately - you do not have to wait for the permanent card.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000010', 'Which automatic step in the application process is a security background check?', 'multiple_choice', '["TSA security vetting","The flight review","The PSI proctoring check"]'::jsonb, 'TSA security vetting', 'The Transportation Security Administration runs an automatic security/background check during the application. It must clear before a certificate can be issued.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000011', 'A pilot already holds a current Part 61 certificate with a flight review completed 10 months ago. What may they do instead of the UAG test?', 'multiple_choice', '["Skip certification entirely - Part 61 already covers drones","Complete a free online training course instead of the in-person knowledge test","Take a shortened 30-question version of the UAG test"]'::jsonb, 'Complete a free online training course instead of the in-person knowledge test', 'A current Part 61 pilot with a flight review within the previous 24 months may complete a free online course in place of the UAG test, then apply through IACRA as usual.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000012', 'How many questions are on the UAG knowledge test and how long do you have?', 'multiple_choice', '["60 questions in 120 minutes","100 questions in 180 minutes","40 questions in 90 minutes"]'::jsonb, '60 questions in 120 minutes', 'The UAG exam is 60 multiple-choice questions with a 2-hour (120-minute) time limit, about two minutes per question.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000013', 'What score is required to pass the UAG knowledge test?', 'multiple_choice', '["60%","70%","80%"]'::jsonb, '70%', 'You need 70% to pass, which is approximately 42 of the 60 questions correct.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000014', 'Which ACS Area of Operation makes up the LARGEST share of the UAG exam?', 'multiple_choice', '["Regulations","Weather","Operations"]'::jsonb, 'Operations', 'Operations is the single largest area at roughly 35-45% of the test. It covers CRM, ADM and hazardous attitudes, physiology, maintenance/preflight, emergencies, and night operations.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000015', 'Which list correctly names the five ACS Areas of Operation tested on the UAG exam?', 'multiple_choice', '["Regulations; Airspace & Operating Requirements; Weather; Loading & Performance; Operations","Navigation; Communications; Maintenance; Weather; Law","Charts; Batteries; Insurance; Weather; Ethics"]'::jsonb, 'Regulations; Airspace & Operating Requirements; Weather; Loading & Performance; Operations', 'The five ACS areas are Regulations, Airspace & Operating Requirements, Weather, Loading & Performance, and Operations.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000016', 'If you fail the UAG knowledge test, how long must you wait before retaking it?', 'multiple_choice', '["24 hours","14 calendar days","30 calendar days"]'::jsonb, '14 calendar days', 'A failed UAG test requires a 14-calendar-day wait before you may retake it.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000017', 'Where is the UAG knowledge test administered?', 'multiple_choice', '["Online from home with remote proctoring","At a PSI Services testing center","At any FAA Flight Standards District Office"]'::jsonb, 'At a PSI Services testing center', 'PSI Services is the FAA''s testing vendor; the in-person UAG test is taken at a PSI center, where you must present a government photo ID.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000018', 'Which statement about the Remote Pilot Certificate''s expiration is correct?', 'multiple_choice', '["The certificate expires every 24 months and must be reissued","The certificate does not expire, but knowledge recency must be renewed every 24 calendar months","The certificate expires every 5 years"]'::jsonb, 'The certificate does not expire, but knowledge recency must be renewed every 24 calendar months', 'The certificate itself has no expiration date. What must be kept current is aeronautical knowledge recency, renewed every 24 calendar months.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000019', 'Since the 2021 rule change, how does a Part 107 pilot renew knowledge recency?', 'multiple_choice', '["By taking a paid in-person recurrent knowledge test","By completing a free online recurrent training course","By re-doing the full 60-question UAG exam"]'::jsonb, 'By completing a free online recurrent training course', 'The 2021 rule replaced the paid in-person recurrent test with a free online recurrent training course - it is training, not a retest, and it includes a night-operations topic.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000020', 'After completing recurrent training, what does the FAA give the pilot as evidence of currency?', 'multiple_choice', '["A brand-new Remote Pilot Certificate by mail","Nothing - the pilot retains the course-completion certificate as proof","A new endorsement printed on the existing plastic card"]'::jsonb, 'Nothing - the pilot retains the course-completion certificate as proof', 'The FAA does not issue a new certificate after recurrent training. The pilot must retain and be able to present the course-completion certificate as proof of currency.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000021', 'A remote pilot completes recurrent training on June 12. Through approximately when is their knowledge recency valid?', 'multiple_choice', '["Through June 12 two years later, to the exact day","Through the last day of June two years later (end of the 24th calendar month)","Through December 31 of the same year"]'::jsonb, 'Through the last day of June two years later (end of the 24th calendar month)', '''24 calendar months'' runs through the last day of the 24th month after completion, so training done in June is good through the end of June two years later - not the exact day.', 'hard', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000022', 'Which knowledge area was added to recurrent training in connection with the 2021 rules?', 'multiple_choice', '["Night operations","Beyond visual line of sight (BVLOS)","International operations"]'::jsonb, 'Night operations', 'The 2021 rule permitted night flight without a waiver, and a night-operations knowledge area was added to the recurrent training course.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000023', 'How does Part 107 drone registration differ from recreational registration?', 'multiple_choice', '["Part 107 drones do not need to be registered at all","Each Part 107 drone is registered individually, rather than one number covering all of a pilot''s drones","Part 107 registration never expires"]'::jsonb, 'Each Part 107 drone is registered individually, rather than one number covering all of a pilot''s drones', 'Part 107 registration is per-aircraft: every drone gets its own unique number. Recreational flyers can register once and apply that single number to all their drones.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000024', 'Which is a requirement for a registered Part 107 drone?', 'multiple_choice', '["The registration number must be marked on the exterior, legible without tools","The registration number may be stored only in an app, never on the aircraft","Registration is required only for drones over 25 pounds"]'::jsonb, 'The registration number must be marked on the exterior, legible without tools', 'The registration number must be marked on the aircraft''s exterior and be readable without tools. All Part 107 aircraft must be registered regardless of weight, and proof of registration must be carried during operations.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000025', 'Which of the following is NOT one of the three ways to comply with Remote ID?', 'multiple_choice', '["Operating a standard Remote ID drone with built-in broadcast","Attaching a Remote ID broadcast module","Filing a Remote ID waiver before every flight"]'::jsonb, 'Filing a Remote ID waiver before every flight', 'The three compliance options are a standard Remote ID drone, a broadcast module, or flying within a FRIA. Filing a per-flight waiver is not one of them.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000026', 'What location does a Remote ID BROADCAST MODULE report, compared with a standard Remote ID drone?', 'multiple_choice', '["The live control-station (pilot) location, same as a standard drone","The drone''s take-off location, whereas a standard RID drone reports the live control-station location","It reports no location at all"]'::jsonb, 'The drone''s take-off location, whereas a standard RID drone reports the live control-station location', 'A broadcast module reports the take-off location and requires the drone to stay within VLOS, while a standard Remote ID drone broadcasts the live control-station (pilot) location plus drone position, velocity, timestamp, and emergency status.', 'hard', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000027', 'What is a FRIA in the context of Remote ID?', 'multiple_choice', '["A federal registration invoice and authorization","An FAA-Recognized Identification Area where drones without Remote ID may fly within VLOS","A required insurance certificate for commercial drones"]'::jsonb, 'An FAA-Recognized Identification Area where drones without Remote ID may fly within VLOS', 'A FRIA is a defined area, sponsored by community organizations or schools, where drones lacking Remote ID equipment may be flown as long as the drone stays within visual line of sight.', 'medium', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70130-0000-0000-0000-000000000028', 'Which portal is used to register a Part 107 drone?', 'multiple_choice', '["IACRA","FAADroneZone","PSI Services"]'::jsonb, 'FAADroneZone', 'Drones are registered through FAADroneZone. IACRA is for the pilot certificate application; PSI is the testing vendor.', 'easy', 'faa70000-0000-0000-0000-000000000001', 'faa70110-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70210-0000-0000-0000-000000000001', 'faa70000-0000-0000-0000-000000000002', 'Lesson 1: Applicability, Definitions, and Falsification', '', ARRAY['Part 107 governs non-recreational sUAS operations; ''small'' = less than 55 lb including payload at takeoff.','Part 107 excludes recreational §44809 flights, public aircraft, model rockets, kites, moored/free balloons, and air carriers.','The sUAS is the aircraft PLUS control station, links, and supporting equipment.','The Remote PIC holds final authority; an unrated person may manipulate controls only under direct, take-over-able supervision.','Falsification, fraudulent reproduction, or alteration of certificates/records (107.5) can lead to denial, suspension, or revocation.']::text[], 1, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Identify which operations fall under 14 CFR Part 107 and which are excluded.','Define core terms: small unmanned aircraft, sUAS, remote PIC, person manipulating the controls, visual observer, and control station.','Explain the consequences of falsifying or altering certificates and records.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0001-0000-0000-000000000000', 'faa70210-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What Part 107 covers</h3><p><strong>14 CFR Part 107</strong> is the body of federal regulation that governs the operation of <strong>small unmanned aircraft systems (sUAS)</strong> for <em>non-recreational</em> (i.e., commercial, professional, civic, or business) purposes in the United States. If you are flying a drone to take real-estate photos, inspect a roof, map a job site, or conduct a survey, you are operating under Part 107. A <strong>small unmanned aircraft</strong> is one that weighs <strong>less than 55 pounds</strong> (including everything on board, such as the battery and any payload) at takeoff. The <strong>unmanned aircraft system (sUAS)</strong> is the small unmanned aircraft <em>plus</em> the associated elements — the control station, data links, and other equipment — needed to operate it safely.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0001-0000-0000-000000000001', 'faa70210-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What Part 107 does NOT cover</h3><p>Part 107 does not apply to everything that flies. The rule specifically excludes: aircraft <strong>at or above 55 lb</strong>; <strong>recreational/hobby</strong> flying conducted under the statutory exception in <strong>49 U.S.C. § 44809</strong> (covered in Lesson 7); operations under a separate FAA exemption or certificate of authorization; <strong>amateur rocketry</strong>, <strong>moored balloons</strong>, <strong>kites</strong>, and <strong>free balloons</strong>; <strong>public aircraft</strong> operations (certain government/agency flights operating under a COA); and air carrier operations. The exam may ask you to recognize that a hobbyist flying for fun is <em>not</em> automatically under Part 107 — but note the catch in Lesson 7: break a recreational condition and the flight is judged under Part 107 anyway.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0001-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'table', '{"headers":["Term","Definition"],"rows":[["Small unmanned aircraft","An unmanned aircraft weighing less than 55 lb (including payload) at takeoff."],["sUAS","The small unmanned aircraft plus its control station, links, and equipment for safe operation."],["Remote pilot in command (Remote PIC)","The person who has final authority and responsibility for the operation; must hold a remote pilot certificate."],["Person manipulating the controls","The individual actually flying the aircraft; may be unrated if directly supervised by the Remote PIC who can immediately take control."],["Visual observer (VO)","An optional crewmember who assists the Remote PIC by seeing and avoiding other air traffic and hazards."],["Control station","The interface (e.g., the controller/ground station) used to operate the small unmanned aircraft."]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0001-0000-0000-000000000003', 'faa70210-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Weight test: ''Small'' means LESS THAN 55 lb at takeoff, counting the battery and any payload. A 55 lb (or heavier) aircraft is outside Part 107 entirely."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0001-0000-0000-000000000004', 'faa70210-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Falsification, reproduction, and alteration</h3><p>Honesty with the FAA is itself a rule. <strong>14 CFR 107.5</strong> prohibits the <strong>fraudulent or intentionally false</strong> making of any record, report, application, or statement required under Part 107; the <strong>reproduction for fraudulent purposes</strong> of any certificate or authorization; and the <strong>alteration</strong> of a certificate or authorization. Doing any of these is a basis for the FAA to <strong>deny an application</strong> or to <strong>suspend or revoke</strong> any certificate or waiver you hold — and it can carry civil or criminal penalties. In short: do not lie on your IACRA application, do not doctor a waiver, and do not forge a knowledge-test report.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0001-0000-0000-000000000005', 'faa70210-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Falsifying records, reproducing a certificate for fraud, or altering a certificate (107.5) is grounds for denial, suspension, or revocation — and possible criminal liability."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0001-0000-0000-000000000006', 'faa70210-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Part 107 governs non-recreational sUAS operations; ''small'' = less than 55 lb including payload at takeoff.","Part 107 excludes recreational §44809 flights, public aircraft, model rockets, kites, moored/free balloons, and air carriers.","The sUAS is the aircraft PLUS control station, links, and supporting equipment.","The Remote PIC holds final authority; an unrated person may manipulate controls only under direct, take-over-able supervision.","Falsification, fraudulent reproduction, or alteration of certificates/records (107.5) can lead to denial, suspension, or revocation."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70210-0000-0000-0000-000000000002', 'faa70000-0000-0000-0000-000000000002', 'Lesson 2: Registration, Marking, and Remote ID', '', ARRAY['Register via FAADroneZone; under Part 107 each aircraft gets its own number, regardless of weight.','Mark the registration number on the exterior, readable without tools; carry proof of registration.','Remote ID broadcast has been enforced since September 16, 2023.','Three RID options: standard RID drone, broadcast module, or flying within a FRIA.','Standard RID broadcasts the live control-station location; a broadcast module broadcasts the take-off location and requires VLOS.']::text[], 2, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['State the registration and exterior-marking requirements for Part 107 aircraft.','Explain that Part 107 registration is per-aircraft, unlike recreational registration.','Describe the three Remote ID compliance options and their differences.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0002-0000-0000-000000000000', 'faa70210-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Registration and marking</h3><p>Before you fly commercially you must <strong>register the aircraft</strong> with the FAA through <strong>FAADroneZone</strong>. Under Part 107, registration is <strong>per aircraft</strong>: <em>every individual drone gets its own unique registration number</em>. (Contrast this with recreational flyers under §44809, who may register once and apply that single number to every drone they own.) Registration is required for any sUAS weighing <strong>more than 0.55 lb (250 g) up to 55 lb</strong>; and notably, <strong>all Part 107 aircraft must be registered regardless of weight</strong>, because they are not recreational. The registration costs about <strong>$5</strong> and is valid for <strong>3 years</strong>.</p><p>The assigned registration number must be <strong>marked on the exterior</strong> of the aircraft so it is <strong>legible and readable without tools</strong>, and you must carry <strong>proof of registration</strong> (digital or paper) during operations.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0002-0000-0000-000000000001', 'faa70210-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"Part 107 = each drone registered individually. Recreational (§44809) = one number covers all your drones. The exam tests this difference directly."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0002-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Remote ID — the ''digital license plate''</h3><p><strong>Remote ID (RID)</strong> broadcasts identification and location information about a drone in flight, allowing the public and authorities to receive it. Broadcast enforcement began <strong>September 16, 2023</strong>: if a drone is required to be registered, it must <strong>broadcast Remote ID</strong> — unless it is flown entirely within a FRIA. There are <strong>three ways to comply</strong>:</p><ul><li><strong>Standard Remote ID drone</strong> — RID capability is <em>built in</em>. It broadcasts the drone''s ID, the drone''s <strong>location and altitude</strong>, the <strong>control-station (pilot/take-off) location</strong>, velocity, a timestamp, and emergency status.</li><li><strong>Remote ID broadcast module</strong> — a <em>retrofit add-on</em> attached to a non-RID drone. It broadcasts the drone ID, the <strong>take-off location</strong> (not the moving control-station location), and velocity. When using a module, the pilot must keep the drone within <strong>visual line of sight</strong>.</li><li><strong>Fly within a FRIA</strong> — an <strong>FAA-Recognized Identification Area</strong>, a defined geographic area (sponsored by community-based organizations or educational institutions) where drones <em>without</em> RID equipment may be flown, provided the aircraft stays within VLOS of the operator.</li></ul>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0002-0000-0000-000000000003', 'faa70210-0000-0000-0000-000000000002', 'table', '{"headers":["Compliance option","What it broadcasts","Key limitation"],"rows":[["Standard Remote ID drone","Drone ID, drone location/altitude, control-station (pilot) location, velocity, timestamp, emergency status","Built-in; most complete data set"],["Remote ID broadcast module","Drone ID, take-off location, velocity","Retrofit; must keep drone within VLOS (no control-station tracking)"],["Fly within a FRIA","(No RID broadcast required)","Drone must stay within VLOS inside the FRIA boundary"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0002-0000-0000-000000000004', 'faa70210-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"A broadcast module reports the TAKE-OFF location, while a standard RID drone reports the live CONTROL-STATION (pilot) location. That distinction is a favorite exam item."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0002-0000-0000-000000000005', 'faa70210-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Three Remote ID compliance paths — standard RID drone (broadcasts pilot location), broadcast module (broadcasts take-off location), and flying within a FRIA."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0002-0000-0000-000000000006', 'faa70210-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Register via FAADroneZone; under Part 107 each aircraft gets its own number, regardless of weight.","Mark the registration number on the exterior, readable without tools; carry proof of registration.","Remote ID broadcast has been enforced since September 16, 2023.","Three RID options: standard RID drone, broadcast module, or flying within a FRIA.","Standard RID broadcasts the live control-station location; a broadcast module broadcasts the take-off location and requires VLOS."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70210-0000-0000-0000-000000000003', 'faa70000-0000-0000-0000-000000000002', 'Lesson 3: The Remote Pilot Certificate & Remote PIC Responsibilities', '', ARRAY['Eligibility: 16+, English, sound physical/mental condition, pass UAG (or online course for Part 61 holders), TSA vetting.','The certificate never expires, but aeronautical knowledge recency must be renewed every 24 calendar months via free online recurrent training.','Keep the recurrent course-completion certificate as proof of currency — no new card is issued.','Every operation has one Remote PIC with final authority and responsibility (107.19).','An uncertificated person may manipulate the controls only under direct, immediate-takeover supervision by a Remote PIC.','On request, the Remote PIC must present the certificate, authorizations, and records for FAA inspection (107.7).']::text[], 3, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['List the eligibility requirements for a remote pilot certificate.','Explain aeronautical-knowledge recency (recurrent training every 24 calendar months).','Describe the remote PIC''s responsibilities and who may operate the aircraft.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0003-0000-0000-000000000000', 'faa70210-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Eligibility (14 CFR 107.61–107.65)</h3><p>To obtain a <strong>Remote Pilot Certificate with a small UAS rating</strong> you must be at least <strong>16 years old</strong>; be able to <strong>read, speak, write, and understand English</strong> (waivable only for a medical reason such as a hearing or speech impairment); be in a <strong>physical and mental condition to safely operate</strong> a small UAS; and either <strong>pass the initial aeronautical knowledge test (UAG)</strong> or, if you already hold a Part 61 certificate and are current on a flight review, complete the FAA''s <strong>online Part 107 training course</strong> instead. You must also be <strong>vetted by the TSA</strong> (a background check that runs automatically during the application through IACRA).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0003-0000-0000-000000000001', 'faa70210-0000-0000-0000-000000000003', 'table', '{"headers":["Eligibility requirement","Standard"],"rows":[["Minimum age","16 years old"],["Language","Read, speak, write, understand English (medical waiver only)"],["Condition","Physical and mental condition to safely operate"],["Knowledge","Pass UAG test (or online course if a current Part 61 holder)"],["Security","TSA vetting (automatic via IACRA)"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0003-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'text', '{"html":"<h3>The certificate does not expire — but recency does</h3><p>The remote pilot certificate has <strong>no printed expiration date</strong>. However, you must keep your <strong>aeronautical knowledge recency current every 24 calendar months</strong>. Since the 2021 rule change, recency is renewed by completing a <strong>free online recurrent training course</strong> on FAASafety.gov — there is <strong>no in-person retest</strong>. That recurrent course now includes a <strong>night operations</strong> knowledge area. The FAA does <em>not</em> mail a new certificate after recurrent training; you must <strong>retain and be able to present the course-completion certificate</strong> as proof of currency. ''24 calendar months'' runs through the last day of the 24th month after completion.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0003-0000-0000-000000000003', 'faa70210-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"Recency, not the certificate, is what expires: complete free online recurrent training every 24 calendar months. No retest, no new card — keep the completion certificate."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0003-0000-0000-000000000004', 'faa70210-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Who may operate, and the Remote PIC''s role</h3><p>Each operation must have <strong>one Remote PIC</strong> who holds a remote pilot certificate and who has <strong>final authority and responsibility</strong> for the flight (<strong>107.19</strong>). A person <em>without</em> a certificate may physically manipulate the controls <strong>only if</strong> a certificated Remote PIC is <strong>directly supervising</strong> and is able to <strong>immediately take over</strong> control. The Remote PIC must ensure the operation poses <strong>no undue hazard</strong> to people, other aircraft, or property; must have the ability to <strong>direct the aircraft to ensure compliance</strong>; must check that the aircraft is in a <strong>condition for safe operation</strong>; and must <strong>cease the operation</strong> if it would pose a hazard. The Remote PIC must also be available to present the certificate and authorizations for inspection upon FAA request (<strong>107.7</strong>).</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0003-0000-0000-000000000005', 'faa70210-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"An unrated friend can fly the drone only while a certificated Remote PIC directly supervises and can instantly take the controls. Otherwise, a certificate is required to act as pilot."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0003-0000-0000-000000000006', 'faa70210-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Eligibility: 16+, English, sound physical/mental condition, pass UAG (or online course for Part 61 holders), TSA vetting.","The certificate never expires, but aeronautical knowledge recency must be renewed every 24 calendar months via free online recurrent training.","Keep the recurrent course-completion certificate as proof of currency — no new card is issued.","Every operation has one Remote PIC with final authority and responsibility (107.19).","An uncertificated person may manipulate the controls only under direct, immediate-takeover supervision by a Remote PIC.","On request, the Remote PIC must present the certificate, authorizations, and records for FAA inspection (107.7)."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70210-0000-0000-0000-000000000004', 'faa70000-0000-0000-0000-000000000002', 'Lesson 4: Core Operating Limitations (14 CFR 107.51)', '', ARRAY['Maximum altitude is 400 ft AGL, or up to 400 ft above a structure when within a 400-ft radius of it.','Maximum groundspeed is 87 knots (100 mph).','Minimum flight visibility is 3 statute miles from the control station.','Cloud clearance is at least 500 ft below and 2,000 ft horizontal from clouds.','The structure exception raises only the altitude ceiling, not the other limits.']::text[], 4, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Recall the maximum altitude (400 ft AGL) and the 400-ft-above-structure exception.','Recall the maximum groundspeed, minimum flight visibility, and cloud-clearance requirements.','Apply these limits to operational scenarios.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0004-0000-0000-000000000000', 'faa70210-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The four numbers of 107.51</h3><p>Section <strong>107.51</strong> sets the core operating limitations every remote pilot must memorize. These are among the most frequently tested numbers on the entire exam, so commit them exactly:</p><ul><li><strong>Maximum altitude — 400 ft AGL.</strong> You may not fly higher than 400 feet above ground level <em>unless</em> the aircraft is flown <strong>within a 400-ft radius of a structure</strong>, in which case you may fly up to <strong>400 ft above the structure''s immediate uppermost limit</strong> (this lets you inspect tall towers and buildings).</li><li><strong>Maximum groundspeed — 87 knots (100 mph).</strong></li><li><strong>Minimum flight visibility — 3 statute miles</strong>, measured from the control-station location.</li><li><strong>Cloud clearance — at least 500 ft below clouds and at least 2,000 ft horizontally from clouds.</strong></li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0004-0000-0000-000000000001', 'faa70210-0000-0000-0000-000000000004', 'table', '{"headers":["Limitation (107.51)","Value"],"rows":[["Maximum altitude","400 ft AGL — or up to 400 ft above a structure if within 400 ft of it"],["Maximum groundspeed","87 knots (100 mph)"],["Minimum flight visibility","3 statute miles (from the control station)"],["Cloud clearance","≥ 500 ft below clouds AND ≥ 2,000 ft horizontally from clouds"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0004-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"The structure exception is altitude only: within a 400-ft RADIUS of a structure you may go 400 ft ABOVE that structure''s top — it does not raise the speed, visibility, or cloud-clearance limits."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0004-0000-0000-000000000003', 'faa70210-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Why these limits exist</h3><p>The 400-ft AGL cap keeps drones well below the airspace where most manned aircraft operate, reducing collision risk. The structure exception recognizes that inspecting a 1,000-ft broadcast tower would be impossible under a flat 400-ft ceiling — but only when you stay close (within a 400-ft radius) to that structure. The <strong>3 SM visibility</strong> and <strong>500-below / 2,000-horizontal</strong> cloud-clearance rules ensure you can <em>see and avoid</em> other traffic and that manned aircraft descending out of a cloud have room before reaching your drone. The <strong>100 mph / 87 kt</strong> speed cap keeps the aircraft controllable and within reaction time for see-and-avoid.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0004-0000-0000-000000000004', 'faa70210-0000-0000-0000-000000000004', 'accordion', '{"sections":[{"title":"Scenario: inspecting a 600-ft tower","content":"<p>You are hired to inspect a 600-ft communications tower. Flying straight up over open ground you would be limited to 400 ft AGL. But if you operate <strong>within a 400-ft radius of the tower</strong>, you may climb to <strong>400 ft above the tower''s top</strong> — i.e., up to about 1,000 ft AGL — to inspect the antenna array. Stray more than 400 ft horizontally from the tower and you must drop back to the 400-ft AGL ceiling.</p>","open":false},{"title":"Scenario: a cloud layer at 1,200 ft","content":"<p>A broken layer sits at 1,200 ft AGL. To respect the 500-ft-below cloud clearance, your maximum operating altitude becomes about <strong>700 ft AGL</strong> for clearance purposes — but you are still capped at <strong>400 ft AGL</strong> by 107.51 anyway, so 400 ft remains your ceiling. The cloud rule matters most when it forces you <em>lower</em> than 400 ft, or constrains how close you may fly horizontally to building cloud.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0004-0000-0000-000000000005', 'faa70210-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Maximum altitude is 400 ft AGL, or up to 400 ft above a structure when within a 400-ft radius of it.","Maximum groundspeed is 87 knots (100 mph).","Minimum flight visibility is 3 statute miles from the control station.","Cloud clearance is at least 500 ft below and 2,000 ft horizontal from clouds.","The structure exception raises only the altitude ceiling, not the other limits."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70210-0000-0000-0000-000000000005', 'faa70000-0000-0000-0000-000000000002', 'Lesson 5: Day/Night Operations, VLOS, Right-of-Way, and Hazardous Operations', '', ARRAY['Day, civil twilight, and night are all permitted; twilight and night require anti-collision lighting visible for 3 SM.','Night no longer requires a waiver if the pilot has completed the updated (night) training.','Maintain VLOS with unaided vision (corrective lenses OK) throughout the flight; FPV cannot replace it.','One unmanned aircraft per pilot; visual observers are optional but must be able to communicate with the RPIC.','Always yield right of way to all other aircraft; never operate carelessly/recklessly or drop hazardous objects.','No operating from a moving vehicle except over sparsely populated areas; alcohol = 8 hr, BAC < 0.04%, no impairing drugs.']::text[], 5, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Apply the rules for daylight, civil twilight, and night operations, including anti-collision lighting.','Explain visual line of sight (VLOS), the use of visual observers, and the one-aircraft-per-pilot rule.','State the right-of-way, careless/reckless, dropping-objects, alcohol/drugs, and moving-vehicle rules.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000000', 'faa70210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Daylight, civil twilight, and night (107.29)</h3><p>Since the rule change effective <strong>April 21, 2021</strong>, Part 107 operations are allowed during the <strong>day, during civil twilight, and at night</strong>. For operations during <strong>civil twilight and at night</strong>, the aircraft must have <strong>lighted anti-collision lighting visible for at least 3 statute miles</strong>, with a flash rate sufficient to avoid a collision. (The Remote PIC may reduce the lighting intensity only if doing so is in the interest of safety — e.g., when it impairs the pilot''s vision.) <strong>Night flight no longer requires a waiver</strong>, provided the pilot has completed the updated training (the initial UAG test or recurrent training, both of which now cover night operations). All previously issued night waivers were cancelled when the new rule took effect.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000001', 'faa70210-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"Civil twilight AND night both require anti-collision lighting visible for at least 3 statute miles. Daylight operations do not require it."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Visual line of sight and visual observers (107.31, 107.33, 107.35)</h3><p><strong>VLOS (107.31):</strong> The Remote PIC, the person manipulating the controls, and any visual observer must be able to see the unmanned aircraft <strong>with vision unaided</strong> (corrective lenses are allowed) throughout the entire flight — well enough to know its <strong>location, attitude, altitude, and direction</strong>, to scan the airspace for traffic, and to ensure it endangers no one. First-person-view (FPV) goggles may supplement but cannot replace VLOS. <strong>Visual observer (107.33):</strong> using a VO is optional; if one is used, the Remote PIC and VO must be able to communicate and coordinate. <strong>One aircraft per pilot (107.35):</strong> a person may not act as Remote PIC, or manipulate the controls, of <strong>more than one</strong> unmanned aircraft at a time.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000003', 'faa70210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Right-of-way and hazardous operations (107.37, 107.23, 107.25)</h3><p><strong>Right of way (107.37):</strong> you must <strong>yield the right of way to all other aircraft</strong> — manned and unmanned — and must not operate so close to another aircraft as to create a collision hazard. The drone always gives way. <strong>Careless or reckless (107.23):</strong> you may not operate in a careless or reckless manner, and you may not <strong>allow an object to be dropped</strong> from the aircraft in a manner that creates a hazard to persons or property. <strong>Moving vehicles (107.25):</strong> you may not operate the controls from a <strong>moving vehicle or aircraft</strong>, <em>except</em> over a <strong>sparsely populated area</strong> (and never while transporting another person''s property for compensation or hire).</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000004', 'faa70210-0000-0000-0000-000000000005', 'table', '{"headers":["Section","Rule"],"rows":[["107.29","Day/civil-twilight/night allowed; anti-collision lighting visible 3 SM required for twilight and night"],["107.31","Maintain VLOS with unaided vision (corrective lenses OK) throughout the flight"],["107.33","Visual observer optional; if used, RPIC and VO must be able to communicate"],["107.35","One unmanned aircraft per pilot at a time"],["107.37","Yield right of way to all other aircraft; avoid collision hazards"],["107.23","No careless/reckless operation; no dropping objects that create a hazard"],["107.25","No operating from a moving vehicle except over a sparsely populated area"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000005', 'faa70210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Alcohol and drugs (107.27 / 107.57)</h3><p>You may not act as Remote PIC, manipulate the controls, or serve as VO if you are: within <strong>8 hours</strong> of consuming alcohol (''8 hours bottle-to-throttle''); <strong>under the influence</strong> of alcohol; have a <strong>blood-alcohol concentration of 0.04% or greater</strong>; or are <strong>using any drug</strong> that affects your faculties in a way contrary to safety. These thresholds mirror the rules for manned pilots.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000006', 'faa70210-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"Alcohol limits: 8 hours bottle-to-throttle, no flying under the influence, and BAC must be below 0.04%. The same applies to anyone serving as a visual observer."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0005-0000-0000-000000000007', 'faa70210-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["Day, civil twilight, and night are all permitted; twilight and night require anti-collision lighting visible for 3 SM.","Night no longer requires a waiver if the pilot has completed the updated (night) training.","Maintain VLOS with unaided vision (corrective lenses OK) throughout the flight; FPV cannot replace it.","One unmanned aircraft per pilot; visual observers are optional but must be able to communicate with the RPIC.","Always yield right of way to all other aircraft; never operate carelessly/recklessly or drop hazardous objects.","No operating from a moving vehicle except over sparsely populated areas; alcohol = 8 hr, BAC < 0.04%, no impairing drugs."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70210-0000-0000-0000-000000000006', 'faa70000-0000-0000-0000-000000000002', 'Lesson 6: Operations Over People & Moving Vehicles, Preflight, and Accident Reporting', '', ARRAY['Operations over people fall into Categories 1–4 by injury potential: 0.55 lb / 11 ft-lb / 25 ft-lb / airworthiness certificate.','Category 3 may not sustain flight over open-air assemblies; Categories 1, 2, and 4 may (with RID).','Operations over moving vehicles require a closed/restricted site or no sustained flight (Cat 1–3); hazardous material carriage is prohibited.','Carrying property for hire is allowed but 107.25 and 107.31 are not waivable for it; the total sUAS must stay under 55 lb.','Preflight (107.15/107.49): inspect for condition for safe operation and assess weather, airspace, persons/property, power, and RID.','Report under 107.9 within 10 calendar days for serious injury, loss of consciousness, or non-drone property damage over $500.']::text[], 6, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Classify operations over people into Categories 1–4 and state the key criteria for each.','Describe the rules for operations over moving vehicles and for carriage of property for compensation.','Identify the preflight requirements and the accident-reporting triggers and timeline under 107.9.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000000', 'faa70210-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Operations over people — Subpart D, Categories 1–4</h3><p>Effective <strong>April 21, 2021</strong>, Part 107 allows certain operations <strong>over people</strong> without a waiver, sorted into four categories by the likely severity of injury the aircraft could cause. The category determines what you may fly over (a few transiting people, a closed site, or an open-air assembly):</p><ul><li><strong>Category 1:</strong> aircraft weighs <strong>0.55 lb (250 g) or less</strong> at takeoff and throughout flight, has <strong>no exposed rotating parts that could lacerate skin</strong>, and meets Remote ID. The lightest, simplest category.</li><li><strong>Category 2:</strong> the aircraft <strong>will not cause injury equal to or greater than the impact of 11 ft-lb</strong> of kinetic energy from a rigid object, has no lacerating exposed parts, and is built to an FAA-accepted means of compliance with a manufacturer declaration.</li><li><strong>Category 3:</strong> the aircraft <strong>will not cause injury equal to or greater than 25 ft-lb</strong> of kinetic energy, with no lacerating parts and a declaration. <strong>No sustained flight over open-air assemblies</strong> is allowed — you may operate over people only within a closed/restricted-access site or while transiting.</li><li><strong>Category 4:</strong> the aircraft holds an <strong>airworthiness certificate</strong> and is operated per its <strong>approved Flight Manual</strong> with ongoing maintenance. The most capable category; may operate over open-air assemblies if it also meets standard Remote ID.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000001', 'faa70210-0000-0000-0000-000000000006', 'table', '{"headers":["Category","Key eligibility criterion","Over open-air assemblies?"],"rows":[["1","≤ 0.55 lb, no exposed lacerating parts, meets RID","Yes (if it meets RID)"],["2","No injury ≥ 11 ft-lb KE; no lacerating parts; declaration","Yes (with RID)"],["3","No injury ≥ 25 ft-lb KE; no lacerating parts; declaration","No — closed/restricted site or transit only"],["4","Airworthiness certificate + approved Flight Manual","Yes (if it meets RID)"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"Remember the numbers: Cat 1 = 0.55 lb; Cat 2 = 11 ft-lb; Cat 3 = 25 ft-lb; Cat 4 = airworthiness certificate. Only Category 3 is barred from sustained flight over open-air assemblies."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000003', 'faa70210-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Operations over moving vehicles & carriage of property (107.145, 107.36)</h3><p>For operations <strong>over moving vehicles</strong> (107.145): under Categories 1, 2, or 3 the aircraft must either remain <strong>within or over a closed- or restricted-access site</strong> (with the occupants on notice) or <strong>not maintain sustained flight</strong> over the moving vehicles; a Category 4 aircraft operates per its operating limitations. You may transport <strong>property for compensation or hire</strong> under Part 107 subject to weight (the total sUAS must stay under 55 lb), interstate limits, and the rule that <strong>107.25 (moving vehicle) and 107.31 (VLOS) are not waivable</strong> when carrying someone else''s property for hire. <strong>Carriage of hazardous material (107.36) is prohibited.</strong></p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000004', 'faa70210-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Preflight: condition for safe operation (107.15, 107.49)</h3><p>Before each flight the Remote PIC must perform the actions of <strong>107.49</strong> — assess the operating environment (weather, airspace and any required authorizations, NOTAMs/TFRs, and the location of persons and property), confirm there is <strong>sufficient power</strong> for the intended operation, ensure any Remote ID equipment functions, and inspect the sUAS to confirm it is in a <strong>condition for safe operation</strong> (<strong>107.15</strong>). If the aircraft is not in a condition for safe operation, you must not fly it.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000005', 'faa70210-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Accident / safety-event reporting — 14 CFR 107.9</h3><p>This is a high-yield exam item. You must report an operation to the FAA <strong>no later than 10 calendar days</strong> after it results in <strong>at least</strong> one of the following: a <strong>serious injury</strong> to any person, or <strong>any loss of consciousness</strong>; OR <strong>damage to any property other than the small unmanned aircraft itself</strong>, <em>unless</em> the cost of repair (materials and labor) does <strong>not exceed $500</strong>, or the fair market value of the property does <strong>not exceed $500</strong> in the event of a total loss. In short: report within 10 days for serious injury / loss of consciousness, or for property damage <strong>greater than $500</strong> (excluding the drone itself).</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000006', 'faa70210-0000-0000-0000-000000000006', 'callout', '{"type":"warning","text":"107.9: report within 10 calendar days if there is serious injury, loss of consciousness, OR property damage over $500 — and damage to the drone itself never counts toward the $500."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000007', 'faa70210-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: 107.9 reporting decision flow — serious injury or loss of consciousness, or non-drone property damage over $500, triggers a report within 10 calendar days."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0006-0000-0000-000000000008', 'faa70210-0000-0000-0000-000000000006', 'key_takeaways', '{"title":"Key Takeaways","items":["Operations over people fall into Categories 1–4 by injury potential: 0.55 lb / 11 ft-lb / 25 ft-lb / airworthiness certificate.","Category 3 may not sustain flight over open-air assemblies; Categories 1, 2, and 4 may (with RID).","Operations over moving vehicles require a closed/restricted site or no sustained flight (Cat 1–3); hazardous material carriage is prohibited.","Carrying property for hire is allowed but 107.25 and 107.31 are not waivable for it; the total sUAS must stay under 55 lb.","Preflight (107.15/107.49): inspect for condition for safe operation and assess weather, airspace, persons/property, power, and RID.","Report under 107.9 within 10 calendar days for serious injury, loss of consciousness, or non-drone property damage over $500."]}'::jsonb, 8);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70210-0000-0000-0000-000000000007', 'faa70000-0000-0000-0000-000000000002', 'Lesson 7: Waivers, Airspace Authorizations, and Recreational §44809 vs. Part 107', '', ARRAY['A 107.200 certificate of waiver permits deviation from waivable rules if the operation can be done safely.','107.205 lists waivable sections (e.g., 107.25, 107.31, 107.33, 107.35, 107.37(a), 107.39, 107.41, 107.51).','107.25 and 107.31 are not waivable for carrying another person''s property for hire.','Operational waivers (rule deviation) differ from airspace authorizations (LAANC/DroneZone for controlled airspace).','Recreational flying uses §44809/TRUST with fewer privileges; Part 107 offers more privileges with more vetting.','Violating any §44809 condition causes the flight to be judged under Part 107.']::text[], 7, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Explain the certificate-of-waiver process (107.200) and which sections are waivable (107.205).','Distinguish an operational waiver from an airspace authorization (LAANC/DroneZone).','Compare recreational flying under §44809 with Part 107 operations.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000000', 'faa70210-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Certificate of waiver (107.200) and waivable sections (107.205)</h3><p>A <strong>Certificate of Waiver (107.200)</strong> lets the FAA authorize a deviation from certain Part 107 rules if the applicant demonstrates the proposed operation can be conducted <strong>safely</strong> under the terms and conditions of the waiver. Not every rule is waivable. <strong>107.205</strong> lists the sections the FAA may waive, including: <strong>107.25</strong> (operation from a moving vehicle), <strong>107.29</strong> (daylight — historical), <strong>107.31</strong> (VLOS), <strong>107.33</strong> (visual observer), <strong>107.35</strong> (one aircraft per pilot), <strong>107.37(a)</strong> (yielding right of way), <strong>107.39</strong> (operation over people), <strong>107.41</strong> (operation in certain airspace), and <strong>107.51</strong> (operating limitations such as altitude/speed/visibility). Importantly, <strong>107.25 and 107.31 are NOT waivable</strong> when you are carrying another person''s property for compensation or hire.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000001', 'faa70210-0000-0000-0000-000000000007', 'callout', '{"type":"warning","text":"Even for a waiver, you must show the operation can be done SAFELY. And 107.25 (moving vehicle) and 107.31 (VLOS) cannot be waived for carrying someone else''s property for hire."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Waiver vs. airspace authorization</h3><p>Do not confuse the two. An <strong>operational waiver</strong> (above) deviates from a Part 107 <em>rule</em>. An <strong>airspace authorization</strong> is what you need to fly in <strong>controlled airspace</strong> (Class B, C, D, and surface-area E) and is obtained through <strong>LAANC</strong> (Low Altitude Authorization and Notification Capability — often near-real-time) or through <strong>FAADroneZone</strong> for airports not LAANC-enabled. In uncontrolled <strong>Class G</strong> airspace below 400 ft AGL, no ATC authorization is required. You may need <em>both</em> a waiver and an authorization for some complex operations, but they are separate approvals.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000003', 'faa70210-0000-0000-0000-000000000007', 'table', '{"headers":["Approval","What it permits","How you get it"],"rows":[["Certificate of waiver (107.200/.205)","Deviation from a waivable Part 107 rule (e.g., night before 2021, VLOS, over people)","Apply to FAA showing the operation is safe"],["Airspace authorization","Flight in controlled airspace (B/C/D/surface E)","LAANC (near-real-time) or FAADroneZone"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000004', 'faa70210-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Recreational §44809 vs. Part 107</h3><p>Hobby flying is governed by the statutory <strong>Exception for Limited Recreational Operations, 49 U.S.C. § 44809</strong>, not by Part 107. Recreational flyers must fly <em>strictly for recreation</em>, follow a community-based organization''s (CBO) safety guidelines, pass the free <strong>TRUST</strong> test (no expiration), register (one number can cover all their drones), and stay within VLOS. Part 107 grants <strong>greater privileges</strong> — higher altitude/airspace access, the ability to fly for business, and the ability to apply for <strong>waivers</strong> — in exchange for <strong>greater vetting</strong> (the remote pilot certificate). A crucial catch: if a recreational flyer <strong>violates any §44809 condition</strong>, the flight is judged <strong>under Part 107</strong> instead, exposing the pilot to greater requirements and penalties.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000005', 'faa70210-0000-0000-0000-000000000007', 'table', '{"headers":["Topic","Recreational (§44809)","Part 107"],"rows":[["Purpose","Strictly recreational/hobby","Any non-recreational/commercial purpose"],["Credential","TRUST test (free, no expiration)","Remote Pilot Certificate (UAG test + TSA vetting)"],["Registration","One number can cover all your drones","Each drone registered individually"],["Waivers","None available","Waivers (107.205) + airspace authorizations"],["Fallback","Break a condition → flight judged under Part 107","—"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000006', 'faa70210-0000-0000-0000-000000000007', 'callout', '{"type":"info","text":"Break a single §44809 recreational condition and the FAA treats the whole flight as a Part 107 operation — which it cannot satisfy without a remote pilot certificate. This is a classic exam trap."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70220-0007-0000-0000-000000000007', 'faa70210-0000-0000-0000-000000000007', 'key_takeaways', '{"title":"Key Takeaways","items":["A 107.200 certificate of waiver permits deviation from waivable rules if the operation can be done safely.","107.205 lists waivable sections (e.g., 107.25, 107.31, 107.33, 107.35, 107.37(a), 107.39, 107.41, 107.51).","107.25 and 107.31 are not waivable for carrying another person''s property for hire.","Operational waivers (rule deviation) differ from airspace authorizations (LAANC/DroneZone for controlled airspace).","Recreational flying uses §44809/TRUST with fewer privileges; Part 107 offers more privileges with more vetting.","Violating any §44809 condition causes the flight to be judged under Part 107."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000001', 'Small unmanned aircraft', 'An unmanned aircraft weighing less than 55 lb (including everything on board) at takeoff.', 'Think of the upper weight limit.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000002', 'sUAS', 'The small unmanned aircraft together with its control station, data links, and other equipment needed to operate it safely.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000003', '14 CFR 107.5', 'Prohibits fraudulent/false records, fraudulent reproduction of a certificate, or alteration of a certificate; grounds for denial, suspension, or revocation.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000004', 'Person manipulating the controls', 'The individual flying the aircraft; may be unrated only if directly supervised by a Remote PIC who can immediately take control.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000005', 'Per-aircraft registration', 'Under Part 107, every individual drone must be registered with its own unique number (unlike recreational, where one number covers all).', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000006', 'Remote ID enforcement date', 'Broadcast Remote ID has been required (for drones that must be registered) since September 16, 2023.', 'September 2023.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000007', 'Remote ID broadcast module', 'A retrofit add-on that broadcasts drone ID, take-off location, and velocity; the pilot must keep the drone within VLOS.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000008', 'FRIA', 'FAA-Recognized Identification Area — a defined area where drones without RID equipment may fly while staying within VLOS.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000009', 'Standard Remote ID drone', 'A drone with built-in RID that broadcasts drone ID/location/altitude, control-station location, velocity, timestamp, and emergency status.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000010', 'Minimum age for remote pilot certificate', '16 years old.', 'Same as a learner''s permit in many states.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000011', 'Aeronautical knowledge recency', 'Must be renewed every 24 calendar months via a free online recurrent training course on FAASafety.gov; no in-person retest.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000012', '14 CFR 107.19', 'Remote PIC responsibilities — final authority and responsibility for the operation; must ensure compliance and a safe operation.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000013', 'Direct supervision rule', 'An uncertificated person may manipulate the controls only if a Remote PIC is directly supervising and can immediately take control.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000014', 'Maximum altitude (107.51)', '400 ft AGL — or up to 400 ft above a structure''s top when within a 400-ft radius of that structure.', 'Four hundred, twice.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000015', 'Maximum groundspeed (107.51)', '87 knots (100 mph).', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000016', 'Minimum flight visibility (107.51)', '3 statute miles, measured from the control-station location.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000017', 'Cloud clearance (107.51)', 'At least 500 ft below clouds and at least 2,000 ft horizontally from clouds.', '500 below / 2,000 horizontal.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000018', '14 CFR 107.29', 'Daylight, civil twilight, and night operations; anti-collision lighting visible for 3 statute miles required for twilight and night.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000019', '14 CFR 107.31', 'Visual line of sight — RPIC/person at controls/VO must see the aircraft with unaided vision (corrective lenses OK) throughout flight.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000020', '14 CFR 107.35', 'A person may not operate or act as Remote PIC of more than one unmanned aircraft at a time.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000021', '14 CFR 107.37', 'Yield right of way to all other aircraft (manned and unmanned); do not create a collision hazard.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000022', '14 CFR 107.25', 'No operating from a moving vehicle or aircraft, except over a sparsely populated area.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000023', 'Alcohol/drug limits (107.27/107.57)', 'No operating within 8 hours of alcohol, while under the influence, with BAC ≥ 0.04%, or while using an impairing drug.', '8 hours; 0.04.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000024', 'Category 1 (operations over people)', 'Aircraft ≤ 0.55 lb (250 g) with no exposed lacerating rotating parts and meeting Remote ID.', 'Same weight as the registration threshold.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000025', 'Category 2 vs. Category 3 (KE limits)', 'Cat 2 will not cause injury ≥ 11 ft-lb of kinetic energy; Cat 3 will not cause injury ≥ 25 ft-lb (and no sustained flight over open-air assemblies).', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000026', 'Category 4 (operations over people)', 'Requires an airworthiness certificate and operation per the approved Flight Manual.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000027', '14 CFR 107.9 reporting', 'Report to the FAA within 10 calendar days for serious injury, any loss of consciousness, or property damage (other than the drone) over $500.', '10 days; $500.', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000028', '14 CFR 107.36', 'Carriage of hazardous material by sUAS is prohibited.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000029', '14 CFR 107.200', 'Certificate of Waiver — FAA may authorize deviation from listed Part 107 rules if the operation can be conducted safely.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000030', '14 CFR 107.205', 'Lists the waivable Part 107 sections (e.g., 107.25, 107.31, 107.33, 107.35, 107.37(a), 107.39, 107.41, 107.51).', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000031', 'Non-waivable for property-for-hire', '107.25 (moving vehicle) and 107.31 (VLOS) cannot be waived when carrying another person''s property for compensation.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000032', '49 U.S.C. § 44809', 'The Exception for Limited Recreational Operations — governs hobby flight (TRUST test, CBO guidelines, VLOS).', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70240-0000-0000-0000-000000000033', '§44809 fallback rule', 'If a recreational flyer violates any §44809 condition, the operation is judged under Part 107.', NULL, 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000001', 'You plan to fly a 4-lb drone to photograph a client''s commercial building for an advertising brochure. Under which rule does this operation fall?', 'multiple_choice', '["14 CFR Part 107","49 U.S.C. § 44809 (recreational)","No rule applies because the drone is under 55 lb"]'::jsonb, '14 CFR Part 107', 'Flying for a business/advertising purpose is non-recreational, so it falls under Part 107. §44809 is only for strictly recreational flight, and all sUAS operations are regulated regardless of weight.', 'easy', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000002', 'A remote pilot intentionally enters false information on an IACRA certificate application. Under 14 CFR 107.5, this can result in:', 'multiple_choice', '["Denial of the application or suspension/revocation of any certificate held","A written warning only, with no effect on the certificate","Nothing, because 107.5 applies only to manned pilots"]'::jsonb, 'Denial of the application or suspension/revocation of any certificate held', '107.5 prohibits fraudulent/false records and is grounds for denial, suspension, or revocation (plus possible criminal penalties). It applies to Part 107 remote pilots.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000003', 'An uncertificated coworker wants to fly the drone during a Part 107 job. This is permissible only if:', 'multiple_choice', '["A certificated Remote PIC directly supervises and can immediately take control","The coworker has passed the TRUST test","The coworker stays under 400 ft AGL"]'::jsonb, 'A certificated Remote PIC directly supervises and can immediately take control', 'A person without a certificate may manipulate the controls only under direct supervision by a Remote PIC who can immediately take over. TRUST is for recreational flyers, and altitude limits do not substitute for the supervision requirement.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000004', 'Under Part 107, how are drones registered?', 'multiple_choice', '["Each individual aircraft must be registered with its own unique number","One registration number can be applied to all the pilot''s drones","Registration is not required for Part 107"]'::jsonb, 'Each individual aircraft must be registered with its own unique number', 'Part 107 requires per-aircraft registration. Single-number-covers-all is the recreational (§44809) approach, and Part 107 requires registration regardless of weight.', 'easy', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000005', 'Remote ID broadcast became an enforced requirement for drones that must be registered on what date?', 'multiple_choice', '["September 16, 2023","April 21, 2021","September 16, 2025"]'::jsonb, 'September 16, 2023', 'Broadcast Remote ID enforcement began September 16, 2023. April 21, 2021 was the effective date for night and operations-over-people rules.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000006', 'What key difference exists between a standard Remote ID drone and a Remote ID broadcast module?', 'multiple_choice', '["A standard RID drone broadcasts the live control-station location; a module broadcasts the take-off location","A module broadcasts the control-station location; a standard RID drone broadcasts only the take-off location","Both broadcast exactly the same information"]'::jsonb, 'A standard RID drone broadcasts the live control-station location; a module broadcasts the take-off location', 'A standard RID drone (built-in) broadcasts the live control-station/pilot location, while a retrofit module broadcasts the take-off location and requires the pilot to keep the drone within VLOS.', 'hard', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000007', 'You want to fly a drone that has no Remote ID equipment at all. Which option makes that legal?', 'multiple_choice', '["Fly within a FRIA, keeping the drone within VLOS","Fly only at night with anti-collision lighting","Register the drone twice"]'::jsonb, 'Fly within a FRIA, keeping the drone within VLOS', 'A FAA-Recognized Identification Area (FRIA) is the option that allows flying a non-RID drone, as long as it stays within VLOS inside the FRIA. Lighting and double registration do not satisfy RID.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000008', 'What is the minimum age to be eligible for a Remote Pilot Certificate?', 'multiple_choice', '["16 years old","18 years old","14 years old"]'::jsonb, '16 years old', 'You must be at least 16 to hold a remote pilot certificate. (Recreational flyers under §44809 have no minimum certificate age but must take TRUST.)', 'easy', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000009', 'To keep a remote pilot certificate valid for operations, a pilot must:', 'multiple_choice', '["Complete free online recurrent training every 24 calendar months","Retake the in-person UAG knowledge test every 24 months","Renew the certificate annually with the FAA, which issues a new card"]'::jsonb, 'Complete free online recurrent training every 24 calendar months', 'The certificate itself never expires, but aeronautical knowledge recency must be renewed every 24 calendar months via free online recurrent training — no in-person retest and no new card is issued.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000010', 'Who is ultimately responsible for ensuring a Part 107 operation complies with the regulations?', 'multiple_choice', '["The Remote PIC, who has final authority and responsibility","The visual observer","The drone manufacturer"]'::jsonb, 'The Remote PIC, who has final authority and responsibility', 'Under 107.19, the Remote PIC holds final authority and responsibility for the operation and its compliance.', 'easy', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000011', 'A pilot completed recurrent training and asks when a new certificate will arrive. What is correct?', 'multiple_choice', '["No new certificate is issued; the pilot retains the course-completion certificate as proof of currency","A new physical certificate is mailed within 30 days","The certificate must be reprinted at a PSI testing center"]'::jsonb, 'No new certificate is issued; the pilot retains the course-completion certificate as proof of currency', 'The FAA does not issue a new certificate after recurrent training; the pilot must keep and be able to present the recurrent course-completion certificate.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000012', 'What is the maximum allowable groundspeed for a small unmanned aircraft under Part 107?', 'multiple_choice', '["87 knots (100 mph)","100 knots (115 mph)","60 knots (70 mph)"]'::jsonb, '87 knots (100 mph)', '107.51 limits groundspeed to 87 knots, equal to 100 mph.', 'easy', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000013', 'You must inspect the antenna at the top of a 700-ft tower. Under the structure exception, the highest you may legally fly is approximately:', 'multiple_choice', '["1,100 ft AGL, as long as you stay within a 400-ft radius of the tower","400 ft AGL, with no exception for structures","700 ft AGL, the height of the tower"]'::jsonb, '1,100 ft AGL, as long as you stay within a 400-ft radius of the tower', 'Within a 400-ft radius of a structure you may fly up to 400 ft above the structure''s top: 700 + 400 ≈ 1,100 ft AGL. Outside the 400-ft radius, the 400-ft AGL ceiling applies again.', 'hard', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000014', 'The minimum flight visibility for a Part 107 operation, measured from the control station, is:', 'multiple_choice', '["3 statute miles","1 statute mile","5 statute miles"]'::jsonb, '3 statute miles', '107.51 requires a minimum flight visibility of 3 statute miles from the control-station location.', 'easy', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000015', 'What cloud clearance must a remote pilot maintain under 107.51?', 'multiple_choice', '["At least 500 ft below and 2,000 ft horizontally from clouds","At least 1,000 ft below and 1 mile horizontally from clouds","Clear of clouds at all times with no specific distance"]'::jsonb, 'At least 500 ft below and 2,000 ft horizontally from clouds', 'The required cloud clearance is 500 ft below and 2,000 ft horizontal. The 1,000-ft/1-mile values apply to certain manned-aircraft rules, not Part 107.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000016', 'You want to operate at night under Part 107. What is required?', 'multiple_choice', '["Anti-collision lighting visible for at least 3 statute miles, plus completion of the updated (night) training","A special night waiver, since night flight is otherwise prohibited","Nothing different from daytime operations"]'::jsonb, 'Anti-collision lighting visible for at least 3 statute miles, plus completion of the updated (night) training', 'Since the 2021 rule, night flight is allowed without a waiver if the aircraft has anti-collision lighting visible for 3 SM and the pilot has completed the updated night training. Night is not prohibited, but it does require the lighting.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000017', 'A remote pilot wears prescription glasses while flying. Regarding VLOS (107.31), this is:', 'multiple_choice', '["Acceptable — corrective lenses are allowed; binoculars or FPV alone are not","Prohibited — vision must be completely unaided","Acceptable only if a visual observer is also used"]'::jsonb, 'Acceptable — corrective lenses are allowed; binoculars or FPV alone are not', '107.31 requires unaided vision except for corrective lenses. Binoculars and FPV goggles may supplement but cannot replace VLOS, and a VO is optional.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000018', 'A manned helicopter is approaching your drone''s area. Under 107.37, you must:', 'multiple_choice', '["Yield the right of way and maneuver to avoid a collision hazard","Hold your position and let the helicopter avoid you","Climb above the helicopter to stay clear"]'::jsonb, 'Yield the right of way and maneuver to avoid a collision hazard', '107.37 requires the unmanned aircraft to yield right of way to all other aircraft and avoid creating a collision hazard. The drone always gives way.', 'easy', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000019', 'Operating the controls of a drone from a moving vehicle is permitted under Part 107:', 'multiple_choice', '["Only over a sparsely populated area (and not while carrying another''s property for hire)","Anywhere, as long as someone else is driving","Never, under any circumstances"]'::jsonb, 'Only over a sparsely populated area (and not while carrying another''s property for hire)', '107.25 prohibits operation from a moving vehicle except over a sparsely populated area, and never while transporting property for compensation/hire.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000020', 'A remote pilot finished two beers and wants to fly. Under Part 107, the pilot must wait at least:', 'multiple_choice', '["8 hours, and must not fly with a BAC of 0.04% or greater or while under the influence","4 hours, with no BAC limit","12 hours, with a BAC limit of 0.08%"]'::jsonb, '8 hours, and must not fly with a BAC of 0.04% or greater or while under the influence', 'The rule is 8 hours bottle-to-throttle, no flying under the influence, and BAC must be below 0.04%. 0.08% is the driving limit, not the aviation limit.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000021', 'You want to fly directly over a small group of people. Your drone weighs 0.5 lb and has no exposed parts that could lacerate skin. This best fits:', 'multiple_choice', '["Category 1 operations over people","Category 3 operations over people","Category 4 operations over people"]'::jsonb, 'Category 1 operations over people', 'Category 1 requires the aircraft to weigh 0.55 lb or less with no exposed lacerating parts and to meet Remote ID — matching a 0.5 lb drone. Cat 3 and Cat 4 apply to heavier or certificated aircraft.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000022', 'Which Operations Over People category is prohibited from sustained flight over open-air assemblies?', 'multiple_choice', '["Category 3","Category 1","Category 4"]'::jsonb, 'Category 3', 'Category 3 may operate over people only within a closed/restricted-access site or while transiting, and may not sustain flight over open-air assemblies. Categories 1, 2, and 4 may (with RID).', 'hard', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000023', 'During a flight your drone strikes a parked car, causing $800 in damage; no one is hurt. Under 107.9 you must:', 'multiple_choice', '["Report to the FAA within 10 calendar days","Not report, because no one was injured","Report only if the damage exceeds $1,000"]'::jsonb, 'Report to the FAA within 10 calendar days', 'Property damage (other than to the drone) over $500 triggers a 107.9 report within 10 calendar days, even with no injury. $800 exceeds $500.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000024', 'Your drone is damaged in a hard landing, costing $700 to repair, but nothing else is harmed and no one is injured. Under 107.9 you must:', 'multiple_choice', '["Not report — damage to the small unmanned aircraft itself does not count","Report within 10 days because the cost exceeds $500","Report immediately within 24 hours"]'::jsonb, 'Not report — damage to the small unmanned aircraft itself does not count', '107.9 excludes damage to the small unmanned aircraft itself from the $500 threshold. With no injury, loss of consciousness, or other property damage, no report is required.', 'hard', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000025', 'As part of preflight (107.15/107.49), the Remote PIC must, among other things:', 'multiple_choice', '["Assess weather/airspace/persons and confirm the aircraft is in condition for safe operation","Only confirm the battery is fully charged","File a flight plan with ATC for every flight"]'::jsonb, 'Assess weather/airspace/persons and confirm the aircraft is in condition for safe operation', '107.49 requires assessing the operating environment (weather, airspace/authorizations, persons/property, sufficient power, RID) and 107.15 requires the aircraft be in a condition for safe operation. No ATC flight plan is required for typical sUAS operations.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000026', 'Which of the following is a waivable section under 107.205?', 'multiple_choice', '["107.31 (visual line of sight)","107.9 (accident reporting)","107.5 (falsification)"]'::jsonb, '107.31 (visual line of sight)', '107.31 (VLOS) is on the 107.205 waivable list. Accident reporting (107.9) and falsification (107.5) are not waivable.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000027', 'To fly in Class D controlled airspace near a towered airport, a Part 107 pilot needs:', 'multiple_choice', '["An airspace authorization (e.g., via LAANC or DroneZone)","Only a certificate of waiver under 107.200","Nothing, because Class D is uncontrolled"]'::jsonb, 'An airspace authorization (e.g., via LAANC or DroneZone)', 'Controlled airspace (B, C, D, surface E) requires an airspace authorization via LAANC or FAADroneZone — separate from an operational waiver. Class D is controlled, not uncontrolled.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000028', 'When carrying another person''s property for compensation, which two sections may NOT be waived?', 'multiple_choice', '["107.25 (moving vehicle) and 107.31 (VLOS)","107.29 (night) and 107.35 (multiple aircraft)","107.39 (over people) and 107.51 (operating limitations)"]'::jsonb, '107.25 (moving vehicle) and 107.31 (VLOS)', 'For carriage of another''s property for hire, 107.25 and 107.31 cannot be waived. The others remain potentially waivable under 107.205.', 'hard', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000029', 'A recreational flyer under §44809 begins using the drone to inspect a paying client''s roof. The flight is now judged:', 'multiple_choice', '["Under Part 107, because the recreational conditions were violated","Still under §44809, as long as TRUST was completed","Under no rule, since the drone is small"]'::jsonb, 'Under Part 107, because the recreational conditions were violated', 'Flying for compensation violates the ''strictly recreational'' condition of §44809, so the operation is judged under Part 107 — which requires a remote pilot certificate the flyer may not hold.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70230-0000-0000-0000-000000000030', 'Which statement correctly distinguishes a 107.200 waiver from an airspace authorization?', 'multiple_choice', '["A waiver permits deviation from a Part 107 rule; an authorization permits flight in controlled airspace","They are the same thing under different names","A waiver is only for recreational flyers; an authorization is only for Part 107"]'::jsonb, 'A waiver permits deviation from a Part 107 rule; an authorization permits flight in controlled airspace', 'A certificate of waiver (107.200) authorizes deviation from a waivable rule, while an airspace authorization (LAANC/DroneZone) permits operations in controlled airspace. They are separate approvals, both for Part 107 operations.', 'medium', 'faa70000-0000-0000-0000-000000000002', 'faa70210-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70310-0000-0000-0000-000000000001', 'faa70000-0000-0000-0000-000000000003', 'The National Airspace System: Controlled vs. Uncontrolled', '', ARRAY['The NAS is divided into lettered classes A-G to keep aircraft separated.','Controlled = Classes A, B, C, D, E (ATC provides services); uncontrolled = Class G.','Part 107 requires an airspace authorization (LAANC/DroneZone) to fly in controlled airspace; Class G needs none.','Drones are limited to 400 ft AGL, so the relevant airspace is the lowest slice near the surface.','Class A (18,000 ft MSL to FL600) is never relevant to drone operations but appears on the exam.']::text[], 1, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Define the National Airspace System (NAS) and the purpose of airspace classification.','Distinguish controlled airspace (A-E) from uncontrolled airspace (Class G).','Explain the practical meaning of ''controlled'' for a Part 107 remote pilot.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0001-0000-0000-000000000000', 'faa70310-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What the National Airspace System Is</h3><p>The <strong>National Airspace System (NAS)</strong> is the network of airspace, airports, navigation aids, air traffic control facilities, rules, and procedures that lets manned and unmanned aircraft share the sky safely. To keep traffic separated, the United States divides the airspace into lettered <strong>classes</strong>, each with its own dimensions, communication and equipment requirements, and entry rules. As a Remote Pilot in Command (RPIC) you do not need to memorize every manned-aircraft requirement, but you absolutely must know <strong>which class of airspace you are flying in</strong> and <strong>whether it requires authorization</strong> before you launch.</p><p>Two big buckets matter for Part 107: <strong>controlled airspace</strong> (Classes A, B, C, D, and E) where air traffic control (ATC) provides separation services, and <strong>uncontrolled airspace</strong> (Class G) where ATC does not. The single most important habit this module builds is reading a <strong>Sectional Aeronautical Chart</strong> to figure out which class sits over any spot on the ground.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0001-0000-0000-000000000001', 'faa70310-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Controlled vs. Uncontrolled in Plain Terms</h3><p><strong>Controlled airspace</strong> does not mean drones are banned there. It means ATC exercises some authority and provides services to participating aircraft. For a Part 107 pilot the practical translation is simple: <strong>to fly in controlled airspace you must obtain an airspace authorization first</strong> (through LAANC or FAADroneZone). <strong>Uncontrolled airspace (Class G)</strong> requires <strong>no ATC authorization</strong> — it is the default legal home for sUAS flying at or below 400 ft AGL, as long as you obey all other Part 107 rules.</p><p>Remember a key reference frame: airspace floors and ceilings are quoted in feet above ground level (<strong>AGL</strong>) or feet above mean sea level (<strong>MSL</strong>). Drones are limited to 400 ft AGL, so most of the airspace you ever touch is the lowest slice — exactly the slice that surrounds airports, where controlled airspace usually comes all the way down to the surface.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0001-0000-0000-000000000002', 'faa70310-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Class letters run A (highest/busiest) through G (uncontrolled). A memory hook: A, B, C, D, E are Controlled; G is the ''Ground/General'' airspace that is uncontrolled. (There is no Class F in the United States.)"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0001-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Side-view cross-section of the NAS showing each airspace class by altitude, with Class B''s upside-down wedding-cake shape, Class C''s two-tier shape, Class D''s cylinder to the surface, Class E floors at 700/1,200 ft AGL and the surface, Class A from 18,000 ft MSL up, and Class G filling the space below the overlying Class E."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0001-0000-0000-000000000004', 'faa70310-0000-0000-0000-000000000001', 'table', '{"headers":["Bucket","Classes","ATC services?","Part 107 authorization needed?"],"rows":[["Controlled","A, B, C, D, E","Yes (to participating aircraft)","Yes for B, C, D, and surface-area E"],["Uncontrolled","G","No","No"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0001-0000-0000-000000000005', 'faa70310-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Class A airspace begins at 18,000 ft MSL and tops out at FL600 (60,000 ft) — far above the 400 ft AGL drone ceiling. You will never legally operate a Part 107 drone in Class A, but you must still know it exists for the exam."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0001-0000-0000-000000000006', 'faa70310-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The NAS is divided into lettered classes A-G to keep aircraft separated.","Controlled = Classes A, B, C, D, E (ATC provides services); uncontrolled = Class G.","Part 107 requires an airspace authorization (LAANC/DroneZone) to fly in controlled airspace; Class G needs none.","Drones are limited to 400 ft AGL, so the relevant airspace is the lowest slice near the surface.","Class A (18,000 ft MSL to FL600) is never relevant to drone operations but appears on the exam."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70310-0000-0000-0000-000000000002', 'faa70000-0000-0000-0000-000000000003', 'Controlled Airspace: Classes A, B, C, and D', '', ARRAY['Class A: 18,000 ft MSL to FL600 — never a drone operating concern.','Class B (busiest airports): surface to ~10,000 MSL, upside-down wedding cake, solid BLUE.','Class C (busy airports): surface to ~4,000 AGL, solid MAGENTA.','Class D (towered airports): surface to ~2,500 AGL, BLUE DASHED, ceiling shown in a box (hundreds of ft MSL).','B, C, and D all require a Part 107 airspace authorization before flight.']::text[], 2, 28, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['State the altitude limits and physical shape of Class A, B, C, and D airspace.','Match each class to its Sectional Chart line color.','Recognize that Class B, C, and D all require Part 107 authorization before flight.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000000', 'faa70310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Class A: The High-Altitude Ceiling</h3><p><strong>Class A</strong> airspace extends from <strong>18,000 ft MSL up to and including FL600 (60,000 ft)</strong> over the contiguous United States and offshore areas. All operations there are conducted under instrument flight rules (IFR) by ATC clearance. Because it begins miles above the 400 ft AGL drone limit, <strong>Class A is never a Part 107 concern operationally</strong> — but expect a knowledge-test question on its floor (18,000 MSL) and ceiling (FL600).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000001', 'faa70310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Class B: The Busiest Airports (''Upside-Down Wedding Cake'')</h3><p><strong>Class B</strong> surrounds the nation''s <strong>busiest airports</strong> (think major metropolitan hubs). It typically extends from the <strong>surface up to about 10,000 ft MSL</strong> and is built from several concentric shelves that get wider as you go up — the classic <strong>''upside-down wedding cake.''</strong> On a Sectional Chart, Class B is drawn with <strong>solid blue</strong> lines. Every Part 107 operation inside Class B requires an <strong>airspace authorization</strong> before flight.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000002', 'faa70310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Class C: Busy (Not Busiest) Airports</h3><p><strong>Class C</strong> surrounds <strong>moderately busy</strong> airports with an operating control tower and radar approach control. It generally runs from the <strong>surface to about 4,000 ft AGL</strong> and is usually a two-ring structure (an inner surface ring and an outer shelf). On the Sectional, Class C is drawn with <strong>solid magenta</strong> lines. Authorization is required for Part 107 operations.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Class D: Smaller Towered Airports</h3><p><strong>Class D</strong> surrounds airports that have an <strong>operating control tower</strong> but less traffic than Class C. It is typically a simple cylinder from the <strong>surface up to about 2,500 ft AGL</strong>, and on the chart it is shown with a <strong>blue dashed</strong> ring. A small <strong>boxed number</strong> inside the ring (for example, [25]) gives the Class D <strong>ceiling in hundreds of feet MSL</strong> — [25] means the top is 2,500 ft MSL. Authorization is required. Note that when a control tower closes for the night, the airspace may revert to Class E or G, but for Part 107 planning you still treat the charted controlled airspace as requiring authorization unless you confirm otherwise.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000004', 'faa70310-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Sectional excerpt placing the three towered-airport airspaces side by side — solid BLUE concentric Class B rings, solid MAGENTA Class C rings, and a BLUE DASHED Class D ring with its boxed ceiling number (e.g., [33]) shown clearly."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000005', 'faa70310-0000-0000-0000-000000000002', 'table', '{"headers":["Class","Typical vertical extent","Sectional line color","107 authorization?"],"rows":[["A","18,000 ft MSL to FL600","Not depicted on sectionals as a ring","N/A (above drones)"],["B","Surface to ~10,000 ft MSL","Solid BLUE","Required"],["C","Surface to ~4,000 ft AGL","Solid MAGENTA","Required"],["D","Surface to ~2,500 ft AGL","BLUE DASHED","Required"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000006', 'faa70310-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Don''t confuse the colors: Class B and Class D are both BLUE (B solid, D dashed); Class C is solid MAGENTA. A common trap on the exam is calling a magenta solid ring ''Class B'' — magenta solid is Class C."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0002-0000-0000-000000000007', 'faa70310-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Class A: 18,000 ft MSL to FL600 — never a drone operating concern.","Class B (busiest airports): surface to ~10,000 MSL, upside-down wedding cake, solid BLUE.","Class C (busy airports): surface to ~4,000 AGL, solid MAGENTA.","Class D (towered airports): surface to ~2,500 AGL, BLUE DASHED, ceiling shown in a box (hundreds of ft MSL).","B, C, and D all require a Part 107 airspace authorization before flight."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70310-0000-0000-0000-000000000003', 'faa70000-0000-0000-0000-000000000003', 'Class E, Class G, and Who Needs Authorization', '', ARRAY['Class E floors: surface (dashed magenta), 700 ft AGL (faded magenta vignette), 1,200 ft AGL (faded blue vignette).','Only surface-area Class E (dashed magenta) reaches drone altitude and requires authorization.','Class G is uncontrolled, runs surface to the base of overlying Class E, and needs no authorization.','14 CFR 107.41 requires ATC authorization for Class B, C, D, and surface-area E — obtained via LAANC (near-real-time) or DroneZone.','A UASFM ''0'' grid means no automatic LAANC; a further-coordination request is required.']::text[], 3, 28, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Describe where Class E airspace begins (surface, 700 ft AGL, 1,200 ft AGL) and how each is charted.','Define Class G uncontrolled airspace and its relationship to the overlying Class E.','Explain why controlled airspace near the surface requires LAANC/DroneZone authorization but Class G does not.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0003-0000-0000-000000000000', 'faa70310-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Class E: Controlled Airspace That Floats at Different Floors</h3><p><strong>Class E</strong> is controlled airspace that is everywhere except where another class or Class G exists. What makes it tricky is that its <strong>floor</strong> changes from place to place. The three floors a drone pilot cares about are:</p><ul><li><strong>Surface</strong> — Class E to the ground, usually around an airport that needs controlled airspace but doesn''t rate a tower. Charted with a <strong>dashed magenta</strong> line. <strong>This requires Part 107 authorization</strong> because it is controlled airspace touching the surface where you fly.</li><li><strong>700 ft AGL</strong> — the most common floor; charted as a <strong>fuzzy/faded magenta vignette</strong> that fades <em>outward</em>. Inside the faded edge the floor is 700 AGL.</li><li><strong>1,200 ft AGL</strong> — charted as a <strong>fuzzy/faded blue vignette</strong>.</li></ul><p>For a drone flying at or below 400 ft AGL, a Class E floor of 700 or 1,200 ft AGL sits <em>above</em> you — so you are actually operating in the <strong>Class G</strong> beneath it and need no authorization. Only <strong>surface-area Class E</strong> (the dashed magenta) reaches down to where you fly and triggers an authorization requirement.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0003-0000-0000-000000000001', 'faa70310-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Sectional excerpt that shows all three Class E depictions together — a DASHED MAGENTA surface-area ring around an airport, the FADED MAGENTA vignette (700 ft AGL floor) fading outward, and a FADED BLUE vignette marking where the floor steps up to 1,200 ft AGL."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0003-0000-0000-000000000002', 'faa70310-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Class G: Uncontrolled — The Drone''s Default Home</h3><p><strong>Class G</strong> is <strong>uncontrolled</strong> airspace. It runs from the <strong>surface up to the base of the overlying Class E</strong> — commonly 700 ft AGL (under a magenta vignette) or 1,200 ft AGL (under a blue vignette), and in some remote areas higher. Because a drone is limited to 400 ft AGL, when you are in a Class G area you are comfortably below the Class E floor and <strong>no ATC authorization is required.</strong> Class G is where the vast majority of legal Part 107 flying happens.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0003-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Why Controlled Airspace Needs LAANC/DroneZone but Class G Does Not</h3><p><strong>14 CFR 107.41</strong> prohibits operating in Class B, C, D, or the surface area of Class E <strong>without prior authorization from ATC.</strong> The reason is safety: those areas surround airports where manned aircraft are taking off and landing at low altitude — exactly the altitude band a drone occupies. ATC needs to know a drone is operating so it can manage that risk, so the FAA created two tools to grant authorization:</p><ul><li><strong>LAANC</strong> (Low Altitude Authorization and Notification Capability) — gives <strong>near-real-time</strong> authorization up to the altitude posted on the UAS Facility Map grid for that location.</li><li><strong>FAADroneZone</strong> — the FAA portal used where LAANC is unavailable, and for further-coordination requests and waivers (not near-real-time).</li></ul><p><strong>Class G</strong> has none of this airport traffic structure at the surface, so no authorization is needed — but you still owe every other Part 107 duty: stay at or below 400 ft AGL, maintain visual line of sight, yield to manned aircraft, and check for TFRs.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0003-0000-0000-000000000004', 'faa70310-0000-0000-0000-000000000003', 'accordion', '{"sections":[{"title":"How LAANC works (and the ''0'' grid)","content":"<p>LAANC is a partnership between the FAA and approved companies called UAS Service Suppliers (USS). You request authorization through a USS app; if your requested altitude is at or below the maximum altitude posted on the UAS Facility Map (UASFM) grid for that location, the system can approve it <strong>automatically in near-real-time.</strong> A grid showing <strong>''0''</strong> means automatic LAANC is NOT available there — you must submit a <strong>further-coordination</strong> request through FAADroneZone, which the FAA reviews manually and is much slower.</p>","open":false},{"title":"UAS Facility Maps (UASFM)","content":"<p>UAS Facility Maps are grids overlaid around controlled airports that show the <strong>maximum altitude (e.g., 0, 100, 200, 300, 400 ft AGL)</strong> at which LAANC can pre-approve a drone operation. Lower numbers appear close to runways; the cap may be 400 ft farther out. Always check the grid value before requesting an authorization.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0003-0000-0000-000000000005', 'faa70310-0000-0000-0000-000000000003', 'callout', '{"type":"error","text":"Authorization is NOT a waiver. An airspace authorization (LAANC/DroneZone) lets you enter controlled airspace; a waiver (107.205) lets you deviate from an operating rule like VLOS or flying over people. Don''t mix them up on the exam."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0003-0000-0000-000000000006', 'faa70310-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Class E floors: surface (dashed magenta), 700 ft AGL (faded magenta vignette), 1,200 ft AGL (faded blue vignette).","Only surface-area Class E (dashed magenta) reaches drone altitude and requires authorization.","Class G is uncontrolled, runs surface to the base of overlying Class E, and needs no authorization.","14 CFR 107.41 requires ATC authorization for Class B, C, D, and surface-area E — obtained via LAANC (near-real-time) or DroneZone.","A UASFM ''0'' grid means no automatic LAANC; a further-coordination request is required."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70310-0000-0000-0000-000000000004', 'faa70000-0000-0000-0000-000000000003', 'Reading the Sectional Chart: Airports, Airspace Lines & Vignettes', '', ARRAY['Blue airport symbol = towered; magenta airport symbol = non-towered.','Solid blue = Class B; solid magenta = Class C; blue dashed = Class D; magenta dashed = Class E to surface.','Faded magenta vignette = Class E floor at 700 ft AGL; faded blue vignette = floor at 1,200 ft AGL.','Stacked/slashed numbers show ceiling over floor in hundreds of feet MSL (e.g., 41/12 = 4,100 over 1,200 MSL).','SFC = surface; a boxed number by a blue dashed ring is the Class D ceiling in hundreds of feet MSL.']::text[], 4, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Identify towered vs. non-towered airport symbols by color.','Decode every airspace line/vignette color back to its airspace class.','Interpret ceiling and floor numbers (boxes and slashed pairs) on the chart.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000000', 'faa70310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The Sectional Aeronautical Chart</h3><p>A <strong>Sectional Aeronautical Chart</strong> (or ''sectional'') is the primary VFR chart pilots and drone operators use to see airspace, airports, terrain, and obstacles. Many UAG exam questions hand you a chart excerpt and ask which airspace applies, how high you may fly, or what a symbol means. The chart speaks in <strong>color and symbol</strong> — once you can translate those two languages, chart questions become quick points.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000001', 'faa70310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Airport Symbols: Color Tells You Towered vs. Non-Towered</h3><p>The color of an airport symbol tells you whether it has an operating control tower:</p><ul><li><strong>BLUE airport symbol</strong> = airport <strong>WITH</strong> an operating control tower (towered).</li><li><strong>MAGENTA airport symbol</strong> = airport <strong>WITHOUT</strong> an operating control tower (non-towered).</li></ul><p>Extra marks add detail: small <strong>ticks/extensions</strong> around the symbol indicate fuel and services are available; a <strong>star</strong> above the symbol means the airport has a <strong>rotating beacon</strong>; the runway layout may be drawn to scale at larger airports.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000002', 'faa70310-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Side-by-side airport symbols — a BLUE towered-airport symbol and a MAGENTA non-towered-airport symbol — annotated with the fuel/service ticks and the rotating-beacon star."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Airspace Lines & Vignettes: The Master Color Key</h3><p>Every boundary on the chart maps to an airspace class. Memorize this key — it is the single highest-yield chart skill for Part 107:</p><ul><li><strong>Solid BLUE line</strong> = Class B.</li><li><strong>Solid MAGENTA line</strong> = Class C.</li><li><strong>BLUE DASHED line</strong> = Class D.</li><li><strong>MAGENTA DASHED line</strong> = Class E to the surface.</li><li><strong>Faded MAGENTA vignette</strong> (fades outward) = Class E floor at 700 ft AGL.</li><li><strong>Faded BLUE vignette</strong> = Class E floor at 1,200 ft AGL.</li></ul><p>A handy rule for the magenta fade: standing <em>inside</em> the faded magenta, the Class E floor is 700 AGL; step <em>outside</em> it (onto the plain background or into the blue vignette) and the floor is 1,200 AGL or as noted.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000004', 'faa70310-0000-0000-0000-000000000004', 'table', '{"headers":["What you see on the chart","Airspace it means","Floor / ceiling clue"],"rows":[["Solid blue line","Class B","Floors/ceilings printed in the shelf boxes (MSL)"],["Solid magenta line","Class C","Floor/ceiling pairs printed near the ring (MSL)"],["Blue dashed line","Class D","Boxed number = ceiling in hundreds of ft MSL"],["Magenta dashed line","Class E to surface","Reaches the ground; authorization required"],["Faded magenta (fades outward)","Class E, floor 700 ft AGL","Inside the fade = 700 AGL floor"],["Faded blue","Class E, floor 1,200 ft AGL","Floor steps up to 1,200 AGL"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000005', 'faa70310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Reading the Ceiling/Floor Numbers</h3><p>Airspace boxes use a stacked or slashed pair of numbers to show the <strong>ceiling over the floor</strong>, in hundreds of feet MSL. For example, a Class C shelf marked <strong>41/12</strong> means the airspace there runs from a floor of <strong>1,200 ft MSL up to a ceiling of 4,100 ft MSL</strong>. A bare <strong>boxed number like [25]</strong> next to a blue dashed ring is a Class D <strong>ceiling</strong> of 2,500 ft MSL. A floor written as <strong>SFC</strong> means the airspace starts at the surface.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000006', 'faa70310-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Zoomed chart excerpt highlighting airspace floor/ceiling numbers — a Class C shelf labeled ''41/12'' (4,100 MSL ceiling over 1,200 MSL floor) and a Class D ring with a boxed [25] ceiling (2,500 MSL), with an ''SFC'' floor callout."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0004-0000-0000-000000000007', 'faa70310-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Blue airport symbol = towered; magenta airport symbol = non-towered.","Solid blue = Class B; solid magenta = Class C; blue dashed = Class D; magenta dashed = Class E to surface.","Faded magenta vignette = Class E floor at 700 ft AGL; faded blue vignette = floor at 1,200 ft AGL.","Stacked/slashed numbers show ceiling over floor in hundreds of feet MSL (e.g., 41/12 = 4,100 over 1,200 MSL).","SFC = surface; a boxed number by a blue dashed ring is the Class D ceiling in hundreds of feet MSL."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70310-0000-0000-0000-000000000005', 'faa70000-0000-0000-0000-000000000003', 'Airport Data Blocks, Frequencies, Lat/Long & the MEF', '', ARRAY['The airport data block lists name, field elevation (MSL), CTAF/UNICOM frequency, runway length, and lighting.','CTAF is shown with a bold magenta ''C'' in a circle; UNICOM commonly 122.7-123.0; monitoring CTAF aids awareness.','Latitude = N/S parallels; longitude = E/W meridians; tick marks on the neatlines read coordinates (60 minutes per degree).','The MEF is the highest terrain/obstacle in a quadrangle in thousands+hundreds of ft MSL (12 over 5 = 12,500 MSL).','Field elevation matters because airspace ceilings are MSL while your 400 ft drone limit is AGL.']::text[], 5, 28, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Read an airport data block for elevation, CTAF/UNICOM frequency, runway length, and lighting.','Locate and interpret latitude/longitude tick marks on the chart neatlines.','Define the Maximum Elevation Figure (MEF) and read it from a chart quadrangle.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000000', 'faa70310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>The Airport Data Block</h3><p>Next to each airport symbol is a small block of text — the <strong>airport data block</strong>. Reading it tells you how to coordinate with manned traffic and assess the site. A typical block lists, in order, the airport <strong>name</strong>, the <strong>field elevation in feet MSL</strong>, the <strong>CTAF/UNICOM frequency</strong>, the <strong>longest runway length</strong> (in hundreds of feet), and <strong>lighting</strong> availability (e.g., an asterisk/''L'' code for lighting that operates on a schedule). Knowing the field elevation matters because airspace ceilings are in MSL but your drone limit is AGL.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000001', 'faa70310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>CTAF & Other Frequencies</h3><p>Many drone sites sit near <strong>non-towered</strong> airports where pilots self-announce on the <strong>CTAF (Common Traffic Advisory Frequency)</strong>. On the chart, the CTAF is marked with a bold <strong>''C''</strong> inside a magenta circle next to the frequency. <strong>UNICOM</strong> (an advisory/ground service) commonly uses 122.7, 122.8, 122.9, or 123.0 MHz. Around Class B/C/D airspace you will also see boxed <strong>approach/departure</strong> and tower frequencies. While Part 107 does not require you to transmit, <strong>monitoring</strong> the CTAF is excellent practice for keeping situational awareness of manned aircraft taking off and landing.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000002', 'faa70310-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A magnified Sectional airport data block with callouts labeling each element — airport name, field elevation (MSL), CTAF frequency (with the bold magenta ''C'' in a circle), runway length in hundreds of feet, and the lighting code."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Latitude & Longitude</h3><p><strong>Latitude</strong> lines (parallels) run east-west and measure degrees <strong>north or south</strong> of the equator; <strong>longitude</strong> lines (meridians) run north-south and measure degrees <strong>east or west</strong> of the Prime Meridian. On a Sectional, tick marks along the <strong>neatlines</strong> (and along the latitude/longitude grid lines crossing the chart) let you read a location''s coordinates. Each degree is divided into 60 minutes; the small ticks usually mark single minutes. Exam questions may give you coordinates and ask you to find the airspace at that point, or give a point and ask for its coordinates.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000004', 'faa70310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>The Maximum Elevation Figure (MEF)</h3><p>Each latitude-longitude <strong>quadrangle</strong> on the chart carries a large <strong>bold number</strong> made of two parts — for example a big <strong>''12''</strong> with a slightly smaller <strong>''5''</strong>. This is the <strong>Maximum Elevation Figure (MEF)</strong>: the height of the <strong>highest known terrain or obstacle</strong> in that quadrangle, expressed in <strong>thousands and hundreds of feet MSL.</strong> A MEF shown as 12<sup>5</sup> means 12,500 ft MSL. The MEF includes an allowance for the height of obstacles and gives a quick terrain-clearance reference. While a drone stays at 400 ft AGL, the MEF is a fast way to spot tall obstructions worth investigating before you fly.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000005', 'faa70310-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A chart quadrangle bounded by latitude/longitude lines, showing the large bold Maximum Elevation Figure (e.g., 12 with a superscript 5 = 12,500 ft MSL) centered in the block, with the minute tick marks along the lat/long neatlines called out."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000006', 'faa70310-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"MEF math: read it as thousands + hundreds of feet MSL. A MEF of 3 with a small 4 = 3,400 ft MSL; a MEF of 10 with a small 8 = 10,800 ft MSL. It is the HIGHEST obstacle/terrain in that grid square, not an airspace floor."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0005-0000-0000-000000000007', 'faa70310-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["The airport data block lists name, field elevation (MSL), CTAF/UNICOM frequency, runway length, and lighting.","CTAF is shown with a bold magenta ''C'' in a circle; UNICOM commonly 122.7-123.0; monitoring CTAF aids awareness.","Latitude = N/S parallels; longitude = E/W meridians; tick marks on the neatlines read coordinates (60 minutes per degree).","The MEF is the highest terrain/obstacle in a quadrangle in thousands+hundreds of ft MSL (12 over 5 = 12,500 MSL).","Field elevation matters because airspace ceilings are MSL while your 400 ft drone limit is AGL."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70310-0000-0000-0000-000000000006', 'faa70000-0000-0000-0000-000000000003', 'Special Use Airspace, TFRs, NOTAMs & Obstructions', '', ARRAY['Prohibited (P) = no flight; Restricted (R) = enter only with permission when cold; Warning (W) = like restricted but over international waters.','MOA, Alert (A), and Controlled Firing Areas are non-regulatory; CFAs are not charted.','SUA is outlined with hatched borders; a tabulation box lists numbers, altitudes, hours, and controlling agency.','TFRs (issued as FDC NOTAMs) are temporary, often ban UAS, and must be checked before every flight.','Obstructions show top MSL in bold and AGL in parentheses; lighted/tall (>=1,000 AGL) obstructions get special symbols.']::text[], 6, 28, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Identify the types of Special Use Airspace and how each is charted.','Explain TFRs and NOTAMs and the duty to check them before every flight.','Recognize charted obstructions and lighting symbols and their height labels.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0006-0000-0000-000000000000', 'faa70310-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Special Use Airspace (SUA)</h3><p><strong>Special Use Airspace</strong> sets aside areas where activities require limits on other aircraft. Some are <strong>regulatory</strong> (created by rulemaking, 14 CFR Part 73) and some are <strong>non-regulatory.</strong> They are outlined on the chart with blue or magenta <strong>hatched borders</strong>, and a tabbed box lists each area''s <strong>number, altitudes, hours of use, and controlling agency.</strong></p><ul><li><strong>Prohibited Area (P-###):</strong> flight is <strong>prohibited</strong> entirely (e.g., over the White House). Regulatory.</li><li><strong>Restricted Area (R-###):</strong> hazardous activity such as artillery or missile firing; flight is <strong>restricted</strong> and you may enter only with the controlling agency''s permission when it is ''cold.'' Regulatory.</li><li><strong>Warning Area (W-###):</strong> like a restricted area but located over <strong>international waters</strong> (3+ NM offshore). Non-regulatory.</li><li><strong>Military Operations Area (MOA):</strong> separates military training from IFR traffic; use caution when active. Non-regulatory.</li><li><strong>Alert Area (A-###):</strong> high volume of pilot training or unusual aerial activity; all pilots share responsibility to see and avoid. Non-regulatory.</li><li><strong>Controlled Firing Area (CFA):</strong> activity that ceases when an aircraft approaches; <strong>not charted</strong> because it poses no charted hazard.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0006-0000-0000-000000000001', 'faa70310-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Sectional excerpt displaying several Special Use Airspace borders (a Restricted Area R-#### with blue hatching, a Prohibited Area, a magenta-hatched MOA, and an Alert Area) alongside the chart''s SUA tabulation box listing numbers, altitudes, times, and controlling agency."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0006-0000-0000-000000000002', 'faa70310-0000-0000-0000-000000000006', 'text', '{"html":"<h3>TFRs and NOTAMs</h3><p>A <strong>Temporary Flight Restriction (TFR)</strong> restricts flight in a defined area for a limited time — common reasons include VIP/Presidential movement, disasters, wildfires, and major sporting events. TFRs are issued as <strong>FDC NOTAMs</strong>, and <strong>many TFRs prohibit all UAS operations.</strong> Because they pop up and expire, they are <strong>not pre-printed</strong> on the Sectional — you must check for active TFRs before every flight.</p><p>A <strong>NOTAM (Notice to Air Missions)</strong> is time-critical aeronautical information such as a closed runway, an inoperative light, a crane erected near an airport, or an airspace restriction. Part 107 pilots must check NOTAMs and TFRs as part of preflight planning; an airspace authorization does not excuse you from complying with an active TFR or NOTAM.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0006-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'callout', '{"type":"warning","text":"TFRs are dynamic and override your routine plan. Check a current source (B4UFLY app, the FAA TFR list, or a briefing) immediately before launch. Stadium TFRs and disaster/VIP TFRs frequently ban drones outright."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0006-0000-0000-000000000004', 'faa70310-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Obstructions & Lighting</h3><p><strong>Obstructions</strong> (towers, antennas, tall buildings) are drawn on the chart with an <strong>inverted-V</strong> symbol; a group of them gets a clustered symbol. Each obstruction lists <strong>two heights</strong>: the <strong>top above MSL in bold</strong>, and the <strong>height above ground (AGL) in parentheses below it.</strong> For example, <strong>1,549 (1,149)</strong> means the top is 1,549 ft MSL and the structure rises 1,149 ft above the ground. Obstructions that are <strong>lighted</strong> show a small lightning-bolt/asterisk-style marking. Obstructions <strong>1,000 ft AGL or higher</strong> are drawn with a bolder symbol. Because drones operate low, charted towers — especially tall lighted ones — are a real collision hazard worth checking against your flight area.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0006-0000-0000-000000000005', 'faa70310-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Sectional obstruction symbology — a single tower (inverted V) and a grouped obstruction, each annotated with the bold top-of-structure MSL height and the parenthetical AGL height, plus the symbol used for high-intensity lighted obstructions."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0006-0000-0000-000000000006', 'faa70310-0000-0000-0000-000000000006', 'key_takeaways', '{"title":"Key Takeaways","items":["Prohibited (P) = no flight; Restricted (R) = enter only with permission when cold; Warning (W) = like restricted but over international waters.","MOA, Alert (A), and Controlled Firing Areas are non-regulatory; CFAs are not charted.","SUA is outlined with hatched borders; a tabulation box lists numbers, altitudes, hours, and controlling agency.","TFRs (issued as FDC NOTAMs) are temporary, often ban UAS, and must be checked before every flight.","Obstructions show top MSL in bold and AGL in parentheses; lighted/tall (>=1,000 AGL) obstructions get special symbols."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70310-0000-0000-0000-000000000007', 'faa70000-0000-0000-0000-000000000003', 'Putting It Together: Can I Legally Fly Here?', '', ARRAY['Five-step go/no-go: locate -> identify airspace -> authorization? -> TFR/SUA/NOTAM -> obstructions/MEF.','Class G below 400 ft AGL needs no authorization; controlled airspace needs LAANC or DroneZone first.','An active prohibitive TFR or a prohibited area overrides everything else — do not fly.','The UASFM altitude caps what LAANC can auto-approve; a ''0'' grid means no automatic approval.','Use B4UFLY and a current TFR/NOTAM check immediately before launch to confirm the plan.']::text[], 7, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Apply a step-by-step workflow to decide whether a location is legal to fly.','Integrate airspace class, authorization, SUA, TFRs, and obstructions into a go/no-go decision.','Use tools (UASFM, B4UFLY, LAANC) to confirm a plan.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0007-0000-0000-000000000000', 'faa70310-0000-0000-0000-000000000007', 'text', '{"html":"<h3>A Repeatable Decision Workflow</h3><p>Every chart question and every real flight boils down to one question: <strong>''Can I legally fly here, and how high?''</strong> Use this five-step workflow every time:</p><ol><li><strong>Locate the point</strong> on the chart (by airport name or by latitude/longitude).</li><li><strong>Identify the airspace</strong> at the surface there — read the ring colors and vignettes to name the class.</li><li><strong>Decide if authorization is needed.</strong> Controlled (B/C/D/surface-E) = yes, get LAANC or DroneZone first. Class G = no authorization needed.</li><li><strong>Check for restrictions</strong> — active TFRs, Special Use Airspace, and a current NOTAM search.</li><li><strong>Check obstructions and terrain</strong> — towers, MEF, and the local environment around your operating area.</li></ol><p>If any step says ''no'' (an active prohibitive TFR, a prohibited area, no authorization obtained for controlled airspace), then you do not fly until the issue is resolved.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0007-0000-0000-000000000001', 'faa70310-0000-0000-0000-000000000007', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A decision flowchart mirroring the five-step workflow — Locate point -> Identify airspace class -> Authorization needed? (Class G = no / controlled = LAANC/DroneZone) -> TFR/SUA/NOTAM check -> Obstruction & MEF check -> GO / NO-GO."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0007-0000-0000-000000000002', 'faa70310-0000-0000-0000-000000000007', 'accordion', '{"sections":[{"title":"Worked example 1 — Magenta non-towered field in faded magenta","content":"<p>You plan to fly in a park next to a <strong>magenta (non-towered) airport</strong> that sits inside a <strong>faded magenta vignette</strong> with no dashed ring touching it. The faded magenta means Class E starts at <strong>700 ft AGL</strong>; below that, at the surface, you are in <strong>Class G.</strong> A drone at 400 ft AGL is in Class G, so <strong>no authorization is required.</strong> You still check TFRs/NOTAMs, watch for traffic at the non-towered field, and stay within VLOS at or below 400 ft AGL. Result: GO (with normal precautions).</p>","open":false},{"title":"Worked example 2 — Blue dashed ring around a towered airport","content":"<p>Your site falls inside a <strong>blue dashed ring</strong> with a boxed [33] ceiling. Blue dashed = <strong>Class D</strong> (controlled, surface to 3,300 ft MSL). You <strong>must obtain an airspace authorization</strong> (LAANC if available, otherwise FAADroneZone) before flying, and you may only go up to the altitude the UASFM grid permits at that spot — which could be 400 ft, 100 ft, or even 0 (no auto-LAANC). Result: NO-GO until authorized.</p>","open":false},{"title":"Worked example 3 — Stadium event day","content":"<p>Your Class G site is fine on the chart, but there is a major sporting event nearby today. A <strong>stadium TFR</strong> may be active, and many of those <strong>prohibit all UAS</strong> within a several-mile radius up to a few thousand feet. Even though the underlying airspace is uncontrolled, the active <strong>TFR overrides</strong> your plan. Result: NO-GO inside the TFR while it is active.</p>","open":false}]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0007-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Tools That Confirm Your Plan</h3><p>The chart tells you the airspace; these tools confirm the rest. The <strong>UAS Facility Map (UASFM)</strong> shows the maximum LAANC altitude for each grid around a controlled airport. <strong>LAANC</strong> (via a USS app) grants near-real-time authorization up to that altitude. <strong>FAADroneZone</strong> handles non-LAANC airports, further coordination, and waivers. The <strong>B4UFLY</strong> app gives an at-a-glance view of where you can fly, current restrictions, and active TFRs. Use the chart to understand <em>why</em>, and the apps to confirm <em>that</em> you are authorized before you launch.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0007-0000-0000-000000000004', 'faa70310-0000-0000-0000-000000000007', 'callout', '{"type":"success","text":"Bottom line: Class G + no TFR + within 400 ft AGL + VLOS = fly. Controlled airspace = get LAANC/DroneZone authorization first. Active prohibitive TFR or prohibited area = do not fly. Always re-check TFRs immediately before launch."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70320-0007-0000-0000-000000000005', 'faa70310-0000-0000-0000-000000000007', 'key_takeaways', '{"title":"Key Takeaways","items":["Five-step go/no-go: locate -> identify airspace -> authorization? -> TFR/SUA/NOTAM -> obstructions/MEF.","Class G below 400 ft AGL needs no authorization; controlled airspace needs LAANC or DroneZone first.","An active prohibitive TFR or a prohibited area overrides everything else — do not fly.","The UASFM altitude caps what LAANC can auto-approve; a ''0'' grid means no automatic approval.","Use B4UFLY and a current TFR/NOTAM check immediately before launch to confirm the plan."]}'::jsonb, 5);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000001', 'National Airspace System (NAS)', 'The network of airspace, airports, navigation aids, ATC facilities, rules, and procedures that lets aircraft share U.S. airspace safely.', 'It''s the whole ''system,'' not a single class.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000002', 'Controlled airspace', 'Airspace Classes A, B, C, D, and E in which ATC provides separation services; for Part 107 it requires an airspace authorization (LAANC/DroneZone) to enter.', 'A through E.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000003', 'Uncontrolled airspace (Class G)', 'Airspace where ATC does not provide separation services; no authorization needed for Part 107 ops at or below 400 ft AGL.', 'The default legal home for drones.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000004', 'AGL vs. MSL', 'AGL = feet Above Ground Level (height over the terrain). MSL = feet above Mean Sea Level (elevation referenced to the ocean). The 400 ft drone limit is AGL.', 'One follows the dirt, one is fixed to the sea.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000005', 'Class A airspace', 'Controlled airspace from 18,000 ft MSL up to and including FL600; all IFR; far above the drone ceiling.', '18,000 to 60,000.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000006', 'Class B airspace', 'Controlled airspace around the busiest airports, surface to ~10,000 ft MSL, ''upside-down wedding cake,'' drawn with SOLID BLUE lines; 107 authorization required.', 'Busiest = solid blue.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000007', 'Class C airspace', 'Controlled airspace around busy towered airports, surface to ~4,000 ft AGL, drawn with SOLID MAGENTA lines; 107 authorization required.', 'Solid magenta.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000008', 'Class D airspace', 'Controlled airspace around smaller towered airports, surface to ~2,500 ft AGL, drawn with a BLUE DASHED ring; boxed number = ceiling in hundreds of ft MSL; authorization required.', 'Blue dashed cylinder.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000009', 'Class E airspace', 'Controlled airspace with a floor that varies: surface (dashed magenta), 700 ft AGL (faded magenta vignette), or 1,200 ft AGL (faded blue vignette). Only surface-area E requires 107 authorization.', 'The ''everywhere else'' controlled airspace with shifting floors.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000010', 'Class G airspace', 'Uncontrolled airspace from the surface up to the base of the overlying Class E (often 700 or 1,200 ft AGL); no ATC authorization needed for Part 107.', 'Where most legal drone flying happens.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000011', 'LAANC', 'Low Altitude Authorization and Notification Capability — provides near-real-time authorization to fly in controlled airspace up to the altitude on the UAS Facility Map grid.', 'Near-real-time approval via a USS app.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000012', 'FAADroneZone', 'FAA portal for airspace authorizations where LAANC is unavailable, plus further-coordination requests and waivers; not near-real-time.', 'The slower, manual route.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000013', '14 CFR 107.41', 'Rule prohibiting operation in Class B, C, D, or the lateral surface area of Class E airspace without prior authorization from ATC.', 'The ''get permission for controlled airspace'' rule.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000014', 'Blue airport symbol', 'On a Sectional, indicates an airport WITH an operating control tower (towered).', 'Towered = blue.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000015', 'Magenta airport symbol', 'On a Sectional, indicates an airport WITHOUT an operating control tower (non-towered).', 'Non-towered = magenta.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000016', 'Magenta dashed line', 'Sectional symbol for Class E airspace that begins at the surface; reaches drone altitude and requires 107 authorization.', 'Dashed = D or E-surface; magenta points to E.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000017', 'Faded magenta vignette', 'Sectional shading marking Class E with a floor at 700 ft AGL; fades outward, with the 700-AGL floor on the inside.', 'Soft magenta = 700 AGL floor.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000018', 'Stacked airspace numbers (e.g., 41/12)', 'Ceiling over floor in hundreds of feet MSL; 41/12 = ceiling 4,100 MSL, floor 1,200 MSL. SFC = surface.', 'Top number is the ceiling.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000019', 'Airport data block', 'Text near an airport symbol giving its name, field elevation (MSL), CTAF/UNICOM frequency, longest runway length, and lighting.', 'The little caption next to the airport.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000020', 'CTAF (Common Traffic Advisory Frequency)', 'The frequency pilots use to self-announce at non-towered airports; shown on the chart with a bold magenta ''C'' in a circle.', 'Self-announce frequency, marked with a C.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000021', 'Latitude vs. longitude', 'Latitude = parallels measuring degrees N/S of the equator; longitude = meridians measuring degrees E/W of the Prime Meridian. 60 minutes per degree.', '''Lat'' is flat (runs east-west).', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000022', 'Maximum Elevation Figure (MEF)', 'Large bold number in each chart quadrangle giving the highest terrain/obstacle in that block in thousands+hundreds of feet MSL (e.g., 12 over 5 = 12,500 MSL).', 'Highest thing in the grid square.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000023', 'Prohibited Area (P-)', 'Special Use Airspace where flight is prohibited entirely (e.g., over the White House); regulatory, created under 14 CFR Part 73.', 'P = no entry, period.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000024', 'Restricted Area (R-)', 'SUA containing hazardous activity (artillery, missiles); flight restricted, entry only with controlling-agency permission when inactive (''cold'').', 'Hazards present; ask before entering.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000025', 'Military Operations Area (MOA)', 'Non-regulatory SUA that separates military training from IFR traffic; use caution when active.', 'Military training zone.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000026', 'Temporary Flight Restriction (TFR)', 'A time-limited flight restriction issued via FDC NOTAM (VIP movement, disasters, stadiums); often bans UAS; not pre-printed on charts, so check before every flight.', 'Temporary, dynamic, often drone-banning.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000027', 'Obstruction height (e.g., 1549 (1149))', 'Chart obstruction labels: bold number = top above MSL; parenthetical number = height above ground (AGL). Lighted/tall obstructions get special symbols.', 'Top is MSL; the parentheses are AGL.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000028', 'Can-I-fly workflow', '1) Locate the point, 2) identify the airspace class, 3) decide if authorization is needed, 4) check TFRs/SUA/NOTAMs, 5) check obstructions/MEF, then make a go/no-go decision.', 'Five steps ending in go/no-go.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000029', 'B4UFLY', 'An FAA-approved app that shows where you can fly, current airspace restrictions, and active TFRs for trip planning.', 'Before-you-fly situational-awareness app.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70340-0000-0000-0000-000000000030', 'UAS Facility Map (UASFM)', 'Grid around a controlled airport showing the maximum altitude LAANC can auto-approve; a ''0'' grid means no automatic authorization (further coordination required).', 'The grid of LAANC altitude caps.', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000001', 'Which group of airspace classes is considered ''controlled'' airspace?', 'multiple_choice', '["Classes A, B, C, D, and E","Class G only","Classes E, F, and G"]'::jsonb, 'Classes A, B, C, D, and E', 'Controlled airspace consists of Classes A, B, C, D, and E, where ATC provides separation services. Class G is uncontrolled. There is no Class F in the United States.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000002', 'For a Part 107 remote pilot, what is the practical meaning of operating in ''controlled'' airspace?', 'multiple_choice', '["You must obtain an airspace authorization (LAANC or DroneZone) before flying","Drone flight is completely banned there","You may fly with no restrictions because ATC handles everything"]'::jsonb, 'You must obtain an airspace authorization (LAANC or DroneZone) before flying', 'Controlled airspace is not closed to drones, but Part 107 requires prior ATC authorization (via LAANC or FAADroneZone) to operate in Class B, C, D, or surface-area E. It is not unrestricted.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000003', 'The 400-foot maximum altitude for Part 107 operations is measured in which reference?', 'multiple_choice', '["Above ground level (AGL)","Above mean sea level (MSL)","Above the nearest airport''s field elevation"]'::jsonb, 'Above ground level (AGL)', 'The 400-foot drone ceiling is AGL (height over the terrain). Airspace ceilings on the chart are usually MSL, which is why knowing the difference matters.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000004', 'Class A airspace extends from what lower limit up to FL600?', 'multiple_choice', '["18,000 ft MSL","10,000 ft MSL","1,200 ft AGL"]'::jsonb, '18,000 ft MSL', 'Class A runs from 18,000 ft MSL up to and including FL600 (60,000 ft). It is far above the 400 ft AGL drone limit and is never an operating concern for Part 107.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000005', 'On a Sectional Chart, which airspace is depicted by solid blue concentric rings forming an ''upside-down wedding cake''?', 'multiple_choice', '["Class B","Class C","Class D"]'::jsonb, 'Class B', 'Class B surrounds the busiest airports and is drawn with solid blue lines in the characteristic upside-down wedding-cake shape. Class C is solid magenta; Class D is blue dashed.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000006', 'A solid magenta ring around a busy towered airport on a Sectional indicates which class of airspace?', 'multiple_choice', '["Class C","Class B","Class D"]'::jsonb, 'Class C', 'Solid magenta lines depict Class C airspace (surface to ~4,000 ft AGL). Class B is solid blue; Class D is a blue dashed ring.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000007', 'A blue dashed-line ring around an airport indicates which class of airspace?', 'multiple_choice', '["Class D","Class C","Class E to the surface"]'::jsonb, 'Class D', 'A blue dashed ring depicts Class D airspace around a towered airport. Class C is solid magenta; Class E to the surface is depicted with a magenta dashed line.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000008', 'Inside a Class D blue dashed ring you see a boxed number [25]. What does it represent?', 'multiple_choice', '["The Class D ceiling of 2,500 ft MSL","A radio frequency of 25 MHz","The maximum drone altitude of 250 ft"]'::jsonb, 'The Class D ceiling of 2,500 ft MSL', 'A bracketed number in a Class D ring is the ceiling in hundreds of feet MSL; [25] = 2,500 ft MSL. It is not a frequency or a drone altitude limit.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000009', 'Which statement about Class B, C, and D airspace is correct for a Part 107 operation?', 'multiple_choice', '["All three require an airspace authorization before flight","Only Class B requires authorization","None require authorization because drones stay below 400 ft AGL"]'::jsonb, 'All three require an airspace authorization before flight', 'Class B, C, and D are all controlled airspace surrounding towered airports; Part 107 requires prior ATC authorization for each, regardless of how low the drone flies.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000010', 'On a Sectional, Class E airspace beginning at 700 ft AGL is depicted by which symbol?', 'multiple_choice', '["A faded (fuzzy) magenta vignette that fades outward","A solid blue ring","A magenta dashed ring"]'::jsonb, 'A faded (fuzzy) magenta vignette that fades outward', 'The faded magenta vignette marks Class E with a 700 ft AGL floor; inside the fade the floor is 700 AGL. A faded blue vignette marks a 1,200 ft AGL floor, and a magenta dashed ring is Class E to the surface.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000011', 'A magenta dashed line around an airport on a Sectional indicates which airspace?', 'multiple_choice', '["Class E that begins at the surface","Class D","Class G uncontrolled airspace"]'::jsonb, 'Class E that begins at the surface', 'A magenta dashed ring depicts Class E to the surface, which is controlled airspace reaching the ground and therefore requires Part 107 authorization. Class D is blue dashed.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000012', 'Why does a Part 107 operation in Class G airspace not require ATC authorization while one in Class D does?', 'multiple_choice', '["Class G is uncontrolled airspace with no ATC services, whereas Class D is controlled airspace around a towered airport","Class G is only available at night","Class G airspace does not exist below 400 ft AGL"]'::jsonb, 'Class G is uncontrolled airspace with no ATC services, whereas Class D is controlled airspace around a towered airport', 'Class G is uncontrolled — ATC provides no separation there, so no authorization is needed. Class D is controlled airspace around a towered airport, so 14 CFR 107.41 requires prior ATC authorization.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000013', 'Class G airspace generally extends from the surface up to what point?', 'multiple_choice', '["The base of the overlying Class E (often 700 or 1,200 ft AGL)","18,000 ft MSL","Exactly 400 ft AGL everywhere"]'::jsonb, 'The base of the overlying Class E (often 700 or 1,200 ft AGL)', 'Class G runs from the surface up to the floor of the overlying Class E, commonly 700 ft AGL (magenta vignette) or 1,200 ft AGL (blue vignette). 400 ft AGL is the drone limit, not the top of Class G.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000014', 'Which tool provides near-real-time authorization to operate in controlled airspace up to the altitude posted on the UAS Facility Map?', 'multiple_choice', '["LAANC","FAADroneZone further coordination","A Part 107 waiver under 107.205"]'::jsonb, 'LAANC', 'LAANC (Low Altitude Authorization and Notification Capability) delivers near-real-time authorization up to the UASFM grid altitude. DroneZone further coordination is manual and slow; a waiver lets you deviate from operating rules, not enter airspace.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000015', 'A UAS Facility Map grid square for your location shows ''0''. What does this mean for LAANC?', 'multiple_choice', '["Automatic LAANC is unavailable there; a further-coordination request to the FAA is required","You may fly up to 400 ft AGL without any authorization","The airport is closed to all aircraft"]'::jsonb, 'Automatic LAANC is unavailable there; a further-coordination request to the FAA is required', 'A ''0'' grid means LAANC cannot auto-approve any altitude there; you must submit a further-coordination request through FAADroneZone, which the FAA reviews manually.', 'hard', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000016', 'Which regulation prohibits operating in Class B, C, D, or surface-area E airspace without prior ATC authorization?', 'multiple_choice', '["14 CFR 107.41","14 CFR 107.9","14 CFR 107.51"]'::jsonb, '14 CFR 107.41', '14 CFR 107.41 is the airspace-authorization rule. 107.9 covers accident reporting and 107.51 covers operating limitations like the 400 ft and 87 kt caps.', 'hard', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000017', 'On a Sectional Chart, what does a blue airport symbol indicate?', 'multiple_choice', '["An airport with an operating control tower","An airport without a control tower","A heliport"]'::jsonb, 'An airport with an operating control tower', 'Blue airport symbols denote towered airports; magenta symbols denote non-towered airports.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000018', 'A magenta airport symbol on a Sectional Chart indicates what?', 'multiple_choice', '["An airport without an operating control tower","An airport with an operating control tower","A prohibited area"]'::jsonb, 'An airport without an operating control tower', 'Magenta airport symbols mark non-towered airports. Blue symbols mark towered airports.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000019', 'A Class C shelf on a Sectional is labeled ''41/12''. What altitudes does this represent?', 'multiple_choice', '["Ceiling 4,100 ft MSL over a floor of 1,200 ft MSL","Ceiling 41,000 ft over a floor of 1,200 ft","A frequency pair of 41 and 12"]'::jsonb, 'Ceiling 4,100 ft MSL over a floor of 1,200 ft MSL', 'Stacked/slashed airspace numbers are ceiling-over-floor in hundreds of feet MSL: 41/12 = 4,100 ft MSL ceiling and 1,200 ft MSL floor.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000020', 'If you are standing inside the faded edge of a magenta vignette (with no other ring present), what is the floor of the Class E airspace above you?', 'multiple_choice', '["700 ft AGL","1,200 ft AGL","The surface"]'::jsonb, '700 ft AGL', 'Inside the faded magenta vignette the Class E floor is 700 ft AGL. Outside it (plain background or blue vignette) the floor steps up to 1,200 ft AGL. A surface floor would be a magenta dashed ring.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000021', 'Where on a Sectional Chart do you read latitude and longitude coordinates?', 'multiple_choice', '["From tick marks along the neatlines and lat/long grid lines","From the airport data block","From the Maximum Elevation Figure"]'::jsonb, 'From tick marks along the neatlines and lat/long grid lines', 'Latitude (parallels) and longitude (meridians) are read from the tick marks along the chart''s neatlines and grid lines, with 60 minutes per degree. The data block gives airport info, not coordinates.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000022', 'A chart quadrangle shows a large bold MEF of ''12'' with a smaller ''5''. What does this tell you?', 'multiple_choice', '["The highest terrain or obstacle in that quadrangle is 12,500 ft MSL","The airspace floor is 1,250 ft AGL","The CTAF frequency is 125.0 MHz"]'::jsonb, 'The highest terrain or obstacle in that quadrangle is 12,500 ft MSL', 'The Maximum Elevation Figure is read as thousands+hundreds of feet MSL; 12 over 5 = 12,500 ft MSL, the highest known terrain/obstacle in that grid block. It is not a floor or a frequency.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000023', 'On a Sectional, the CTAF (Common Traffic Advisory Frequency) is marked with which symbol?', 'multiple_choice', '["A bold magenta ''C'' inside a circle next to the frequency","A blue star above the airport symbol","An inverted-V symbol"]'::jsonb, 'A bold magenta ''C'' inside a circle next to the frequency', 'CTAF is shown with a bold magenta ''C'' in a circle. A blue star indicates a rotating beacon; an inverted V is an obstruction symbol.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000024', 'In which type of Special Use Airspace is flight prohibited entirely?', 'multiple_choice', '["A Prohibited Area (P-)","A Military Operations Area (MOA)","An Alert Area (A-)"]'::jsonb, 'A Prohibited Area (P-)', 'Prohibited Areas (P-) forbid flight entirely. MOAs and Alert Areas are non-regulatory and call for caution but do not prohibit flight outright.', 'easy', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000025', 'A Restricted Area (R-) on a chart means what for an aircraft?', 'multiple_choice', '["Hazardous activity may be present; entry only with the controlling agency''s permission when inactive","Flight is always permitted with no coordination","It is reserved exclusively for drones"]'::jsonb, 'Hazardous activity may be present; entry only with the controlling agency''s permission when inactive', 'Restricted Areas contain hazards like artillery or missile firing; you may enter only with the controlling agency''s permission, typically when the area is ''cold.''', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000026', 'How is a Temporary Flight Restriction (TFR) issued, and how should a remote pilot treat it?', 'multiple_choice', '["It is issued via an FDC NOTAM and must be checked before every flight because it is temporary and often bans UAS","It is permanently printed on the Sectional Chart","It only applies to manned aircraft, never drones"]'::jsonb, 'It is issued via an FDC NOTAM and must be checked before every flight because it is temporary and often bans UAS', 'TFRs are issued as FDC NOTAMs, are dynamic, frequently prohibit UAS, and are not pre-printed on charts — so you must check current sources before every flight. They absolutely apply to drones.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000027', 'An obstruction on a Sectional is labeled ''2049 (1149)''. What do these two numbers mean?', 'multiple_choice', '["Top is 2,049 ft MSL; the structure is 1,149 ft above ground (AGL)","Top is 2,049 ft AGL; 1,149 is the frequency","2,049 is the latitude; 1,149 is the longitude"]'::jsonb, 'Top is 2,049 ft MSL; the structure is 1,149 ft above ground (AGL)', 'Obstruction labels show the bold top elevation in MSL and, in parentheses, the height above ground (AGL). So 2,049 ft MSL and 1,149 ft AGL.', 'hard', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000028', 'Using the can-I-fly workflow, after locating your point and identifying the airspace as Class G, what is the next key consideration before launching?', 'multiple_choice', '["Check for active TFRs, Special Use Airspace, NOTAMs, and obstructions","Immediately file for a LAANC authorization","Climb above 400 ft AGL to clear obstacles"]'::jsonb, 'Check for active TFRs, Special Use Airspace, NOTAMs, and obstructions', 'Even in Class G (no authorization needed), you must still check TFRs, SUA, NOTAMs, and obstructions, and stay at/below 400 ft AGL within VLOS. You would not file LAANC for Class G or exceed 400 ft AGL.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000029', 'Your planned site is in Class G, but a major sporting event with an active stadium TFR covers the area today. What is the correct decision?', 'multiple_choice', '["Do not fly inside the TFR while it is active, even though the underlying airspace is uncontrolled","Fly anyway because Class G never requires authorization","Fly as long as you stay below 200 ft AGL"]'::jsonb, 'Do not fly inside the TFR while it is active, even though the underlying airspace is uncontrolled', 'An active TFR overrides the underlying airspace; many stadium/VIP TFRs ban all UAS. Being in Class G does not exempt you from a TFR, and there is no low-altitude carve-out.', 'medium', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70330-0000-0000-0000-000000000030', 'What is the difference between an airspace authorization and a Part 107 waiver?', 'multiple_choice', '["An authorization lets you enter controlled airspace; a waiver lets you deviate from an operating rule like VLOS or operations over people","They are the same thing with different names","A waiver is required to fly in Class G airspace"]'::jsonb, 'An authorization lets you enter controlled airspace; a waiver lets you deviate from an operating rule like VLOS or operations over people', 'An airspace authorization (LAANC/DroneZone) grants entry to controlled airspace; a waiver (107.205) permits deviation from specific operating rules. Class G needs neither.', 'hard', 'faa70000-0000-0000-0000-000000000003', 'faa70310-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70410-0000-0000-0000-000000000001', 'faa70000-0000-0000-0000-000000000004', 'The Atmosphere, the Standard Atmosphere & Moisture', '', ARRAY['The atmosphere is ~78% nitrogen and ~21% oxygen, plus variable water vapor that drives weather; pressure decreases with altitude.','Essentially all weather and all sUAS flight happen in the troposphere (surface to ~36,000 ft), where temperature normally falls with height.','ICAO standard atmosphere: 15 degrees C and 29.92 inHg at sea level, lapse ~2 degrees C per 1,000 ft - the reference for performance and density altitude.','Dewpoint is the temperature at which air saturates; relative humidity is how close the air is to saturation.','A SMALL temperature-dewpoint spread signals near-saturated air and likely fog or low cloud.']::text[], 1, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Describe the gas composition of the atmosphere and the role of the troposphere in weather.','State the values of the ICAO standard atmosphere and the standard temperature and pressure lapse rates.','Explain temperature, dewpoint, relative humidity, and the meaning of the temperature-dewpoint spread.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000000', 'faa70410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why weather is a Part 107 subject</h3><p>Weather is roughly <strong>11 to 16 percent</strong> of the Unmanned Aircraft General (UAG) knowledge exam, and it is the single biggest physical threat to a small drone. A multirotor weighs a few pounds and has very little inertia, so it is far more sensitive to wind, gusts, density altitude, and precipitation than a manned aircraft. You do not need to be a meteorologist, but you must understand <em>why</em> the air behaves as it does, recognize hazardous conditions before launch, and be able to <strong>read a METAR and a TAF</strong>. This module builds that understanding from the ground up.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000001', 'faa70410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What the atmosphere is made of</h3><p>The atmosphere is a thin shell of gas held to Earth by gravity. By volume the dry atmosphere is about <strong>78 percent nitrogen</strong> and <strong>21 percent oxygen</strong>, with the remaining ~1 percent argon, carbon dioxide, and trace gases. Critically, the atmosphere also carries a variable amount of <strong>water vapor</strong> (up to a few percent), and it is that water vapor that drives clouds, precipitation, fog, and most of what we call \"weather.\" Air has <em>mass</em>; the weight of all the air above a point creates <strong>atmospheric pressure</strong>, which decreases with altitude.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000002', 'faa70410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Layers of the atmosphere</h3><p>The atmosphere is layered by how temperature changes with height. The lowest layer, the <strong>troposphere</strong>, extends from the surface to roughly 36,000 ft and is where essentially all weather and all sUAS flight occur. In the troposphere temperature normally <em>decreases</em> with altitude. Above it the <strong>stratosphere</strong> (containing the ozone layer) is more stable. A small drone never leaves the bottom slice of the troposphere, but the same physics that governs the whole layer governs the first 400 feet you fly in.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000003', 'faa70410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The ICAO standard atmosphere</h3><p>To compare aircraft performance and calibrate instruments, aviation uses a fixed reference called the <strong>ICAO standard atmosphere</strong>. At sea level it defines:</p><ul><li>Temperature = <strong>15 degrees C (59 degrees F)</strong></li><li>Pressure = <strong>29.92 inches of mercury (1013.2 hPa)</strong></li><li>Standard temperature lapse rate = about <strong>2 degrees C per 1,000 ft</strong> of altitude gain</li><li>Standard pressure lapse rate = about <strong>1 inHg per 1,000 ft</strong> in the lower atmosphere</li></ul><p>Real conditions rarely match the standard exactly, and the <em>difference</em> between actual and standard conditions is exactly what produces density altitude (next lesson) and is why performance varies day to day.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: The ICAO standard atmosphere - sea-level temperature 15 degrees C, pressure 29.92 inHg, and a lapse rate of about 2 degrees C per 1,000 ft."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000005', 'faa70410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Temperature, dewpoint, and relative humidity</h3><p><strong>Temperature</strong> measures the heat energy of the air. The <strong>dewpoint</strong> is the temperature to which air must be cooled (at constant pressure) for it to become <em>saturated</em> - the point at which water vapor begins to condense into visible moisture. <strong>Relative humidity</strong> is the ratio of the water vapor present to the maximum the air could hold at that temperature, expressed as a percentage; at 100 percent relative humidity the temperature and dewpoint are equal and condensation occurs. Warm air can hold more water vapor than cold air, which is why cooling air toward its dewpoint is the universal trigger for clouds, fog, and dew.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000006', 'faa70410-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"The temperature-dewpoint SPREAD is your fog and low-cloud alarm. A small spread (temperature and dewpoint close together, e.g., 12/11) means the air is nearly saturated - expect fog, mist, or low ceilings. A large spread (e.g., 27/04) means dry air and clear skies. On a METAR, watch that pair of numbers closely."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0001-0000-0000-000000000007', 'faa70410-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The atmosphere is ~78% nitrogen and ~21% oxygen, plus variable water vapor that drives weather; pressure decreases with altitude.","Essentially all weather and all sUAS flight happen in the troposphere (surface to ~36,000 ft), where temperature normally falls with height.","ICAO standard atmosphere: 15 degrees C and 29.92 inHg at sea level, lapse ~2 degrees C per 1,000 ft - the reference for performance and density altitude.","Dewpoint is the temperature at which air saturates; relative humidity is how close the air is to saturation.","A SMALL temperature-dewpoint spread signals near-saturated air and likely fog or low cloud."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70410-0000-0000-0000-000000000002', 'faa70000-0000-0000-0000-000000000004', 'Density Altitude & Its Effect on sUAS Performance', '', ARRAY['Density altitude = pressure altitude corrected for non-standard temperature (and humidity); it is the altitude the aircraft ''feels.''','''High, hot, and humid'' all RAISE density altitude and HURT performance.','Thin air means each propeller stroke moves less mass, so lift, thrust, climb, payload, and endurance all decrease.','Warmer-than-standard air gives a HIGHER density altitude than your true altitude; colder-than-standard gives a lower one and better performance.','On a high-density-altitude day, reduce payload and plan for slower climb and shorter flight time.']::text[], 2, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Define pressure altitude and density altitude and explain how density altitude is computed conceptually.','List the three factors that raise density altitude (''high, hot, humid'').','Explain in physical terms why high density altitude reduces lift, thrust, and endurance for a small drone.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0002-0000-0000-000000000000', 'faa70410-0000-0000-0000-000000000002', 'text', '{"html":"<h3>From pressure altitude to density altitude</h3><p><strong>Pressure altitude</strong> is the altitude you read when the altimeter is set to the standard datum of <strong>29.92 inHg</strong>. <strong>Density altitude</strong> is <em>pressure altitude corrected for non-standard temperature</em> (and, to a lesser degree, humidity). In plain language, density altitude is the altitude the aircraft <em>thinks</em> it is flying at based on how thin the air actually is. When the air is less dense than standard, the drone performs as though it were at a higher elevation - even if it never leaves the ground a few feet.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0002-0000-0000-000000000001', 'faa70410-0000-0000-0000-000000000002', 'text', '{"html":"<h3>What thins the air: high, hot, and humid</h3><p>Air density falls when any of three things happen, summarized by the memory aid <strong>\"high, hot, and humid\"</strong>:</p><ul><li><strong>High elevation / low pressure</strong> - fewer air molecules above you, so the air is thinner. A hot day in Denver is a classic high-density-altitude environment.</li><li><strong>High temperature</strong> - warm air expands, so the molecules are spread farther apart and density drops. This is usually the biggest day-to-day driver.</li><li><strong>High humidity</strong> - water vapor (molecular weight ~18) is <em>lighter</em> than the nitrogen and oxygen it displaces, so moist air is slightly <em>less</em> dense than dry air. The effect is smaller than temperature or elevation but it adds up.</li></ul><p>All three <strong>raise</strong> density altitude, and a high density altitude <strong>degrades</strong> performance.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0002-0000-0000-000000000002', 'faa70410-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"High, hot, and humid = high density altitude = LESS LIFT. On a hot, high, humid afternoon a propeller bites into thinner air, motors strain, and the same drone climbs more slowly, carries less payload, and drains its battery faster. Reduce your payload and plan for reduced endurance and sluggish climb."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0002-0000-0000-000000000003', 'faa70410-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Why thin air hurts a small drone</h3><p>A multirotor flies by accelerating air downward with its propellers; thrust and lift both depend directly on <strong>air density</strong>. When the air is thinner, each spin of the prop moves <em>less mass</em> of air, so:</p><ul><li><strong>Lift decreases</strong> - the rotors must spin faster (and draw more current) just to hover.</li><li><strong>Thrust and climb suffer</strong> - the reserve power available for climbing or fighting wind shrinks.</li><li><strong>Endurance drops</strong> - working the motors harder drains the battery faster, shortening flight time.</li><li><strong>Payload capacity falls</strong> - the margin to lift a camera or sensor is reduced.</li></ul><p>The net effect: on a high-density-altitude day, expect a sluggish, power-hungry, short-lived flight, and reduce weight accordingly.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0002-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A density-altitude chart - enter with outside air temperature and pressure altitude to read density altitude, illustrating how heat and elevation raise it."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0002-0000-0000-000000000005', 'faa70410-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Standard conditions as the baseline</h3><p>Density altitude equals true altitude only under standard conditions (15 degrees C, 29.92 inHg at sea level, ~2 degrees C per 1,000 ft). When the actual temperature is <em>warmer</em> than standard for your elevation, density altitude is <strong>higher</strong> than your true altitude; when it is colder than standard, density altitude is <em>lower</em> and performance actually improves. This is why a drone often feels strong and climbs eagerly on a cold winter morning and feels weak on a hot summer afternoon at the same field.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0002-0000-0000-000000000006', 'faa70410-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Density altitude = pressure altitude corrected for non-standard temperature (and humidity); it is the altitude the aircraft ''feels.''","''High, hot, and humid'' all RAISE density altitude and HURT performance.","Thin air means each propeller stroke moves less mass, so lift, thrust, climb, payload, and endurance all decrease.","Warmer-than-standard air gives a HIGHER density altitude than your true altitude; colder-than-standard gives a lower one and better performance.","On a high-density-altitude day, reduce payload and plan for slower climb and shorter flight time."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70410-0000-0000-0000-000000000003', 'faa70000-0000-0000-0000-000000000004', 'Stability, Air Masses & Fronts', '', ARRAY['Stability depends on the lapse rate: steep lapse = unstable (cumuliform clouds, showers, good visibility, turbulence); shallow lapse/inversion = stable (stratiform clouds, steady precip, poor visibility, smooth air).','A temperature inversion is very stable and traps haze/fog, reducing visibility.','An air mass is a large uniform body of air; a front is the boundary where two air masses meet.','Cold fronts bring narrow, violent, fast weather and clearing behind; warm fronts bring wide, layered, slow weather with low ceilings ahead.','Stationary fronts stall (prolonged weather); occluded fronts form when a cold front overtakes a warm front. Every frontal passage brings a wind shift.']::text[], 3, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Distinguish stable from unstable air by lapse rate, cloud type, precipitation, visibility, and turbulence.','Define an air mass and the four types of fronts.','Predict the weather and wind shift associated with cold, warm, stationary, and occluded fronts.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000000', 'faa70410-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Atmospheric stability and lapse rates</h3><p><strong>Stability</strong> describes whether a parcel of air that is nudged upward keeps rising or sinks back. It is governed by the <strong>lapse rate</strong> - how fast the surrounding temperature falls with height. When the actual (environmental) lapse rate is <em>steep</em> (temperature drops quickly with altitude), a lifted parcel stays warmer than its surroundings and keeps rising: the air is <strong>unstable</strong>. When the lapse rate is <em>shallow</em> - or reverses in a <strong>temperature inversion</strong> (warmer air on top of cooler air) - a lifted parcel cools below its surroundings and sinks back: the air is <strong>stable</strong>.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000001', 'faa70410-0000-0000-0000-000000000003', 'table', '{"headers":["Characteristic","Stable air","Unstable air"],"rows":[["Lapse rate","Shallow / inversion present","Steep"],["Cloud type","Stratiform (flat, layered)","Cumuliform (puffy, towering)"],["Precipitation","Steady, continuous (or drizzle)","Showery, intermittent (and thunderstorms)"],["Visibility","Often poor (haze, fog, smoke trapped)","Generally good (except in showers)"],["Turbulence / ride","Smooth","Bumpy, gusty, choppy"],["Surface wind","Steady","Gusty"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000002', 'faa70410-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"A temperature inversion (warm air aloft over cool air below) is very stable and TRAPS haze, smoke, and pollutants near the surface - reducing visibility. Inversions also favor fog formation. Smooth air with poor visibility is a stable-air signature."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000003', 'faa70410-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Air masses</h3><p>An <strong>air mass</strong> is a large body of air that is relatively uniform in temperature and moisture because it sat over a source region (e.g., cold dry Canadian land, warm moist Gulf water) long enough to take on its character. As an air mass moves, it modifies and, where it meets a different air mass, a <strong>front</strong> forms along the boundary. Fronts are where wind shifts, clouds build, precipitation falls, and turbulence concentrates - so they are the main features a pilot tracks.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'text', '{"html":"<h3>The four front types</h3><p>A <strong>front</strong> is the boundary between two air masses. There are four kinds:</p><ul><li><strong>Cold front</strong> - cold air advances and undercuts warmer air, shoving it up steeply. Produces a narrow band of often-violent weather: towering cumulus and thunderstorms, heavy showers, gusty shifting winds, then rapid clearing with cooler, drier, more unstable air behind. Cold fronts move fast.</li><li><strong>Warm front</strong> - warm air advances and rides up over retreating cold air on a shallow slope. Produces a wide region of layered stratiform clouds, low ceilings, steady precipitation, and poor visibility well ahead of the front; moves slowly.</li><li><strong>Stationary front</strong> - neither air mass advances; the boundary stalls, often bringing prolonged clouds and precipitation over the same area for days.</li><li><strong>Occluded front</strong> - a fast cold front overtakes a warm front, lifting the warm air completely off the surface. Combines characteristics of both, with widespread clouds and precipitation.</li></ul>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000005', 'faa70410-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: The four fronts - cold (blue triangles), warm (red half-circles), stationary (alternating), and occluded (purple) - with cross-sections showing cloud build-up and the steep vs. shallow frontal slopes."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000006', 'faa70410-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"For a small drone, the most dangerous moment is the passage of a fast-moving COLD front: a sudden wind shift, strong gusts, and embedded thunderstorms can arrive abruptly. If a cold front is forecast, do not be in the air when it passes. A wind shift and pressure/temperature change are the hallmark of any frontal passage."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0003-0000-0000-000000000007', 'faa70410-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Stability depends on the lapse rate: steep lapse = unstable (cumuliform clouds, showers, good visibility, turbulence); shallow lapse/inversion = stable (stratiform clouds, steady precip, poor visibility, smooth air).","A temperature inversion is very stable and traps haze/fog, reducing visibility.","An air mass is a large uniform body of air; a front is the boundary where two air masses meet.","Cold fronts bring narrow, violent, fast weather and clearing behind; warm fronts bring wide, layered, slow weather with low ceilings ahead.","Stationary fronts stall (prolonged weather); occluded fronts form when a cold front overtakes a warm front. Every frontal passage brings a wind shift."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70410-0000-0000-0000-000000000004', 'faa70000-0000-0000-0000-000000000004', 'Clouds, Ceilings, Visibility & the Cloud-Clearance Rules', '', ARRAY['Clouds form when air cools to its dewpoint; stratus = layered/stable, cumulus = puffy/unstable, nimbo/nimbus = precipitating, cumulonimbus = the thunderstorm cloud to avoid.','Sky cover: FEW (1-2 oktas), SCT (3-4), BKN (5-7), OVC (8); heights are AGL in hundreds of feet.','A ceiling is the lowest BKN or OVC layer (or vertical visibility into an obscuration); FEW and SCT are never ceilings.','Part 107 requires minimum 3 statute miles flight visibility from the control station.','Part 107 cloud clearance is at least 500 ft below and 2,000 ft horizontally from clouds; low ceilings or low visibility can ground the flight.']::text[], 4, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Identify the basic cloud families and their height classes.','Define sky-cover terms FEW, SCT, BKN, OVC and the meaning of a ceiling.','Connect clouds, ceilings, and visibility to the Part 107 minimums of 3 SM visibility and 500 ft below / 2,000 ft horizontal cloud clearance.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0004-0000-0000-000000000000', 'faa70410-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Cloud families</h3><p>Clouds are condensed water droplets or ice crystals that form when air is cooled to its dewpoint. They come in two basic shapes - layered <strong>stratus</strong> (stable air) and puffy <strong>cumulus</strong> (unstable air) - and are classified by height into <strong>low</strong>, <strong>middle</strong> (prefix \"alto\"), and <strong>high</strong> (prefix \"cirro\") families. The prefix or suffix <strong>nimbo/nimbus</strong> means the cloud is producing precipitation. The towering <strong>cumulonimbus</strong> is the thunderstorm cloud and is the single cloud type a drone pilot must avoid entirely.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0004-0000-0000-000000000001', 'faa70410-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Sky cover and the ceiling</h3><p>METARs report how much of the sky is covered in <strong>oktas</strong> (eighths), using four codes plus a height in <strong>hundreds of feet above ground level (AGL)</strong>:</p><ul><li><strong>FEW</strong> = 1 to 2 oktas (few clouds)</li><li><strong>SCT</strong> = 3 to 4 oktas (scattered)</li><li><strong>BKN</strong> = 5 to 7 oktas (broken)</li><li><strong>OVC</strong> = 8 oktas (overcast)</li><li><strong>SKC / CLR</strong> = sky clear</li></ul><p>A <strong>ceiling</strong> is defined as the height of the <em>lowest</em> layer reported as <strong>broken (BKN) or overcast (OVC)</strong> - or the vertical visibility into an obscuration. FEW and SCT layers are <em>not</em> ceilings. So in a report of \"SCT020 BKN040 OVC080,\" the ceiling is <strong>4,000 ft AGL</strong> (the lowest BKN/OVC layer).</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0004-0000-0000-000000000002', 'faa70410-0000-0000-0000-000000000004', 'table', '{"headers":["Code","Meaning","Sky cover (oktas)","Is it a ceiling?"],"rows":[["SKC / CLR","Clear","0","No"],["FEW","Few","1-2","No"],["SCT","Scattered","3-4","No"],["BKN","Broken","5-7","Yes (lowest BKN/OVC)"],["OVC","Overcast","8","Yes (lowest BKN/OVC)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0004-0000-0000-000000000003', 'faa70410-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"Cloud heights in a METAR are AGL and in HUNDREDS of feet. BKN012 means a broken ceiling at 1,200 ft AGL. FEW250 means a few clouds at 25,000 ft (cirrus). The lowest BKN or OVC layer is the ceiling - FEW and SCT never count."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0004-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The regulatory link: 3 SM and 500/2,000</h3><p>Cloud and visibility data are not academic - they decide whether you may legally fly. Under <strong>14 CFR 107.51</strong>, a Remote PIC must maintain:</p><ul><li><strong>Minimum flight visibility of 3 statute miles</strong>, measured from the control-station location.</li><li><strong>Cloud clearance of at least 500 ft below the clouds and at least 2,000 ft horizontally from the clouds.</strong></li></ul><p>So a low ceiling or reduced visibility can ground you even on a calm day. If a METAR shows visibility below 3 SM, or a ceiling so low that 400-ft AGL flight cannot stay 500 ft below the clouds, the operation is not legal. These minimums exist so the Remote PIC and any nearby manned traffic can see and avoid each other.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0004-0000-0000-000000000005', 'faa70410-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Memorize: 3 SM visibility, 500 ft BELOW clouds, 2,000 ft HORIZONTAL from clouds. A common exam trap reverses these (e.g., ''1,000 below / 500 horizontal'' or ''1 SM''). The numbers are 3 / 500 / 2,000 for Part 107."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0004-0000-0000-000000000006', 'faa70410-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Clouds form when air cools to its dewpoint; stratus = layered/stable, cumulus = puffy/unstable, nimbo/nimbus = precipitating, cumulonimbus = the thunderstorm cloud to avoid.","Sky cover: FEW (1-2 oktas), SCT (3-4), BKN (5-7), OVC (8); heights are AGL in hundreds of feet.","A ceiling is the lowest BKN or OVC layer (or vertical visibility into an obscuration); FEW and SCT are never ceilings.","Part 107 requires minimum 3 statute miles flight visibility from the control station.","Part 107 cloud clearance is at least 500 ft below and 2,000 ft horizontally from clouds; low ceilings or low visibility can ground the flight."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70410-0000-0000-0000-000000000005', 'faa70000-0000-0000-0000-000000000004', 'Wind, Thunderstorms, Microbursts & Fog', '', ARRAY['Wind and gusts are the everyday sUAS hazard; compare reported/forecast wind AND gusts to your aircraft''s limit, and remember wind increases with altitude.','Buildings, ridges, and trees create invisible mechanical turbulence on the lee side - anticipate it from wind direction and obstacle layout.','Thunderstorms develop in three stages - cumulus (updrafts), mature (most violent, updrafts + downdrafts), dissipating (downdrafts); avoid them entirely.','A microburst is an intense localized downdraft producing extreme, rapidly reversing wind shear - one of the most dangerous conditions for a small UA, sometimes with no visual warning.','Fog (radiation, advection, upslope, steam) forms when the temperature-dewpoint spread closes and destroys the visibility needed to fly.']::text[], 5, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Explain how wind, gusts, and terrain/building effects threaten a small drone.','Describe the three stages of a thunderstorm and the hazards each presents.','Define a microburst and wind shear and explain why they are a serious sUAS hazard, and identify the common fog types.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000000', 'faa70410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Wind and gusts</h3><p>Wind is air moving from high pressure toward low pressure, deflected by the Earth''s rotation. For a small drone, wind is the everyday hazard: a multirotor must constantly tilt and burn battery to hold position against it, and a <strong>gust</strong> (a sudden, brief increase in wind speed) can overpower a lightweight aircraft, push it off course, or exceed the maximum wind speed the airframe can handle (often only 20 to 25 mph for consumer drones - check the manufacturer''s spec). Always compare the forecast and reported wind <em>and gusts</em> to your aircraft''s limit before launch, and remember that wind speed increases with altitude.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000001', 'faa70410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Local effects near terrain and buildings</h3><p>Near the surface, wind is shaped by obstacles. Air flowing over and around buildings, trees, hills, and ridgelines creates <strong>mechanical turbulence</strong> - swirling eddies, rotors, and rapid local wind shifts on the downwind (lee) side. Flying close to a building corner, over a rooftop edge, or in the lee of a ridge can produce sudden, invisible turbulence that destabilizes a drone. Channeling between buildings can also accelerate the wind locally. Plan launch, landing, and inspection paths to keep clear of these turbulent zones, especially on windy days.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000002', 'faa70410-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"Mechanical turbulence on the lee (downwind) side of buildings, ridges, and trees is strongest when winds are strong and the air is unstable. The turbulent eddies are invisible - anticipate them from the wind direction and the obstacle layout rather than waiting to feel them."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000003', 'faa70410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Thunderstorms - three stages</h3><p>A thunderstorm requires three ingredients: <strong>moisture</strong>, an <strong>unstable lapse rate</strong>, and a <strong>lifting force</strong> (a front, terrain, or heating). It develops through three stages:</p><ul><li><strong>Cumulus (building) stage</strong> - dominated by <em>updrafts</em> as the cloud towers upward; no precipitation reaching the ground yet.</li><li><strong>Mature stage</strong> - the most violent stage; updrafts <em>and</em> downdrafts coexist, heavy rain/hail falls, lightning, and the strongest turbulence and wind shear occur. Mature is the stage to fear.</li><li><strong>Dissipating stage</strong> - dominated by <em>downdrafts</em>; the storm rains itself out and weakens.</li></ul><p>A drone has no business anywhere near a thunderstorm. Hazards - violent turbulence, lightning, hail, heavy rain, and microbursts - extend well beyond the visible cloud.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Microbursts and wind shear - a serious sUAS hazard</h3><p><strong>Wind shear</strong> is a sudden change in wind speed and/or direction over a short distance, horizontally or vertically. A <strong>microburst</strong> is an intense, localized <em>downdraft</em> from a thunderstorm (or even a rain shower) that slams down and spreads out in all directions at the surface, producing extreme, rapidly reversing wind shear over a small area (typically less than 2.5 miles across) and lasting only minutes. For a manned aircraft a microburst is deadly; for a lightweight drone, the sudden downdraft and shifting horizontal winds can instantly flip it, drive it into the ground, or carry it away. Microbursts can occur with little visual warning - sometimes under a harmless-looking shower or virga. Treat any nearby convective activity as a microburst threat and stay grounded.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000005', 'faa70410-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"Microburst + wind shear = one of the most dangerous conditions for a small UA. The downdraft and explosive outflow can exceed any drone''s control authority in seconds. Do not fly near thunderstorms, rain showers, or virga - the hazard can strike under clouds that look benign."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000006', 'faa70410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Fog types</h3><p>Fog is simply a cloud at the surface; it forms when the temperature-dewpoint spread closes to near zero. Know the common types:</p><ul><li><strong>Radiation fog</strong> - forms on clear, calm nights as the ground radiates heat and cools the air to its dewpoint; common in valleys at dawn, burns off after sunrise.</li><li><strong>Advection fog</strong> - forms when warm, moist air moves horizontally over a cooler surface (e.g., coastal); needs some wind and can persist.</li><li><strong>Upslope fog</strong> - forms when moist air is forced up rising terrain and cools.</li><li><strong>Steam fog</strong> - forms when cold air moves over warmer water, the water ''steaming'' into the cold air.</li></ul><p>All fog destroys visibility and will ground a Part 107 flight below the 3 SM minimum.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0005-0000-0000-000000000007', 'faa70410-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["Wind and gusts are the everyday sUAS hazard; compare reported/forecast wind AND gusts to your aircraft''s limit, and remember wind increases with altitude.","Buildings, ridges, and trees create invisible mechanical turbulence on the lee side - anticipate it from wind direction and obstacle layout.","Thunderstorms develop in three stages - cumulus (updrafts), mature (most violent, updrafts + downdrafts), dissipating (downdrafts); avoid them entirely.","A microburst is an intense localized downdraft producing extreme, rapidly reversing wind shear - one of the most dangerous conditions for a small UA, sometimes with no visual warning.","Fog (radiation, advection, upslope, steam) forms when the temperature-dewpoint spread closes and destroys the visibility needed to fly."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70410-0000-0000-0000-000000000006', 'faa70000-0000-0000-0000-000000000004', 'Reading a METAR & TAF; Weather Sources', '', ARRAY['A METAR is the routine hourly observation (SPECI = special); read it left to right: type, station, Zulu time, modifier, wind, visibility, weather, sky, temp/dewpoint, altimeter, remarks.','Wind direction is degrees TRUE; ''G'' marks gusts; sky heights are AGL in hundreds of feet; temp/dewpoint are Celsius with M for minus; A-group is inHg.','All aviation weather is in Zulu (UTC); convert to local by subtracting the time-zone offset.','A TAF forecasts ~5 SM around an airport for 24-30 hours, using FM (rapid), BECMG (gradual), TEMPO (brief <1 hr), and PROB30/40 (probability) change groups; P6SM = visibility greater than 6 SM.','Use official sources - 1-800-WX-BRIEF / Leidos (1800wxbrief.com) and aviationweather.gov (Aviation Weather Center) - for METARs, TAFs, and briefings.']::text[], 6, 28, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Decode every element of a METAR: type, station, time, modifier, wind, visibility, weather, sky condition, temperature/dewpoint, altimeter, and remarks.','Read a TAF, including the valid period and the FM, BECMG, TEMPO, and PROB change groups.','Name the correct FAA weather sources and the products available from each.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000000', 'faa70410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>METAR: the current observation</h3><p>A <strong>METAR</strong> is a routine, hourly surface weather <em>observation</em> for an airport. (A <strong>SPECI</strong> is the same format issued off-schedule when conditions change significantly.) All aviation weather uses <strong>Zulu / Coordinated Universal Time (UTC)</strong>, and the report is read left to right in a fixed order. Consider this sample, which we will decode element by element:</p><p style=\"font-family:monospace\"><strong>METAR KSAT 121753Z AUTO 27015G25KT 10SM FEW050 SCT250 27/12 A2992 RMK AO2</strong></p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000001', 'faa70410-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: An annotated sample METAR and TAF, with arrows labeling each element (station, time, wind, visibility, weather, sky condition, temperature/dewpoint, altimeter, remarks; and the TAF valid period and FM/TEMPO/BECMG groups)."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000002', 'faa70410-0000-0000-0000-000000000006', 'table', '{"headers":["Element","Code in sample","Decoded meaning"],"rows":[["Report type","METAR","Routine hourly observation (SPECI = special, off-hour)"],["Station","KSAT","ICAO identifier - San Antonio Intl (4-letter, K = contiguous US)"],["Date/time","121753Z","12th day of the month, 1753 Zulu (UTC) - always Zulu"],["Modifier","AUTO","Automated station with no human augmentation (COR = corrected)"],["Wind","27015G25KT","From 270 degrees TRUE at 15 knots, gusting to 25 knots"],["Visibility","10SM","10 statute miles of surface visibility"],["Weather","(none present)","No significant present weather (e.g., RA rain, BR mist, FG fog, TS thunderstorm; - light, + heavy)"],["Sky condition","FEW050 SCT250","Few clouds at 5,000 ft AGL; scattered at 25,000 ft AGL (no ceiling here)"],["Temp/Dewpoint","27/12","Temperature 27 degrees C, dewpoint 12 degrees C (M would prefix a minus value)"],["Altimeter","A2992","Altimeter setting 29.92 inHg"],["Remarks","RMK AO2","Remarks: AO2 = automated station WITH a precipitation sensor (AO1 = without)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000003', 'faa70410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Reading the key groups carefully</h3><p>A few groups trip people up:</p><ul><li><strong>Wind</strong> - the first three digits are direction in degrees <em>true</em> (not magnetic), the next two/three are speed in knots, and a ''G'' marks the gust. <strong>VRB</strong> means variable direction; <strong>00000KT</strong> means calm.</li><li><strong>Sky condition height</strong> - in hundreds of feet AGL. The <strong>ceiling</strong> is the lowest BKN or OVC layer; FEW and SCT are not ceilings.</li><li><strong>Temperature/dewpoint</strong> - in degrees Celsius, separated by a slash; an <strong>M</strong> prefix means minus (e.g., M03 = -3 degrees C). A small spread warns of fog/low cloud.</li><li><strong>Altimeter</strong> - the ''A'' group is inches of mercury with an implied decimal (A2992 = 29.92 inHg).</li></ul>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"Zulu to local: METAR/TAF times are always UTC (Zulu). To convert, subtract the time-zone offset (e.g., US Central Daylight Time is UTC-5, so 1753Z = 12:53 PM CDT). Aviation never uses local time in the report itself."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000005', 'faa70410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>TAF: the forecast</h3><p>A <strong>TAF (Terminal Aerodrome Forecast)</strong> is a forecast for the area within about <strong>5 statute miles</strong> of an airport, normally valid <strong>24 to 30 hours</strong> and issued four times a day. It uses METAR-style coding plus a <strong>valid-period</strong> group and <strong>change groups</strong>. Consider:</p><p style=\"font-family:monospace\"><strong>TAF KSAT 121130Z 1212/1318 27012KT P6SM SCT040 FM121800 30015G25KT P6SM SCT050 TEMPO 1220/1224 5SM TSRA BKN030CB BECMG 1306/1308 32008KT</strong></p><p>Here the valid period <strong>1212/1318</strong> means from the 12th at 1200Z through the 13th at 1800Z. <strong>P6SM</strong> means visibility greater than 6 statute miles.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000006', 'faa70410-0000-0000-0000-000000000006', 'table', '{"headers":["TAF change group","Meaning","Use"],"rows":[["FM (FROM)","A rapid, near-instant change at the stated time","FM121800 = new conditions begin 1800Z on the 12th"],["BECMG","A gradual change over the stated time window","BECMG 1306/1308 = change occurs between 0600-0800Z on the 13th"],["TEMPO","Temporary fluctuations expected to last under 1 hour each, within the window","TEMPO 1220/1224 = brief thunderstorm/rain spells"],["PROB30 / PROB40","A 30% or 40% probability of the stated conditions","Used for uncertain hazards like thunderstorms"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000007', 'faa70410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Where to get official weather</h3><p>Pull weather from FAA-recognized sources, not a generic phone app:</p><ul><li><strong>1-800-WX-BRIEF (Leidos Flight Service)</strong> - phone or online (1800wxbrief.com) standard, abbreviated, and outlook briefings from a flight service provider; also files and tracks information.</li><li><strong>aviationweather.gov (Aviation Weather Center)</strong> - the National Weather Service site (formerly ADDS) for METARs, TAFs, graphical forecasts, AIRMETs/SIGMETs, and PIREPs.</li><li><strong>EFB apps and B4UFLY</strong> - integrate weather with airspace; useful for planning, but verify with the official sources above.</li></ul><p>A standard briefing covers adverse conditions, synopsis, current and forecast weather, winds aloft, NOTAMs, and TFRs - everything the preflight required by 14 CFR 107.49 expects you to assess.</p>"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000008', 'faa70410-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: The official FAA weather sources - aviationweather.gov (Aviation Weather Center) and 1800wxbrief.com (Leidos Flight Service) - showing where a Remote PIC pulls METARs and TAFs."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70420-0006-0000-0000-000000000009', 'faa70410-0000-0000-0000-000000000006', 'key_takeaways', '{"title":"Key Takeaways","items":["A METAR is the routine hourly observation (SPECI = special); read it left to right: type, station, Zulu time, modifier, wind, visibility, weather, sky, temp/dewpoint, altimeter, remarks.","Wind direction is degrees TRUE; ''G'' marks gusts; sky heights are AGL in hundreds of feet; temp/dewpoint are Celsius with M for minus; A-group is inHg.","All aviation weather is in Zulu (UTC); convert to local by subtracting the time-zone offset.","A TAF forecasts ~5 SM around an airport for 24-30 hours, using FM (rapid), BECMG (gradual), TEMPO (brief <1 hr), and PROB30/40 (probability) change groups; P6SM = visibility greater than 6 SM.","Use official sources - 1-800-WX-BRIEF / Leidos (1800wxbrief.com) and aviationweather.gov (Aviation Weather Center) - for METARs, TAFs, and briefings."]}'::jsonb, 9);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000001', 'Troposphere', 'The lowest atmospheric layer (surface to ~36,000 ft) where virtually all weather and all sUAS operations occur and where temperature normally decreases with altitude.', '''Tropo'' = where the weather lives.', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000002', 'ICAO standard atmosphere', 'A fixed reference atmosphere: 15 degrees C and 29.92 inHg at sea level, with a temperature lapse of about 2 degrees C per 1,000 ft. Used to compare performance and calibrate altimeters.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000003', 'Dewpoint', 'The temperature to which air must be cooled, at constant pressure, to become saturated (relative humidity 100%) so that water vapor begins to condense into cloud, fog, or dew.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000004', 'Relative humidity', 'The amount of water vapor in the air expressed as a percentage of the maximum the air could hold at that temperature; 100% means temperature equals dewpoint.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000005', 'Temperature-dewpoint spread', 'The difference between the temperature and the dewpoint. A small spread indicates near-saturated air and likely fog or low ceilings; a large spread indicates dry air.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000006', 'Density altitude', 'Pressure altitude corrected for non-standard temperature (and humidity); the altitude at which the aircraft performs given the actual air density. High density altitude means thin air and degraded performance.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000007', 'Pressure altitude', 'The altitude indicated when the altimeter setting is the standard datum 29.92 inHg; the starting point from which density altitude is computed.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000008', 'High, hot, and humid', 'The memory aid for the three factors that raise density altitude - high elevation/low pressure, high temperature, and high humidity - all of which thin the air and reduce sUAS lift, thrust, and endurance.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000009', 'Effect of density altitude on sUAS', 'As density altitude rises, propellers move less air mass, so the drone produces less lift and thrust, climbs slower, carries less payload, and has shorter flight time.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000010', 'Stable air', 'Air resistant to vertical motion (shallow lapse rate or inversion). Produces stratiform clouds, steady precipitation, poor visibility (trapped haze/fog), and smooth air.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000011', 'Unstable air', 'Air that, once lifted, keeps rising (steep lapse rate). Produces cumuliform clouds, showery precipitation, good visibility, and turbulence/gusty winds.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000012', 'Temperature inversion', 'A layer where temperature increases with altitude (warm over cold). Very stable; traps haze, smoke, and moisture near the surface, reducing visibility and favoring fog.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000013', 'Air mass', 'A large body of air with relatively uniform temperature and moisture acquired from its source region; where two air masses meet, a front forms.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000014', 'Cold front', 'A boundary where cold air advances under warmer air, lifting it steeply; brings narrow, often violent weather (thunderstorms, gusts, wind shift) and clearing, cooler, drier air behind.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000015', 'Warm front', 'A boundary where warm air rides up over retreating cold air on a shallow slope; brings widespread stratiform clouds, low ceilings, steady precipitation, and poor visibility ahead of it.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000016', 'Ceiling', 'The height above ground of the lowest cloud layer reported as broken (BKN) or overcast (OVC), or the vertical visibility into an obscuration. FEW and SCT layers do not count as a ceiling.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000017', 'FEW / SCT / BKN / OVC', 'METAR sky-cover codes in oktas (eighths): FEW = 1-2, SCT (scattered) = 3-4, BKN (broken) = 5-7, OVC (overcast) = 8. Heights follow in hundreds of feet AGL.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000018', 'Part 107 visibility minimum', 'A Remote PIC must maintain at least 3 statute miles of flight visibility, measured from the control-station location (14 CFR 107.51).', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000019', 'Part 107 cloud clearance', 'At least 500 feet below the clouds and at least 2,000 feet horizontally from the clouds (14 CFR 107.51).', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000020', 'Cumulonimbus', 'The towering thunderstorm cloud, producing severe turbulence, lightning, hail, and microbursts. A drone pilot must avoid it entirely.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000021', 'Gust', 'A sudden, brief increase in wind speed. Gusts can overpower a lightweight drone, push it off course, or exceed the airframe''s maximum wind rating; reported in METARs with a ''G'' (e.g., 15G25KT).', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000022', 'Mechanical turbulence', 'Swirling, invisible eddies created when wind flows over and around buildings, trees, hills, and ridgelines; strongest on the downwind (lee) side in strong, unstable winds.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000023', 'Thunderstorm stages', 'Cumulus (building) stage = updrafts dominate; Mature stage = updrafts and downdrafts coexist, most violent (heavy rain/hail, lightning, strongest shear); Dissipating stage = downdrafts dominate and the storm weakens.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000024', 'Microburst', 'An intense, localized downdraft from a storm or shower that hits the surface and spreads outward, creating extreme, rapidly reversing wind shear over a small area for a few minutes - a severe hazard to sUAS, often with little visual warning.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000025', 'Wind shear', 'A sudden change in wind speed and/or direction over a short distance (horizontal or vertical). It can instantly destabilize a small drone and is most extreme in and near microbursts.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000026', 'Radiation fog', 'Fog that forms on clear, calm nights when the ground radiates heat and cools the surface air to its dewpoint; common in valleys near dawn and usually burns off after sunrise.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000027', 'METAR', 'A routine, hourly aviation surface weather OBSERVATION for an airport, in Zulu time. (SPECI is the same format issued off-schedule for significant changes.)', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000028', 'TAF', 'Terminal Aerodrome Forecast - a forecast for ~5 statute miles around an airport, valid 24-30 hours, issued ~4x/day, using FM, BECMG, TEMPO, and PROB change groups.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000029', 'METAR wind group (e.g., 27015G25KT)', 'Wind from 270 degrees TRUE at 15 knots, gusting to 25 knots. VRB = variable direction; 00000KT = calm; the G marks a gust.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000030', 'Zulu time (UTC)', 'Coordinated Universal Time, used for all aviation weather (the ''Z'' in 121753Z). Convert to local by subtracting your time-zone offset.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000031', 'FM / BECMG / TEMPO / PROB', 'TAF change groups: FM = rapid change from a stated time; BECMG = gradual change over a window; TEMPO = temporary fluctuations lasting under 1 hour; PROB30/40 = 30% or 40% probability of conditions.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70440-0000-0000-0000-000000000032', 'Official aviation weather sources', '1-800-WX-BRIEF / Leidos Flight Service (1800wxbrief.com) for briefings, and aviationweather.gov (Aviation Weather Center, formerly ADDS) for METARs, TAFs, AIRMETs/SIGMETs, and PIREPs.', NULL, 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000001', 'What are the sea-level temperature and pressure values of the ICAO standard atmosphere?', 'multiple_choice', '["15 degrees C and 29.92 inHg","59 degrees C and 30.00 inHg","0 degrees C and 29.92 inHg"]'::jsonb, '15 degrees C and 29.92 inHg', 'The standard atmosphere is defined as 15 degrees C (59 degrees F) and 29.92 inHg at sea level. ''59 degrees C'' confuses the Fahrenheit value with Celsius, and 0 degrees C is not the standard temperature.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000002', 'A METAR reports a temperature of 12 degrees C and a dewpoint of 11 degrees C. What does this small temperature-dewpoint spread most likely indicate?', 'multiple_choice', '["Near-saturated air with a high likelihood of fog or low clouds","Very dry air and excellent visibility","An approaching cold front with thunderstorms"]'::jsonb, 'Near-saturated air with a high likelihood of fog or low clouds', 'A small spread means the air is close to saturation, so fog, mist, or low ceilings are likely. A large spread, not a small one, indicates dry air. A small spread by itself does not specifically indicate a cold front.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000003', 'In which layer of the atmosphere do essentially all weather and all small UAS operations occur?', 'multiple_choice', '["The troposphere","The stratosphere","The ozone layer"]'::jsonb, 'The troposphere', 'The troposphere (surface to about 36,000 ft) is where nearly all weather and all sUAS flight take place. The stratosphere lies above it and contains the ozone layer, which is not where drones fly.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000004', 'What does the dewpoint temperature represent?', 'multiple_choice', '["The temperature to which air must be cooled to become saturated and begin condensing","The current air temperature minus the wind chill","The highest temperature the air reached during the day"]'::jsonb, 'The temperature to which air must be cooled to become saturated and begin condensing', 'Dewpoint is the temperature at which air reaches 100% relative humidity and water vapor begins to condense into cloud, fog, or dew. The other choices describe unrelated concepts.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000005', 'Density altitude is best defined as:', 'multiple_choice', '["Pressure altitude corrected for non-standard temperature","The height of the aircraft above ground level","The altitude shown when the altimeter is set to the local altimeter setting"]'::jsonb, 'Pressure altitude corrected for non-standard temperature', 'Density altitude is pressure altitude corrected for non-standard temperature (and humidity) - the altitude the aircraft ''feels.'' Height above ground is AGL altitude, and the local-altimeter-setting reading is indicated altitude.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000006', 'Which combination of conditions produces the HIGHEST density altitude and the worst small-UAS performance?', 'multiple_choice', '["High elevation, high temperature, and high humidity","Low elevation, low temperature, and low humidity","Sea level, standard temperature, and dry air"]'::jsonb, 'High elevation, high temperature, and high humidity', '''High, hot, and humid'' all thin the air and raise density altitude, reducing lift and thrust. Cold, low, dry conditions give a low density altitude and the best performance.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000007', 'On a hot summer afternoon at a high-elevation field, how will a multirotor drone''s performance most likely be affected compared with a cold morning at sea level?', 'multiple_choice', '["Reduced lift and thrust, slower climb, and shorter flight time","Increased lift and longer flight time because warm air is more energetic","No change, because density altitude does not affect electric drones"]'::jsonb, 'Reduced lift and thrust, slower climb, and shorter flight time', 'High density altitude thins the air, so the propellers move less mass per revolution: lift, thrust, climb rate, payload, and endurance all decrease. Electric multirotors still depend on air density for lift, so they are affected.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000008', 'Physically, why does high density altitude reduce a drone''s lift and thrust?', 'multiple_choice', '["The thinner air means each propeller stroke accelerates less mass of air downward","The motors overheat and automatically reduce power","Higher humidity makes the propellers heavier"]'::jsonb, 'The thinner air means each propeller stroke accelerates less mass of air downward', 'Lift and thrust depend on air density; in thin air each prop revolution moves less air mass, so less force is generated. Motor overheating and ''heavier props'' are not the mechanism behind density-altitude performance loss.', 'hard', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000009', 'Which set of characteristics is typical of UNSTABLE air?', 'multiple_choice', '["Cumuliform clouds, showery precipitation, good visibility, and turbulence","Stratiform clouds, steady precipitation, poor visibility, and smooth air","An inversion, fog, and trapped haze"]'::jsonb, 'Cumuliform clouds, showery precipitation, good visibility, and turbulence', 'Unstable air (steep lapse rate) builds cumuliform clouds, produces showers, usually has good visibility, and is turbulent. The other choices describe stable air, where lifted parcels sink back and conditions are smooth with poor visibility.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000010', 'What effect does a temperature inversion typically have on visibility near the surface?', 'multiple_choice', '["It reduces visibility by trapping haze, smoke, and moisture beneath the warm layer","It improves visibility by lifting pollutants away from the surface","It has no effect on visibility"]'::jsonb, 'It reduces visibility by trapping haze, smoke, and moisture beneath the warm layer', 'An inversion (warm air over cool air) is very stable and acts like a lid, trapping haze, smoke, and moisture near the surface and often producing fog. It degrades, not improves, visibility.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000011', 'A fast-moving cold front is approaching your operating site. What weather should you expect as it passes?', 'multiple_choice', '["A sudden wind shift, gusty winds, and a narrow band of showers or thunderstorms","A long period of light, steady drizzle and gradually lowering ceilings","Clear, calm, stable conditions ideal for flight"]'::jsonb, 'A sudden wind shift, gusty winds, and a narrow band of showers or thunderstorms', 'Cold fronts lift warm air steeply, producing a narrow band of often-violent weather with a sharp wind shift and gusts, then clearing behind. Long steady drizzle with lowering ceilings is the warm-front pattern.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000012', 'A warm front is moving into the area. Which conditions are most characteristic of it?', 'multiple_choice', '["Widespread layered clouds, low ceilings, steady precipitation, and poor visibility ahead of it","A short, violent band of thunderstorms followed by rapid clearing","Strong gusty downbursts and rapidly reversing winds"]'::jsonb, 'Widespread layered clouds, low ceilings, steady precipitation, and poor visibility ahead of it', 'Warm air rides up a shallow slope over retreating cold air, producing broad stratiform clouds, low ceilings, steady precipitation, and reduced visibility well ahead of the front. The violent, narrow pattern describes a cold front; gusty downbursts describe a microburst.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000013', 'How is an occluded front formed?', 'multiple_choice', '["A fast cold front overtakes a slower warm front, lifting the warm air off the surface","Two warm air masses merge over an ocean","A front stalls with neither air mass advancing"]'::jsonb, 'A fast cold front overtakes a slower warm front, lifting the warm air off the surface', 'An occlusion occurs when a faster cold front catches up to a warm front and forces the warm air aloft, combining traits of both. A stalled, non-advancing boundary is a stationary front.', 'hard', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000014', 'In a METAR, the sky condition is reported as ''SCT020 BKN040 OVC080.'' What is the ceiling?', 'multiple_choice', '["4,000 ft AGL","2,000 ft AGL","8,000 ft AGL"]'::jsonb, '4,000 ft AGL', 'A ceiling is the lowest broken (BKN) or overcast (OVC) layer. SCT020 (scattered) does not count, so the ceiling is the BKN040 layer at 4,000 ft AGL.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000015', 'Which METAR sky-cover abbreviation indicates a coverage of 5 to 7 oktas (and can therefore constitute a ceiling)?', 'multiple_choice', '["BKN (broken)","SCT (scattered)","FEW (few)"]'::jsonb, 'BKN (broken)', 'BKN (broken) is 5-7 oktas and, as the lowest BKN/OVC layer, forms a ceiling. SCT is 3-4 oktas and FEW is 1-2 oktas; neither is a ceiling.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000016', 'Under 14 CFR 107.51, what is the minimum flight visibility for small UAS operations, measured from the control-station location?', 'multiple_choice', '["3 statute miles","1 statute mile","5 statute miles"]'::jsonb, '3 statute miles', 'Part 107 requires at least 3 statute miles of flight visibility from the control station. One statute mile is too low and five is not the regulatory minimum.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000017', 'What are the minimum cloud-clearance distances required for a Part 107 operation?', 'multiple_choice', '["500 ft below the clouds and 2,000 ft horizontally from the clouds","1,000 ft below and 500 ft horizontally from the clouds","500 ft above and 1,000 ft below the clouds"]'::jsonb, '500 ft below the clouds and 2,000 ft horizontally from the clouds', 'Part 107 requires staying at least 500 ft below and 2,000 ft horizontally from clouds. The other options scramble the standard values; the correct figures are 500/2,000.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000018', 'A METAR reports a broken ceiling at 400 ft AGL (BKN004) and 2 SM visibility. Can you legally conduct a routine Part 107 flight up to 400 ft AGL?', 'multiple_choice', '["No - visibility is below 3 SM and the low ceiling prevents the required 500 ft cloud clearance","Yes - 400 ft AGL is exactly the legal altitude, so the flight is permitted","Yes - cloud clearance rules do not apply below 500 ft AGL"]'::jsonb, 'No - visibility is below 3 SM and the low ceiling prevents the required 500 ft cloud clearance', 'Visibility of 2 SM is below the 3 SM minimum, and a 400-ft ceiling makes it impossible to stay 500 ft below the clouds while still flying. Cloud-clearance and visibility minimums apply throughout the operation, not just above 500 ft.', 'hard', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000019', 'Why is a microburst considered one of the most serious hazards for a small unmanned aircraft?', 'multiple_choice', '["It is an intense localized downdraft producing extreme, rapidly reversing wind shear that can overpower the drone","It permanently demagnetizes the drone''s compass from a distance","It only forms in clear, calm air and is therefore unexpected on sunny days"]'::jsonb, 'It is an intense localized downdraft producing extreme, rapidly reversing wind shear that can overpower the drone', 'A microburst slams down and spreads out, creating extreme, rapidly changing winds that can exceed a small drone''s control authority in seconds. It is associated with convective activity (storms/showers/virga), not clear calm air, and it does not demagnetize compasses.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000020', 'During which stage of a thunderstorm are the strongest turbulence and wind shear typically present?', 'multiple_choice', '["The mature stage","The cumulus (building) stage","The dissipating stage"]'::jsonb, 'The mature stage', 'The mature stage has coexisting updrafts and downdrafts, heavy precipitation, lightning, and the most violent turbulence and shear. The cumulus stage is dominated by updrafts and the dissipating stage by downdrafts as the storm weakens.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000021', 'You plan to inspect a rooftop on a windy day. Where is mechanical turbulence most likely to be strongest?', 'multiple_choice', '["On the downwind (lee) side of the building","Directly upwind of the building in undisturbed flow","Far away from any structures over open ground"]'::jsonb, 'On the downwind (lee) side of the building', 'Wind flowing over and around a building creates swirling eddies on its downwind (lee) side, the strongest mechanical turbulence. Upwind flow is comparatively smooth, and open ground far from obstacles has the least mechanical turbulence.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000022', 'Radiation fog most commonly forms under which conditions?', 'multiple_choice', '["Clear, calm nights when the ground cools the surface air to its dewpoint","Strong winds carrying warm moist air over a cold sea","Air being forced up the side of a mountain"]'::jsonb, 'Clear, calm nights when the ground cools the surface air to its dewpoint', 'Radiation fog forms overnight under clear, calm skies as the ground radiates heat and cools the air to saturation; it typically burns off after sunrise. Warm moist air over a cold surface is advection fog, and air lifted up terrain produces upslope fog.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000023', 'Before launching a small drone with a manufacturer wind limit of about 22 mph, the report shows winds gusting to 30 mph. What is the appropriate decision?', 'multiple_choice', '["Do not fly - the gusts exceed the aircraft''s wind limit and can cause loss of control","Fly anyway, because gusts are brief and do not count toward the limit","Fly, but only above 200 ft AGL where wind is calmer"]'::jsonb, 'Do not fly - the gusts exceed the aircraft''s wind limit and can cause loss of control', 'Gusts can overpower a lightweight drone and must be compared to the aircraft''s limit; 30 mph gusts exceed a 22 mph limit. Wind generally increases, not decreases, with altitude, so flying higher would not help.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000024', 'In the METAR group ''27015G25KT,'' what is the wind doing?', 'multiple_choice', '["Blowing from 270 degrees true at 15 knots, gusting to 25 knots","Blowing toward 270 degrees at 15 knots with a steady 25-knot average","Variable in direction at 27 knots gusting 1,525 knots"]'::jsonb, 'Blowing from 270 degrees true at 15 knots, gusting to 25 knots', 'The first three digits are the direction the wind is coming FROM in degrees true (270), the next two are the sustained speed (15 kt), and the G group is the gust (25 kt). Wind direction always describes where the wind comes from.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000025', 'A METAR includes the group ''121753Z.'' What does it tell you?', 'multiple_choice', '["The observation was taken on the 12th day at 1753 Zulu (UTC)","The temperature is 12 degrees and the dewpoint is 17 degrees","The visibility is 12 miles at 1753 local time"]'::jsonb, 'The observation was taken on the 12th day at 1753 Zulu (UTC)', 'The date/time group is two digits for the day (12) and four digits for the time in Zulu/UTC (1753Z). It is never local time, and it is not temperature or visibility.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000026', 'In a METAR, the group ''A2992'' refers to what?', 'multiple_choice', '["An altimeter setting of 29.92 inches of mercury","An air temperature of 29.92 degrees C","An altitude restriction of 2,992 ft"]'::jsonb, 'An altimeter setting of 29.92 inches of mercury', 'The ''A'' group gives the altimeter setting in inches of mercury with an implied decimal, so A2992 = 29.92 inHg. It is not a temperature or an altitude.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000027', 'Decode the temperature/dewpoint group ''M03/M06'' in a METAR.', 'multiple_choice', '["Temperature -3 degrees C, dewpoint -6 degrees C","Temperature 3 degrees C, dewpoint 6 degrees C","Mist at 3 to 6 statute miles"]'::jsonb, 'Temperature -3 degrees C, dewpoint -6 degrees C', 'The M prefix means minus, so M03/M06 is -3 degrees C temperature over -6 degrees C dewpoint. Without the M it would read positive values; ''M'' here is not the weather code for mist (which is BR).', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000028', 'In a TAF, what does the ''TEMPO'' change group indicate?', 'multiple_choice', '["Temporary fluctuations in conditions expected to last less than an hour within the stated window","A permanent, rapid change to entirely new conditions from a stated time","A gradual change taking place over the stated time window"]'::jsonb, 'Temporary fluctuations in conditions expected to last less than an hour within the stated window', 'TEMPO marks brief, temporary fluctuations (each under an hour) within a window. ''FM'' is the rapid permanent change from a time, and ''BECMG'' is a gradual change over a window.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000029', 'Which is an appropriate, FAA-recognized source for obtaining a weather briefing and METARs/TAFs before a Part 107 flight?', 'multiple_choice', '["1-800-WX-BRIEF / 1800wxbrief.com (Leidos Flight Service) and aviationweather.gov","A generic consumer weather app''s daily forecast only","The drone manufacturer''s marketing website"]'::jsonb, '1-800-WX-BRIEF / 1800wxbrief.com (Leidos Flight Service) and aviationweather.gov', 'Leidos Flight Service (1-800-WX-BRIEF) and the Aviation Weather Center (aviationweather.gov) are the official aviation weather sources for briefings, METARs, and TAFs. Consumer apps and manufacturer sites are not authoritative aviation weather sources.', 'easy', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70430-0000-0000-0000-000000000030', 'In a TAF valid-period group such as ''1212/1318,'' what does it represent?', 'multiple_choice', '["Valid from the 12th at 1200Z through the 13th at 1800Z","A wind of 12 knots from 1,318 degrees","A visibility decreasing from 12 to 13 miles"]'::jsonb, 'Valid from the 12th at 1200Z through the 13th at 1800Z', 'The TAF valid-period group is day/hour-Zulu to day/hour-Zulu: 1212 = 12th at 1200Z, 1318 = 13th at 1800Z. It is not a wind or visibility group.', 'medium', 'faa70000-0000-0000-0000-000000000004', 'faa70410-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70510-0000-0000-0000-000000000001', 'faa70000-0000-0000-0000-000000000005', 'The Forces of Flight on a Small UAS', '', ARRAY['The four forces of flight are lift, weight, thrust, and drag.','Lift opposes weight; thrust opposes drag.','A multirotor hovers when lift equals weight and climbs when lift exceeds weight.','A multirotor moves by tilting, so cruising in wind makes the motors fight drag and weight together.','Anything that adds weight or drag increases the power the motors draw and shortens flight time.']::text[], 1, 22, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Name and define lift, weight, thrust, and drag for a multirotor.','Explain how a multirotor balances these forces in hover, climb, and forward flight.','Relate added weight or drag to the power (and battery) needed to keep flying.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0001-0000-0000-000000000000', 'faa70510-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why the four forces matter to a drone pilot</h3><p>Every aircraft in flight is acted on by <strong>four forces</strong>: <strong>lift</strong>, <strong>weight</strong>, <strong>thrust</strong>, and <strong>drag</strong>. A small unmanned aircraft (sUAS) is no exception. You will not be asked to do airplane aerodynamics math on the UAG exam, but you <em>are</em> expected to understand these forces conceptually so you can predict how loading, wind, and density altitude change what your drone can do.</p><p>On a typical <strong>multirotor</strong> (quadcopter, hexacopter), the spinning propellers act like many small rotating wings. They produce <strong>lift</strong> directly upward, and the flight controller continuously adjusts each motor''s speed to balance the four forces and keep the aircraft where you command it. On a <strong>fixed-wing</strong> sUAS, the wing produces lift as air flows over it, and a separate motor/propeller produces forward thrust - much like a small airplane.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0001-0000-0000-000000000001', 'faa70510-0000-0000-0000-000000000001', 'table', '{"headers":["Force","Direction","What produces it on an sUAS","Pilot takeaway"],"rows":[["Lift","Upward (opposes weight)","Spinning props (multirotor) or airflow over the wing (fixed-wing)","Must at least equal weight to hold altitude; must exceed weight to climb"],["Weight","Downward (toward Earth)","Gravity acting on airframe + battery + payload","Heavier = more lift/power needed = shorter flight"],["Thrust","Direction of travel","Propellers; on a multirotor it comes from tilting the aircraft","Needed to move and to overcome drag/wind"],["Drag","Opposite the direction of travel","Air resistance against the airframe, props, and payload","More drag (wind, bulky payload) = more thrust/power needed"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0001-0000-0000-000000000002', 'faa70510-0000-0000-0000-000000000001', 'text', '{"html":"<h3>How a multirotor uses the forces</h3><p>In a steady <strong>hover</strong>, lift exactly equals weight and the aircraft is motionless. To <strong>climb</strong>, the flight controller spins the props faster so <strong>lift exceeds weight</strong>. To move horizontally, a multirotor <strong>tilts</strong> in the direction of travel; part of the props'' thrust now pushes the aircraft sideways while the rest still supports its weight. That is why a heavily tilted, fast-moving drone in wind works its motors hard - it is fighting <strong>drag</strong> and supporting <strong>weight</strong> at the same time, which drains the battery faster.</p><p>Understanding this gives you a simple mental model: <em>anything that adds weight or drag forces the motors to work harder, drawing more current and cutting your flight time.</em> Payload, wind, and thin (low-density) air all do exactly that.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0001-0000-0000-000000000003', 'faa70510-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: The four forces of flight on a multirotor sUAS - lift up, weight down, thrust in the direction of travel, and drag opposing it. Show the aircraft tilted forward in cruise."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0001-0000-0000-000000000004', 'faa70510-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Memory hook: Lift and Thrust are the ''engine'' forces you generate; Weight and Drag are the ''penalty'' forces you must overcome. Every penalty you add (payload, wind, thin air) costs battery."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0001-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The four forces of flight are lift, weight, thrust, and drag.","Lift opposes weight; thrust opposes drag.","A multirotor hovers when lift equals weight and climbs when lift exceeds weight.","A multirotor moves by tilting, so cruising in wind makes the motors fight drag and weight together.","Anything that adds weight or drag increases the power the motors draw and shortens flight time."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70510-0000-0000-0000-000000000002', 'faa70000-0000-0000-0000-000000000005', 'Weight, Balance, and Center of Gravity', '', ARRAY['Total weight (airframe + battery + payload + attachments) must stay at or below the manufacturer''s maximum takeoff weight.','The center of gravity (CG) is the point about which the aircraft''s weight balances; it must stay within manufacturer limits.','A forward CG increases stability but reduces maneuverability and efficiency.','An aft CG reduces stability and can make the aircraft twitchy or uncontrollable.','Mount payloads on the centerline and secure them so the CG stays centered and cannot shift in flight.']::text[], 2, 26, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Define center of gravity (CG) for an sUAS.','Explain the effects of a forward vs. aft (and lateral) CG on stability and control.','Apply manufacturer maximum takeoff weight and CG limits when mounting payloads.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0002-0000-0000-000000000000', 'faa70510-0000-0000-0000-000000000002', 'text', '{"html":"<h3>What ''weight & balance'' means for a drone</h3><p>Two numbers govern how a drone is loaded: how <strong>much</strong> it weighs and <strong>where</strong> that weight sits. <strong>Total weight</strong> is the airframe plus battery plus payload plus any attachments, and it must stay <strong>at or below the manufacturer''s maximum takeoff weight</strong>. <strong>Balance</strong> is about <em>distribution</em> - whether the weight is centered so the aircraft hangs level.</p><p>The <strong>center of gravity (CG)</strong> is the single point at which the aircraft''s entire weight can be considered to act - the point about which it would balance if you could suspend it. A multirotor is designed to fly with its CG at (or very near) the geometric center, directly under and between the rotors. When you add a camera, sensor, or delivery payload, you move the CG. Keeping the CG within the manufacturer''s limits keeps the aircraft stable and controllable; pushing it out of limits makes the aircraft fight you.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0002-0000-0000-000000000001', 'faa70510-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: CG location on a multirotor. Show (a) a balanced drone with CG at the geometric center, and (b) the CG shifted forward/to one side by an off-center payload, with the aircraft tilting to compensate."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0002-0000-0000-000000000002', 'faa70510-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Effects of a forward, aft, or off-center CG</h3><p>On a multirotor, an off-center CG forces the flight controller to run some motors continuously harder than others just to hold a level hover. That has real consequences:</p><ul><li><strong>Forward CG</strong> (payload mounted too far forward): the nose wants to drop. The aircraft becomes more ''nose-heavy'' and stable in pitch but <strong>sluggish and less responsive</strong>; the rear motors work harder, draining the battery unevenly and shortening flight time.</li><li><strong>Aft CG</strong> (weight too far rearward): the aircraft becomes <strong>less stable and twitchy</strong>, harder to control smoothly, and more prone to oscillation or loss of control. An excessively aft CG is the more dangerous condition because it erodes stability.</li><li><strong>Lateral (side-to-side) imbalance</strong>: the drone drifts or leans toward the heavy side; motors on the heavy side run hotter and that battery sags faster.</li></ul><p>The general aviation rule of thumb carries over: a <strong>forward CG increases stability but reduces maneuverability and efficiency</strong>, while an <strong>aft CG reduces stability</strong> and can make the aircraft unmanageable.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0002-0000-0000-000000000003', 'faa70510-0000-0000-0000-000000000002', 'table', '{"headers":["CG condition","Effect on stability","Effect on control / efficiency"],"rows":[["Within limits (centered)","Designed, predictable stability","Responsive, even motor load, full rated flight time"],["Too far forward","More stable (nose-heavy)","Sluggish, less maneuverable, uneven battery drain"],["Too far aft","Less stable, twitchy, may oscillate","Hard to control; risk of loss of control"],["Laterally off-center","Drifts/leans to heavy side","Heavy-side motors overworked; uneven drain, overheating"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0002-0000-0000-000000000004', 'faa70510-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"An out-of-balance or overloaded sUAS is unstable, hard to control, less efficient, and more likely to suffer a loss of control. Always mount payloads so the CG stays centered and within the manufacturer''s published limits."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0002-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'accordion', '{"sections":[{"title":"How to keep the CG where it belongs","open":false,"content":"<ul><li><strong>Mount on the centerline.</strong> Place cameras, gimbals, and sensors on the aircraft''s designed mounting point so the load sits under the geometric center.</li><li><strong>Balance opposing loads.</strong> If you add weight on one side, offset it (or use the manufacturer''s balancing provisions) so the aircraft hangs level.</li><li><strong>Secure everything.</strong> A payload that shifts in flight moves the CG mid-flight - secure all loads so nothing slides, swings, or detaches.</li><li><strong>Re-check after changes.</strong> Swapping a heavier battery or a different camera changes both total weight and CG; verify a stable, level hover at low altitude before climbing.</li></ul>"}]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0002-0000-0000-000000000006', 'faa70510-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Total weight (airframe + battery + payload + attachments) must stay at or below the manufacturer''s maximum takeoff weight.","The center of gravity (CG) is the point about which the aircraft''s weight balances; it must stay within manufacturer limits.","A forward CG increases stability but reduces maneuverability and efficiency.","An aft CG reduces stability and can make the aircraft twitchy or uncontrollable.","Mount payloads on the centerline and secure them so the CG stays centered and cannot shift in flight."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70510-0000-0000-0000-000000000003', 'faa70000-0000-0000-0000-000000000005', 'Payload Effects: Flight Time, Maneuverability, and Battery Draw', '', ARRAY['Heavier payload -> more lift required -> more power -> shorter flight time and smaller reserve.','Overloading reduces climb rate and maneuverability and raises the risk of loss of control.','Asymmetric or unsecured payloads shift the CG and can cause loss of control; secure and balance every load.','Manufacturer flight times are best-case, standard-condition values - real conditions only make endurance worse.','Plan payload so you always land with a safe battery reserve and never exceed maximum takeoff weight.']::text[], 3, 24, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Explain why heavier payloads require more lift, more power, and yield shorter flight time.','Describe how payload affects maneuverability, climb, and reserve.','Plan payload so the aircraft stays within weight, CG, and endurance margins.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0003-0000-0000-000000000000', 'faa70510-0000-0000-0000-000000000003', 'text', '{"html":"<h3>The payload trade-off</h3><p>Every gram you add to a drone has to be lifted. To support a heavier total weight, the props must produce <strong>more lift</strong>, which requires the motors to spin faster and draw <strong>more current</strong> from the battery. The direct result is <strong>shorter flight time</strong> and a smaller safety reserve. Adding payload is always a trade-off: more capability (a bigger camera, a sensor, a delivery package) in exchange for less endurance and less margin.</p><p>Heavier loading also degrades <strong>performance</strong> across the board. An overloaded drone <strong>climbs more slowly</strong>, is <strong>less maneuverable</strong> (it accelerates and stops more sluggishly), and has a <strong>higher risk of loss of control</strong>, especially in gusty wind or when a low battery can no longer deliver the current the motors demand. In thin air (high density altitude), these effects compound - which is why pilots often <strong>reduce payload</strong> on hot, high days.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0003-0000-0000-000000000001', 'faa70510-0000-0000-0000-000000000003', 'table', '{"headers":["As payload increases...","Effect"],"rows":[["Lift required","Increases (props must work harder)"],["Power / current draw","Increases"],["Flight time / endurance","Decreases"],["Battery reserve at landing","Decreases"],["Climb rate","Decreases"],["Maneuverability / responsiveness","Decreases"],["Risk of loss of control","Increases"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0003-0000-0000-000000000002', 'faa70510-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Heavier payload means more lift required, more power drawn, and a shorter flight. Never load to the point that you cannot land with a safe battery reserve, and never exceed the maximum takeoff weight."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0003-0000-0000-000000000003', 'faa70510-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Asymmetric loads and shifting cargo</h3><p>Payload affects not just <em>how much</em> the aircraft carries but <em>where</em>. An <strong>asymmetric payload</strong> (heavier on one side or end) shifts the CG and forces some motors to overwork, which both worsens control and drains those cells faster. Worse, a load that is not secured can <strong>shift during flight</strong> - changing the CG in the air, sometimes suddenly, and potentially causing a loss of control. Secure every payload, balance it about the center, and confirm a clean, level hover before you commit to the mission.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0003-0000-0000-000000000004', 'faa70510-0000-0000-0000-000000000003', 'accordion', '{"sections":[{"title":"Worked example: payload vs. flight time","open":false,"content":"<p>Suppose a manufacturer rates a quadcopter for <strong>30 minutes of hover with no payload</strong> and <strong>18 minutes with a 1.0 lb payload</strong>. You plan a job needing a 0.5 lb camera in moderate wind on a warm day. From the data you should expect:</p><ul><li>Flight time noticeably shorter than 30 min and likely <em>less</em> than the 18 min figure once you add wind and warm (lower-density) air, which the chart''s standard-condition numbers do not include.</li><li>So you plan conservatively - assume well under 18 minutes of usable time, and land with a reserve (commonly land by 20-30% battery). If the math is tight, fly multiple shorter sorties or use a larger/spare battery instead of stretching one flight.</li></ul><p>The lesson: manufacturer numbers are <strong>best-case, standard-condition</strong> values. Real payload, wind, and temperature always make endurance worse - never better.</p>"}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0003-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Heavier payload -> more lift required -> more power -> shorter flight time and smaller reserve.","Overloading reduces climb rate and maneuverability and raises the risk of loss of control.","Asymmetric or unsecured payloads shift the CG and can cause loss of control; secure and balance every load.","Manufacturer flight times are best-case, standard-condition values - real conditions only make endurance worse.","Plan payload so you always land with a safe battery reserve and never exceed maximum takeoff weight."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70510-0000-0000-0000-000000000004', 'faa70000-0000-0000-0000-000000000005', 'Density Altitude and Wind: Performance and Endurance', '', ARRAY['Density altitude is pressure altitude corrected for non-standard temperature - the altitude the aircraft ''feels.''','High, Hot, and Humid all raise density altitude and reduce lift, thrust, and prop efficiency.','High density altitude means slower climb, reduced payload, sluggish handling, and shorter flight time - reduce payload.','Wind makes the motors work harder and drains the battery faster, shortening endurance.','Watch for gusts, wind shear, and mechanical turbulence near obstacles; avoid thunderstorms and microbursts.']::text[], 4, 24, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Define density altitude and the ''high, hot, humid'' conditions that raise it.','Explain why high density altitude reduces lift, thrust, and propeller efficiency.','Describe how wind, gusts, and shear degrade control and endurance.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0004-0000-0000-000000000000', 'faa70510-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Density altitude - the air the drone ''feels''</h3><p><strong>Density altitude</strong> is <strong>pressure altitude corrected for non-standard temperature</strong> - essentially, the altitude at which the air density makes the aircraft <em>feel</em> like it is flying. Standard sea-level conditions are <strong>29.92 inHg and 15&deg;C</strong>. When the air is <strong>less dense</strong>, the aircraft performs as if it were higher than it really is, and performance degrades.</p><p>Three things make air less dense and therefore <strong>raise</strong> density altitude: <strong>high elevation, high temperature, and high humidity</strong> - the classic memory aid <strong>''High, Hot, and Humid.''</strong> Thinner air means the propellers have fewer air molecules to push against, so they produce <strong>less lift and less thrust</strong> and become <strong>less efficient</strong>. The motors must spin faster to compensate, drawing more current. The practical results on a hot day at high elevation: <strong>slower climb, reduced payload capacity, sluggish handling, and shorter flight time.</strong></p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0004-0000-0000-000000000001', 'faa70510-0000-0000-0000-000000000004', 'table', '{"headers":["Condition","Effect on air density","Effect on density altitude","Effect on sUAS performance"],"rows":[["High elevation","Lower","Higher","Less lift/thrust, degraded"],["High temperature (hot)","Lower","Higher","Less lift/thrust, degraded"],["High humidity","Lower","Higher","Less lift/thrust, degraded"],["Low / cool / dry (high pressure)","Higher","Lower","Better performance"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0004-0000-0000-000000000002', 'faa70510-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"High, Hot, and Humid all RAISE density altitude and HURT performance. On such days, expect slower climb, less payload, and shorter flight time - reduce your load and plan conservatively."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0004-0000-0000-000000000003', 'faa70510-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Wind, gusts, and wind shear</h3><p>Small, light aircraft are very <strong>wind-sensitive</strong>. Holding position or flying a path in wind forces the drone to tilt and run its motors harder to <strong>fight the wind</strong>, which drains the battery faster and <strong>shortens endurance</strong>. Flying <strong>upwind</strong> (into the wind) costs extra power; flying <strong>downwind</strong> increases groundspeed and can carry the aircraft farther than intended. <strong>Gusts</strong> and <strong>wind shear</strong> (sudden changes in wind speed or direction) degrade control and can momentarily overwhelm the flight controller.</p><p>Watch especially for <strong>mechanical turbulence</strong> - the swirling, gusty air created when wind flows around buildings, trees, and terrain near your launch site. A microburst from a nearby thunderstorm produces extreme, rapidly shifting wind shear that can slam a small UA to the ground; avoid thunderstorms entirely. A good operational habit: plan your return so you are flying <strong>back into the wind low on battery</strong>, not discovering you cannot make it home against a headwind.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0004-0000-0000-000000000004', 'faa70510-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Fighting wind drains the battery faster and shortens endurance. Plan to return into the wind, watch for mechanical turbulence near buildings and terrain, and never fly into or near thunderstorms (microburst wind shear)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0004-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Density altitude is pressure altitude corrected for non-standard temperature - the altitude the aircraft ''feels.''","High, Hot, and Humid all raise density altitude and reduce lift, thrust, and prop efficiency.","High density altitude means slower climb, reduced payload, sluggish handling, and shorter flight time - reduce payload.","Wind makes the motors work harder and drains the battery faster, shortening endurance.","Watch for gusts, wind shear, and mechanical turbulence near obstacles; avoid thunderstorms and microbursts."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70510-0000-0000-0000-000000000005', 'faa70000-0000-0000-0000-000000000005', 'Battery Care, Hazards, and Pre-Flight Performance Planning', '', ARRAY['LiPo/Li-ion packs are energy-dense but hazardous; thermal runaway can cause fire or explosion.','Never fly or charge a damaged or swollen pack; charge with the correct charger and never leave it unattended.','Store packs at storage charge (~3.8 V/cell, ~50%), cool, dry, and in a fireproof container.','Cold reduces battery capacity and voltage and can cause sudden power loss - pre-warm packs and expect shorter flights.','Always plan a battery reserve (commonly land by 20-30%) and never fly a pack to 0%.','Manufacturer performance data are best-case, standard-condition values - discount them for payload, wind, and temperature.']::text[], 5, 28, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Apply safe charging, storage, and handling practices for LiPo/Li-ion packs.','Recognize battery hazards: thermal runaway, swelling, damage, and cold-weather effects.','Build a pre-flight performance plan and read manufacturer performance data.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000000', 'faa70510-0000-0000-0000-000000000005', 'text', '{"html":"<h3>LiPo and Li-ion batteries: power and hazard</h3><p>Most sUAS are powered by <strong>lithium polymer (LiPo)</strong> or <strong>lithium-ion (Li-ion)</strong> battery packs. They are prized for being <strong>energy-dense</strong> - a lot of stored energy in a light package - but that same energy density makes them <strong>hazardous</strong> if mistreated. The principal danger is <strong>thermal runaway</strong>: an internal short or overheating triggers a self-feeding chemical reaction that rapidly heats the cell, leading to <strong>fire or explosion</strong>. Thermal runaway can be caused by <strong>overcharging, over-discharging, short-circuiting, puncturing, or physically damaging</strong> a pack.</p><p>A LiPo fire is intense and hard to extinguish, and a damaged pack can ignite without warning - sometimes hours later. That is why battery handling is a core safety skill, not an afterthought. The single most important rule: <strong>never fly or charge a damaged or swollen pack.</strong></p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000001', 'faa70510-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A healthy LiPo pack (flat, firm) next to a swollen/puffed pack. A swollen pack must be retired immediately and never charged or flown."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000002', 'faa70510-0000-0000-0000-000000000005', 'table', '{"headers":["Practice","Do this","Why"],"rows":[["Charging","Use the correct LiPo/Li-ion charger; never leave charging unattended; let hot packs cool before charging","Wrong charger or overcharge can trigger thermal runaway"],["Storage","Store at storage charge (~3.8 V/cell, ~50%), cool and dry, in a fireproof bag/container","Full or empty long-term storage stresses cells and shortens life"],["Damage","Never fly or charge a swollen, puffed, punctured, or damaged pack - retire it","Damaged cells can ignite spontaneously"],["Discharge","Respect the low-voltage cutoff; do not over-discharge or fly to 0%","Over-discharge damages cells and risks sudden voltage sag/loss of power"],["Cold weather","Keep packs warm before flight; expect reduced capacity and shorter flights","Cold lowers capacity and voltage, risking sudden power loss"],["Fire plan","Have a fireproof storage/transport method and a plan to smother/cool a fire","LiPo fires are intense and re-ignite"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000003', 'faa70510-0000-0000-0000-000000000005', 'callout', '{"type":"error","text":"Never fly or charge a damaged or swollen (puffed) LiPo pack. Swelling means the cell is failing - retire it immediately. Never leave a charging pack unattended, and store packs at storage charge in a fireproof container."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000004', 'faa70510-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Cold weather and battery reserves</h3><p><strong>Cold</strong> is a quiet performance killer. Low temperatures <strong>reduce a LiPo''s capacity and voltage</strong>, so a battery that gives 20 minutes in mild weather may give far less in the cold - and can suffer a <strong>sudden voltage drop</strong> under load that forces an unexpected landing. In winter, pre-warm packs, expect shorter flights, and land earlier. Year-round, the rule is the same: <strong>always plan with a battery reserve</strong> and never fly a pack down to 0%. Many operators set a hard ''return-to-home'' or land trigger at <strong>20-30% remaining</strong> so an unexpected headwind or sag still leaves margin to land safely.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Reading manufacturer performance data</h3><p>Manufacturers publish <strong>performance specifications</strong> - maximum flight time, hover time, maximum payload, maximum wind resistance, and operating temperature range - and sometimes a <strong>performance chart</strong> (for example, flight time vs. payload, or vs. temperature). These figures are <strong>best-case, standard-condition</strong> numbers: a ''max flight time'' is usually measured in still air, at a steady speed, with no payload, on a fresh battery in mild temperatures. Your real flight - with payload, wind, maneuvering, and non-standard temperature - will <strong>always be shorter</strong>. Use the published data as a starting point, then <strong>discount it</strong> for your actual conditions and subtract your reserve. When a chart gives values at intervals (e.g., 0, 0.5, 1.0 lb payload), interpolate conservatively and round in the safe direction.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000006', 'faa70510-0000-0000-0000-000000000005', 'accordion', '{"sections":[{"title":"Pre-flight performance planning checklist","open":false,"content":"<p>Before each operation, plan performance the way 14 CFR 107.49 expects you to assess the operating environment:</p><ul><li><strong>Battery:</strong> packs fully charged, healthy (no swelling/damage), warm if cold out; plan a reserve and a hard land/RTH trigger (e.g., 20-30%).</li><li><strong>Wind:</strong> check current and forecast wind, gusts, and direction; confirm they are within the aircraft''s wind-resistance spec; plan to return into the wind.</li><li><strong>Temperature & density altitude:</strong> hot/high/humid? Expect degraded performance and reduce payload.</li><li><strong>Weight & balance:</strong> total weight at or below max takeoff weight; CG centered; payload secured.</li><li><strong>Site assessment:</strong> obstacles, terrain, and buildings that create mechanical turbulence; people and property; a clear takeoff/landing area and an emergency landing spot over the least-populated ground.</li><li><strong>Manufacturer data:</strong> review flight-time/payload/wind specs and discount them for today''s conditions.</li></ul>"}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000007', 'faa70510-0000-0000-0000-000000000005', 'callout', '{"type":"success","text":"Good performance planning = healthy charged batteries + a reserve, wind within limits and a return-into-wind plan, payload within weight/CG limits, density-altitude awareness, and a site assessment - all discounted from best-case manufacturer numbers."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70520-0005-0000-0000-000000000008', 'faa70510-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["LiPo/Li-ion packs are energy-dense but hazardous; thermal runaway can cause fire or explosion.","Never fly or charge a damaged or swollen pack; charge with the correct charger and never leave it unattended.","Store packs at storage charge (~3.8 V/cell, ~50%), cool, dry, and in a fireproof container.","Cold reduces battery capacity and voltage and can cause sudden power loss - pre-warm packs and expect shorter flights.","Always plan a battery reserve (commonly land by 20-30%) and never fly a pack to 0%.","Manufacturer performance data are best-case, standard-condition values - discount them for payload, wind, and temperature."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000001', 'Lift', 'The upward force that opposes weight; on a multirotor it is produced by the spinning propellers, on a fixed-wing by airflow over the wing.', 'Opposes weight; must exceed it to climb.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000002', 'Weight', 'The downward force of gravity acting on the total mass of the aircraft, battery, and payload.', 'The ''penalty'' force lift must overcome.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000003', 'Thrust', 'The force that moves the aircraft in the direction of travel; on a multirotor it comes from tilting the aircraft so the props push it forward.', 'Opposes drag.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000004', 'Drag', 'Air resistance that opposes the aircraft''s motion; increased by wind, bulky payloads, and fast flight.', 'Opposes thrust.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000005', 'Center of gravity (CG)', 'The single point at which the entire weight of the aircraft is considered to act - the balance point. It must remain within the manufacturer''s limits.', 'The point the aircraft would balance on.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000006', 'Maximum takeoff weight', 'The manufacturer''s published limit for total weight (airframe + battery + payload + attachments) at which the aircraft may legally and safely take off.', 'The ceiling for total weight.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000007', 'Forward CG effect', 'Increases stability but makes the aircraft nose-heavy, sluggish, less maneuverable, and less efficient.', 'More stable, less responsive.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000008', 'Aft CG effect', 'Reduces stability; the aircraft becomes twitchy, prone to oscillation, and can become uncontrollable.', 'The more dangerous direction.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000009', 'Payload effect on flight time', 'Adding payload increases the lift and power required, which increases battery draw and shortens flight time and reserve.', 'More weight, less endurance.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000010', 'Effects of overloading', 'Reduced climb performance, reduced maneuverability, shorter flight time, smaller reserve, and increased risk of stall/loss of control.', 'Sluggish and risky.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000011', 'Asymmetric payload', 'A load mounted off-center that shifts the CG, overworks some motors, and can cause loss of control - especially if it shifts in flight.', 'Off-balance cargo.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000012', 'Density altitude', 'Pressure altitude corrected for non-standard temperature; the altitude at which the air density makes the aircraft perform as if it were flying. High density altitude degrades performance.', 'The altitude the aircraft ''feels.''', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000013', 'High, Hot, and Humid', 'The three conditions (high elevation, high temperature, high humidity) that lower air density, raise density altitude, and reduce sUAS lift, thrust, and efficiency.', 'All three raise density altitude.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000014', 'Effect of high density altitude on sUAS', 'Thinner air gives the props less to push against, so there is less lift and thrust: slower climb, reduced payload, sluggish handling, and shorter flight time.', 'Thin air = degraded performance.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000015', 'Mechanical turbulence', 'Swirling, gusty air created when wind flows around buildings, trees, or terrain - a control hazard for sUAS near the launch site.', 'Wind tumbling around obstacles.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000016', 'Thermal runaway', 'A self-feeding chemical reaction in a lithium battery cell that rapidly generates heat, leading to fire or explosion; triggered by overcharge, over-discharge, short circuit, puncture, or damage.', 'The runaway heating that causes LiPo fires.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000017', 'Swollen (puffed) LiPo', 'A battery pack that has visibly bulged, indicating internal failure. It must be retired immediately and never charged or flown.', 'Bulging = retire it now.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000018', 'Storage charge', 'The recommended long-term storage state for a LiPo, about 3.8 V per cell (~50% capacity), kept cool, dry, and in a fireproof container.', 'About half charge, ~3.8 V/cell.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000019', 'Cold-weather battery effect', 'Cold reduces a LiPo''s capacity and voltage, shortening flight time and risking a sudden voltage drop and unexpected landing.', 'Cold = less capacity, sudden sag.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70540-0000-0000-0000-000000000020', 'Battery reserve', 'Charge intentionally kept in reserve so the aircraft can always land safely; pilots commonly set a hard land/RTH trigger at 20-30% and never fly to 0%.', 'Land before empty.', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000001', 'Which two of the four forces of flight are the ''penalty'' forces that an sUAS must overcome to fly?', 'multiple_choice', '["Weight and drag","Lift and thrust","Lift and weight"]'::jsonb, 'Weight and drag', 'Lift and thrust are the forces the aircraft generates (the ''engine'' forces); weight and drag are the opposing ''penalty'' forces it must overcome. Lift opposes weight and thrust opposes drag.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000002', 'On a multirotor sUAS holding a steady, motionless hover, what is the relationship between lift and weight?', 'multiple_choice', '["Lift exactly equals weight","Lift exceeds weight","Lift is less than weight"]'::jsonb, 'Lift exactly equals weight', 'In a steady hover the aircraft is neither climbing nor descending, so lift exactly equals weight. To climb, lift must exceed weight; if lift is less than weight, the aircraft descends.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000003', 'How does a multirotor produce thrust to move horizontally?', 'multiple_choice', '["It tilts in the direction of travel so part of the props'' force pushes it forward","It uses a separate forward-facing propeller","It increases lift on all motors equally"]'::jsonb, 'It tilts in the direction of travel so part of the props'' force pushes it forward', 'A multirotor has no separate forward propeller; it tilts so a component of the rotors'' thrust pushes it horizontally while the rest still supports its weight. Increasing all motors equally would only climb.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000004', 'Why does cruising into a strong wind drain a multirotor''s battery faster?', 'multiple_choice', '["The motors must work harder to overcome drag while still supporting the aircraft''s weight","The wind cools the motors, increasing their resistance","Lift is no longer required in forward flight"]'::jsonb, 'The motors must work harder to overcome drag while still supporting the aircraft''s weight', 'Flying into wind increases drag, so the motors must produce extra thrust to overcome it while still supporting the weight - drawing more current. Lift is still required in forward flight, and wind cooling does not increase resistance.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000005', 'What does the term ''center of gravity'' (CG) refer to on an sUAS?', 'multiple_choice', '["The point at which the aircraft''s entire weight is considered to act","The geometric center of the battery","The point of maximum lift on the propellers"]'::jsonb, 'The point at which the aircraft''s entire weight is considered to act', 'The CG is the single balance point at which the aircraft''s total weight is considered to act. It must stay within the manufacturer''s limits for safe, stable, controllable flight.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000006', 'An sUAS is loaded so its center of gravity is too far aft. What is the most likely effect?', 'multiple_choice', '["Reduced stability, making the aircraft twitchy and harder to control","Increased stability and longer flight time","No effect as long as total weight is within limits"]'::jsonb, 'Reduced stability, making the aircraft twitchy and harder to control', 'An aft CG reduces stability and can make the aircraft twitchy, prone to oscillation, and potentially uncontrollable. CG matters even when total weight is within limits, because balance affects controllability.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000007', 'Compared with a balanced load, what does a forward CG generally do to an sUAS?', 'multiple_choice', '["Increases stability but reduces maneuverability and efficiency","Increases both stability and maneuverability","Reduces stability and increases responsiveness"]'::jsonb, 'Increases stability but reduces maneuverability and efficiency', 'A forward CG makes the aircraft more stable (nose-heavy) but sluggish and less maneuverable, and it drains the battery unevenly. An aft CG, by contrast, reduces stability and increases twitchiness.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000008', 'Which statement about total weight on a Part 107 sUAS is correct?', 'multiple_choice', '["Total weight (airframe + battery + payload + attachments) must stay at or below the manufacturer''s maximum takeoff weight","Only the payload counts toward the weight limit","Weight limits only matter at high density altitude"]'::jsonb, 'Total weight (airframe + battery + payload + attachments) must stay at or below the manufacturer''s maximum takeoff weight', 'Total weight includes the airframe, battery, payload, and any attachments, and it must remain at or below the manufacturer''s maximum takeoff weight. Weight always matters, though high density altitude makes overloading worse.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000009', 'Why is it important to securely mount and balance a payload before flight?', 'multiple_choice', '["An unsecured load can shift in flight, moving the CG and causing a loss of control","Securing the payload increases the maximum takeoff weight","Balancing the payload eliminates the need to check the battery"]'::jsonb, 'An unsecured load can shift in flight, moving the CG and causing a loss of control', 'A load that shifts in flight changes the CG in the air, possibly suddenly, and can cause loss of control. Securing a load does not change the weight limit or remove other pre-flight checks.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000010', 'What is the primary effect of adding payload to an sUAS?', 'multiple_choice', '["More lift and power are required, shortening flight time","Flight time increases because the aircraft is more stable","The aircraft climbs faster"]'::jsonb, 'More lift and power are required, shortening flight time', 'Heavier payload requires more lift, so the motors draw more current and flight time and reserve drop. Added weight also slows the climb and reduces maneuverability rather than improving them.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000011', 'An overloaded sUAS will most likely experience which of the following?', 'multiple_choice', '["Reduced climb rate, reduced maneuverability, and a higher risk of loss of control","Improved endurance and faster climb","No change as long as the CG is centered"]'::jsonb, 'Reduced climb rate, reduced maneuverability, and a higher risk of loss of control', 'Overloading degrades climb and maneuverability and increases the risk of loss of control, in addition to shortening flight time. A centered CG does not offset the penalties of excess total weight.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000012', 'A manufacturer lists a maximum flight time of 28 minutes. How should a remote pilot treat this figure when planning a job that carries a camera payload in moderate wind on a warm day?', 'multiple_choice', '["As a best-case value to be discounted, expecting significantly less usable time","As a guaranteed minimum flight time under any conditions","As the time available after the battery reaches 0%"]'::jsonb, 'As a best-case value to be discounted, expecting significantly less usable time', 'Published flight times are best-case, standard-condition values (no payload, still air, mild temperature, fresh battery). Real payload, wind, and warm air all shorten endurance, so the pilot should plan for significantly less and keep a reserve.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000013', 'How does an asymmetric (off-center) payload affect an sUAS?', 'multiple_choice', '["It shifts the CG and forces some motors to overwork, worsening control and draining those cells faster","It has no effect as long as total weight is under the limit","It improves stability by lowering the CG"]'::jsonb, 'It shifts the CG and forces some motors to overwork, worsening control and draining those cells faster', 'An off-center load moves the CG, so the flight controller must run some motors harder to stay level, which worsens control and drains the battery unevenly. Total weight being within limits does not excuse a CG that is out of balance.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000014', 'Density altitude is best described as:', 'multiple_choice', '["Pressure altitude corrected for non-standard temperature","The aircraft''s height above ground level","The altitude indicated on the controller''s GPS"]'::jsonb, 'Pressure altitude corrected for non-standard temperature', 'Density altitude is pressure altitude corrected for non-standard temperature - the altitude at which the air density makes the aircraft ''feel'' like it is flying. It is not a height above ground or a GPS readout.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000015', 'Which combination of conditions produces a HIGH density altitude and the WORST sUAS performance?', 'multiple_choice', '["High elevation, high temperature, and high humidity","Low elevation, cool temperature, and dry air","Sea level, standard temperature, and high pressure"]'::jsonb, 'High elevation, high temperature, and high humidity', '''High, Hot, and Humid'' all lower air density and raise density altitude, reducing lift, thrust, and propeller efficiency. Cool, dry, low, high-pressure conditions give the best performance.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000016', 'On a hot day at a high-elevation site, what should a remote pilot expect from the aircraft''s performance?', 'multiple_choice', '["Slower climb, reduced payload capacity, and shorter flight time","Faster climb and longer flight time","No change because density altitude only affects manned aircraft"]'::jsonb, 'Slower climb, reduced payload capacity, and shorter flight time', 'High density altitude means thinner air, so the props produce less lift and thrust: the drone climbs more slowly, carries less, and flies shorter. Density altitude affects small UAS just as it affects manned aircraft.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000017', 'Why should a remote pilot plan to fly back toward the launch point INTO the wind while the battery is getting low?', 'multiple_choice', '["Flying into a headwind takes extra power, so it should be done while reserve remains rather than discovering you cannot make it home","A headwind charges the battery during the return","Wind has no effect on a returning aircraft"]'::jsonb, 'Flying into a headwind takes extra power, so it should be done while reserve remains rather than discovering you cannot make it home', 'Returning into the wind costs extra power; doing it while you still have reserve avoids being stranded downwind on a dying battery. Wind does not charge the battery, and it certainly affects a returning aircraft.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000018', 'What is ''mechanical turbulence'' and why does it concern an sUAS pilot?', 'multiple_choice', '["Swirling, gusty air created when wind flows around buildings or terrain - a control hazard near the launch site","Vibration caused by a worn motor bearing","Turbulence felt only above 400 ft AGL"]'::jsonb, 'Swirling, gusty air created when wind flows around buildings or terrain - a control hazard near the launch site', 'Mechanical turbulence is the chaotic air produced when wind tumbles around obstacles such as buildings, trees, and terrain. It can degrade control right where the drone operates, near the ground and structures.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000019', 'How does wind affect an sUAS battery''s endurance?', 'multiple_choice', '["Fighting wind makes the motors work harder, draining the battery faster and shortening endurance","Wind extends endurance by providing free lift","Wind has no measurable effect on endurance"]'::jsonb, 'Fighting wind makes the motors work harder, draining the battery faster and shortening endurance', 'Holding position or flying a path in wind forces the aircraft to tilt and work its motors harder to overcome drag, increasing current draw and shortening endurance. Light aircraft are especially wind-sensitive.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000020', 'What is the principal hazard of LiPo/Li-ion batteries that makes careful handling essential?', 'multiple_choice', '["Thermal runaway leading to fire or explosion","Gradual loss of color over time","They become heavier as they discharge"]'::jsonb, 'Thermal runaway leading to fire or explosion', 'The chief danger is thermal runaway - a self-feeding heating reaction that can cause fire or explosion, triggered by overcharge, over-discharge, short circuit, puncture, or damage. Batteries do not change weight as they discharge.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000021', 'You notice that a LiPo pack has become swollen (puffed up). What should you do?', 'multiple_choice', '["Retire it immediately and do not charge or fly it","Charge it slowly to flatten it back out","Use it for one more flight, then discard it"]'::jsonb, 'Retire it immediately and do not charge or fly it', 'Swelling indicates internal cell failure; a puffed pack must be retired immediately and never charged or flown, because it can ignite spontaneously. There is no safe way to ''flatten'' or use a swollen pack.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000022', 'Which is the recommended way to store a LiPo battery for the long term?', 'multiple_choice', '["At storage charge (about 3.8 V/cell, ~50%), cool, dry, and in a fireproof container","Fully charged so it is always ready to fly","Fully discharged to zero to prevent fire"]'::jsonb, 'At storage charge (about 3.8 V/cell, ~50%), cool, dry, and in a fireproof container', 'LiPos should be stored at about 50% (storage charge, ~3.8 V/cell), cool, dry, and in a fireproof bag or container. Storing fully charged or fully discharged for long periods stresses the cells and shortens their life.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000023', 'How does cold weather typically affect a LiPo-powered sUAS?', 'multiple_choice', '["Reduced battery capacity and voltage, leading to shorter flight time and possible sudden power loss","Increased capacity and longer flights","No effect on the battery, only on the pilot''s comfort"]'::jsonb, 'Reduced battery capacity and voltage, leading to shorter flight time and possible sudden power loss', 'Cold reduces a LiPo''s capacity and voltage, shortening flight time and risking a sudden voltage sag under load that can force an unexpected landing. Pre-warm packs and expect shorter flights in cold weather.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000024', 'Which charging practice helps prevent a battery fire?', 'multiple_choice', '["Use the correct LiPo charger and never leave a charging pack unattended","Charge with any available USB charger to save time","Charge a hot pack immediately after landing to keep it warm"]'::jsonb, 'Use the correct LiPo charger and never leave a charging pack unattended', 'Always charge with the proper LiPo/Li-ion charger and stay with the pack while it charges so you can react if it overheats. The wrong charger can overcharge a pack, and a hot pack should be allowed to cool before charging.', 'easy', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000025', 'Why should a remote pilot always plan a battery reserve and avoid flying a pack to 0%?', 'multiple_choice', '["A reserve leaves margin to land safely if wind, payload, or voltage sag reduce the expected flight time","Flying to 0% extends the battery''s life","Reserves are only required at night"]'::jsonb, 'A reserve leaves margin to land safely if wind, payload, or voltage sag reduce the expected flight time', 'A battery reserve (many pilots set a hard land/RTH trigger around 20-30%) ensures you can still land if conditions cut your endurance or the voltage sags. Over-discharging to 0% damages the cells and is not a day/night issue.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000026', 'When using a manufacturer''s published ''maximum flight time,'' how should it be interpreted?', 'multiple_choice', '["As a best-case, standard-condition value that will be shorter with payload, wind, and non-standard temperature","As the guaranteed flight time in any weather with full payload","As the time available only after the reserve is used up"]'::jsonb, 'As a best-case, standard-condition value that will be shorter with payload, wind, and non-standard temperature', 'Maximum flight time is measured under ideal, standard conditions (no payload, still air, mild temperature). Real operations with payload, wind, maneuvering, and non-standard temperatures will always yield shorter times, so discount the figure and keep a reserve.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70530-0000-0000-0000-000000000027', 'Which item belongs in a pre-flight performance plan for an sUAS operation?', 'multiple_choice', '["Confirming wind is within the aircraft''s limits and planning to return into the wind","Assuming the manufacturer''s max flight time is achievable today","Flying the battery to 0% to maximize coverage"]'::jsonb, 'Confirming wind is within the aircraft''s limits and planning to return into the wind', 'Sound performance planning checks wind against the aircraft''s wind-resistance limits and plans a return into the wind, in addition to weight/CG, density altitude, battery reserves, and a site assessment. You should not assume best-case flight time or fly to 0%.', 'medium', 'faa70000-0000-0000-0000-000000000005', 'faa70510-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70610-0000-0000-0000-000000000001', 'faa70000-0000-0000-0000-000000000006', 'Lesson 1: Crew Resource Management & the Remote PIC''s Authority', '', ARRAY['CRM = using all available resources (people, hardware, information) to fly safely; brief the crew and assign roles before launch.','Under 107.19 the Remote PIC is the final authority and is directly responsible for the operation.','A non-certificated person may manipulate the controls only if an RPIC supervises and can immediately take direct control.','One RPIC per operation, and one aircraft per pilot at a time (107.35); a visual observer is optional but must be able to communicate with the RPIC.']::text[], 1, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Define Crew Resource Management and identify the resources available to a remote pilot.','State the remote PIC''s final authority and responsibilities under 14 CFR 107.19.','Distinguish the roles of the remote PIC, the person manipulating the controls, and the visual observer.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0001-0000-0000-000000000000', 'faa70610-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What is Crew Resource Management?</h3><p><strong>Crew Resource Management (CRM)</strong> is the effective use of <em>all</em> resources available to conduct a flight safely. Those resources fall into three groups: <strong>human resources</strong> (a visual observer, a second remote pilot, ground crew, bystanders helping with crowd control, ATC, a weather briefer), <strong>hardware</strong> (the aircraft, control station, batteries, lighting, checklists), and <strong>information</strong> (weather, NOTAMs, airspace data, the manufacturer''s manual). Even a single-pilot drone operation benefits from CRM: you are still managing checklists, the aircraft, weather information, and the people around your launch site.</p><p>Good CRM is about <strong>communication, situational awareness, and workload management</strong>. Before flight, the remote PIC should brief everyone involved, assign clear roles, agree on how the crew will communicate (verbal callouts, radios, hand signals), and confirm what to do if something goes wrong. When a visual observer is used, the RPIC and VO must be able to communicate at all times so the VO can pass traffic and hazard information back to the pilot.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0001-0000-0000-000000000001', 'faa70610-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"CRM is not only for big crews. A solo remote pilot still ''manages a crew'' of one — plus checklists, the aircraft, and information sources. The goal is to never be overloaded to the point that safety suffers."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0001-0000-0000-000000000002', 'faa70610-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Remote PIC: final authority and responsibility</h3><p>Under <strong>14 CFR 107.19</strong>, every Part 107 operation must have one <strong>Remote Pilot in Command (RPIC)</strong>. The RPIC is <strong>directly responsible for, and the final authority over, the operation</strong>. That responsibility cannot be delegated away. The RPIC must:</p><ul><li>Ensure the operation poses <strong>no undue hazard</strong> to people, aircraft, or property if control is lost.</li><li>Ensure the small unmanned aircraft complies with all of Part 107.</li><li>Have the ability to <strong>direct the aircraft</strong> to ensure compliance — and to immediately take direct control if a non-certificated person is manipulating the controls.</li></ul><p>A person who does <em>not</em> hold a remote pilot certificate may fly the aircraft only if a certificated RPIC is supervising and can <strong>immediately take direct control</strong>. The RPIC is still responsible for everything that happens.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0001-0000-0000-000000000003', 'faa70610-0000-0000-0000-000000000001', 'table', '{"headers":["Role","Certificate required?","Key responsibility"],"rows":[["Remote Pilot in Command (RPIC)","Yes — Remote Pilot Certificate","Final authority and responsibility for the entire operation (107.19); ensures compliance and safety."],["Person manipulating the controls","No, if directly supervised by an RPIC who can immediately take control","Flies the aircraft under the RPIC''s supervision."],["Visual Observer (VO)","No certificate required; optional (107.33)","Helps the RPIC maintain awareness of the aircraft''s position and scan for traffic; must be able to communicate with the RPIC."]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0001-0000-0000-000000000004', 'faa70610-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Only ONE person may act as RPIC for a given operation at a time, and a remote pilot may act as RPIC (or manipulate the controls) for only ONE aircraft at a time (107.35). You cannot fly two drones at once under Part 107."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0001-0000-0000-000000000005', 'faa70610-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A Part 107 crew — the RPIC holds final authority; a non-certificated person may fly only under direct supervision; the VO scans and communicates traffic."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0001-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["CRM = using all available resources (people, hardware, information) to fly safely; brief the crew and assign roles before launch.","Under 107.19 the Remote PIC is the final authority and is directly responsible for the operation.","A non-certificated person may manipulate the controls only if an RPIC supervises and can immediately take direct control.","One RPIC per operation, and one aircraft per pilot at a time (107.35); a visual observer is optional but must be able to communicate with the RPIC."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70610-0000-0000-0000-000000000002', 'faa70000-0000-0000-0000-000000000006', 'Lesson 2: Physiological Factors & Fitness for Flight', '', ARRAY['You must be in a physical and mental condition to operate safely; dehydration, stress, and fatigue silently degrade judgment and vision.','Hyperventilation (over-breathing from stress) causes lightheadedness and is corrected by slowing the breathing rate.','Alcohol/drug rule: no operating within 8 hours of alcohol, while impaired, with BAC ≥ 0.04%, or while using any drug contrary to safety.','Night vision needs ~30 minutes to adapt and uses off-center viewing; bright light destroys it.','Use IMSAFE (Illness, Medication, Stress, Alcohol, Fatigue, Emotion) to self-assess before every flight.']::text[], 2, 28, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Identify physiological factors that degrade pilot performance: dehydration, hyperventilation, stress, fatigue, and impaired vision.','State the alcohol and drug rules: 8 hours bottle-to-throttle, 0.04 BAC, and no operating while impaired.','Use the IMSAFE checklist to self-assess fitness before each flight.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0002-0000-0000-000000000000', 'faa70610-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Your body is part of the aircraft system</h3><p>A drone never gets tired or dehydrated — but the remote pilot does, and a degraded pilot makes degraded decisions. The FAA expects every remote pilot to be in a <strong>physical and mental condition to safely operate</strong>. Several common physiological factors quietly erode judgment, vision, and reaction time:</p><ul><li><strong>Dehydration &amp; heat stress:</strong> Working outdoors in sun and heat causes fluid loss that reduces alertness, slows thinking, blurs vision, and causes headaches and fatigue — often before you notice. Drink water, take shade breaks, and watch for early signs.</li><li><strong>Stress:</strong> Physical, physiological, and psychological stress narrow attention and degrade decision-making. High stress can cause you to fixate or to miss obvious hazards.</li><li><strong>Fatigue:</strong> One of the most insidious hazards — fatigue degrades attention, reaction time, and judgment as much as alcohol can. Acute fatigue (one bad night) and chronic fatigue (long-term) both impair you. Don''t fly tired.</li><li><strong>Hyperventilation:</strong> Abnormally rapid or deep breathing — usually triggered by stress or anxiety — flushes out too much carbon dioxide, causing lightheadedness, tingling, visual impairment, and even loss of consciousness. The remedy is to <strong>slow the breathing rate</strong> (and breathe into a paper bag if needed) until normal breathing returns.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0002-0000-0000-000000000001', 'faa70610-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Vision and scanning</h3><p>Because the legal standard is <strong>visual line of sight</strong>, the pilot''s vision is mission-critical. Vision is degraded by dehydration, fatigue, glare, and aging. To see manned traffic and judge the aircraft''s attitude and altitude:</p><ul><li>Use sunglasses against glare during the day, but remove them in low light.</li><li>Scan the sky in a deliberate, systematic pattern rather than staring at one spot — the eye detects motion better with active scanning.</li><li>At night the eyes need about <strong>30 minutes to adapt to darkness</strong>, and night vision relies on the <em>off-center</em> part of the eye. A bright light (a phone screen, headlights, a flashlight in the face) can destroy dark adaptation in an instant.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0002-0000-0000-000000000002', 'faa70610-0000-0000-0000-000000000002', 'callout', '{"type":"error","text":"DRUGS & ALCOHOL (14 CFR 107.27 / 107.57): A remote pilot may NOT operate a small UAS within 8 hours of consuming alcohol (''8 hours bottle-to-throttle''), while under the influence of alcohol, with a blood-alcohol concentration of 0.04% or greater, or while using any drug that affects the person''s faculties in a way contrary to safety."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0002-0000-0000-000000000003', 'faa70610-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Alcohol, drugs, and medication</h3><p>Alcohol impairs judgment, coordination, and reaction time, and its effects linger well after the legal 8-hour window — a <strong>hangover still impairs you</strong> even when your BAC has returned to zero. Many over-the-counter and prescription <strong>medications</strong> (antihistamines, sleep aids, some cold remedies) also impair faculties; if a drug affects your safety-related performance, you must not fly. When in doubt, ground yourself.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0002-0000-0000-000000000004', 'faa70610-0000-0000-0000-000000000002', 'table', '{"headers":["Letter","Factor","Self-check question"],"rows":[["I","Illness","Am I sick? Any symptom that could impair me?"],["M","Medication","Have I taken any drug (prescription or OTC) that could affect performance?"],["S","Stress","Am I under psychological pressure — work, family, deadlines?"],["A","Alcohol","Have I been drinking within 8 hours? Within 24? Is my BAC under 0.04%?"],["F","Fatigue","Am I tired or poorly rested?"],["E","Emotion","Am I emotionally upset in a way that could distract me?"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0002-0000-0000-000000000005', 'faa70610-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"IMSAFE is a personal pre-flight checklist for the PILOT. Run it before every operation; if any item is a ''yes,'' reconsider whether you should fly."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0002-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["You must be in a physical and mental condition to operate safely; dehydration, stress, and fatigue silently degrade judgment and vision.","Hyperventilation (over-breathing from stress) causes lightheadedness and is corrected by slowing the breathing rate.","Alcohol/drug rule: no operating within 8 hours of alcohol, while impaired, with BAC ≥ 0.04%, or while using any drug contrary to safety.","Night vision needs ~30 minutes to adapt and uses off-center viewing; bright light destroys it.","Use IMSAFE (Illness, Medication, Stress, Alcohol, Fatigue, Emotion) to self-assess before every flight."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70610-0000-0000-0000-000000000003', 'faa70000-0000-0000-0000-000000000006', 'Lesson 3: Aeronautical Decision-Making & the Five Hazardous Attitudes', '', ARRAY['ADM is a systematic approach to consistently choosing the best course of action; the DECIDE model is a continuous loop (Detect, Estimate, Choose, Identify, Do, Evaluate).','The five hazardous attitudes are Anti-Authority, Impulsivity, Invulnerability, Macho, and Resignation.','Each attitude has a memorized antidote — know them verbatim (e.g., Macho → ''Taking chances is foolish'').','Recognizing the attitude in yourself is the first step to applying its antidote and making a safe decision.']::text[], 3, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Define Aeronautical Decision-Making (ADM) and describe the DECIDE model.','Name the five hazardous attitudes and state the correct antidote for each verbatim.','Recognize a hazardous attitude in a scenario and apply its antidote.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0003-0000-0000-000000000000', 'faa70610-0000-0000-0000-000000000003', 'text', '{"html":"<h3>What is ADM?</h3><p><strong>Aeronautical Decision-Making (ADM)</strong> is a systematic approach to consistently determining the best course of action in response to a given set of circumstances. It is what turns raw skill into <em>safe</em> flying. ADM teaches pilots to recognize hazards, evaluate risk, manage their own attitudes, and make conscious go/no-go decisions instead of reacting on instinct or emotion.</p><p>A common ADM process is the <strong>DECIDE model</strong>, a continuous loop:</p><ul><li><strong>D</strong>etect that a change has occurred.</li><li><strong>E</strong>stimate the need to counter or react to the change.</li><li><strong>C</strong>hoose a desirable outcome.</li><li><strong>I</strong>dentify actions to control the change.</li><li><strong>D</strong>o — take the necessary action.</li><li><strong>E</strong>valuate the effect of the action, then start the loop again.</li></ul><p>A big part of ADM is honest <strong>self-assessment</strong> — recognizing the attitudes and pressures that push you toward an unsafe decision.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0003-0000-0000-000000000001', 'faa70610-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"The five hazardous attitudes are some of the easiest points on the exam — memorize each attitude AND its exact antidote. Expect scenario questions that describe a pilot''s thought and ask you to name the attitude or its antidote."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0003-0000-0000-000000000002', 'faa70610-0000-0000-0000-000000000003', 'text', '{"html":"<h3>The five hazardous attitudes</h3><p>The FAA identifies five <strong>hazardous attitudes</strong> that interfere with sound decision-making. Each has a memorized <strong>antidote</strong> — a short statement a pilot consciously recalls to counter the attitude. Learn them word-for-word.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0003-0000-0000-000000000003', 'faa70610-0000-0000-0000-000000000003', 'table', '{"headers":["Hazardous Attitude","The pilot is thinking…","Antidote (memorize verbatim)"],"rows":[["Anti-Authority (''Don''t tell me!'')","The rules don''t apply to me; I resent being told what to do.","Follow the rules. They are usually right."],["Impulsivity (''Do something — quickly!'')","I must act now, on my first idea, without thinking it through.","Not so fast. Think first."],["Invulnerability (''It won''t happen to me'')","Accidents happen to other people, not to me.","It could happen to me."],["Macho (''I can do it'')","I''ll prove I''m better; I''ll take the risk to show my skill.","Taking chances is foolish."],["Resignation (''What''s the use?'')","I''m not really in control; what happens is up to luck or others.","I''m not helpless. I can make a difference."]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0003-0000-0000-000000000004', 'faa70610-0000-0000-0000-000000000003', 'accordion', '{"sections":[{"title":"Example: spotting the attitude","content":"<p>A pilot needs an airspace authorization but launches anyway, thinking ''the FAA''s rules are overkill for a quick job like this.'' That is <strong>Anti-Authority</strong>; the antidote is <em>''Follow the rules. They are usually right.''</em></p><p>A pilot sees clouds building and a client waiting, and rushes the launch without finishing the preflight, thinking ''just go, sort it out in the air.'' That is <strong>Impulsivity</strong>; the antidote is <em>''Not so fast. Think first.''</em></p><p>A pilot flies in marginal wind because ''I''ve flown in worse — I''ve got this.'' That is <strong>Macho</strong>; the antidote is <em>''Taking chances is foolish.''</em></p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0003-0000-0000-000000000005', 'faa70610-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Don''t confuse the attitudes: ''I can do it / I''ll show them'' is MACHO; ''the rules don''t apply to me'' is ANTI-AUTHORITY; ''it won''t happen to me'' is INVULNERABILITY. The exam tests these distinctions."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0003-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["ADM is a systematic approach to consistently choosing the best course of action; the DECIDE model is a continuous loop (Detect, Estimate, Choose, Identify, Do, Evaluate).","The five hazardous attitudes are Anti-Authority, Impulsivity, Invulnerability, Macho, and Resignation.","Each attitude has a memorized antidote — know them verbatim (e.g., Macho → ''Taking chances is foolish'').","Recognizing the attitude in yourself is the first step to applying its antidote and making a safe decision."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70610-0000-0000-0000-000000000004', 'faa70000-0000-0000-0000-000000000006', 'Lesson 4: Risk Management — PAVE & the 3P Model', '', ARRAY['PAVE identifies risk in four buckets: Pilot, Aircraft, enVironment, External pressures.','The ''Pilot'' element of PAVE is assessed with the IMSAFE checklist.','External pressure (''get-there-itis'') is a leading cause of unsafe decisions — set personal minimums and an ''out'' in advance.','The 3P model — Perceive, Process, Perform — is the loop used to manage identified risk.']::text[], 4, 25, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Apply the PAVE checklist to identify risk in the four categories: Pilot, Aircraft, enVironment, External pressures.','Use the 3P model (Perceive, Process, Perform) to manage identified risk.','Recognize how external pressure (''get-there-itis'') drives unsafe decisions.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0004-0000-0000-000000000000', 'faa70610-0000-0000-0000-000000000004', 'text', '{"html":"<h3>From decision-making to risk management</h3><p>ADM tells you <em>how</em> to decide; <strong>risk management</strong> gives you structured tools to find and reduce the hazards before they bite. The FAA promotes two simple frameworks every remote pilot should run before and during a flight: <strong>PAVE</strong> (to identify risk) and the <strong>3P model</strong> (to act on it).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0004-0000-0000-000000000001', 'faa70610-0000-0000-0000-000000000004', 'text', '{"html":"<h3>PAVE — find the risk in four buckets</h3><p>The <strong>PAVE</strong> checklist breaks risk into four categories so nothing is overlooked:</p><ul><li><strong>P — Pilot:</strong> Am I fit to fly? (Run IMSAFE — illness, medication, stress, alcohol, fatigue, emotion. Am I current and proficient?)</li><li><strong>A — Aircraft:</strong> Is the drone airworthy and adequate for this mission? (Battery state, props, firmware, payload, lighting for night.)</li><li><strong>V — enVironment:</strong> Weather, airspace, terrain, obstacles, time of day, people and structures near the site.</li><li><strong>E — External pressures:</strong> Schedule, the client, money, ''I drove two hours to get here'' — anything pushing you to fly when you otherwise wouldn''t.</li></ul><p>The most dangerous of these is often <strong>External pressure</strong>, because it makes a pilot rationalize away the other three. The classic trap is <strong>''get-there-itis''</strong> — pressing on with a flight to satisfy a deadline despite mounting hazards.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0004-0000-0000-000000000002', 'faa70610-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"External pressure is a leading cause of bad go/no-go decisions. Build in an ''out'' before you launch — decide in advance what conditions will make you cancel — so a client''s deadline can''t override your safety judgment."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0004-0000-0000-000000000003', 'faa70610-0000-0000-0000-000000000004', 'table', '{"headers":["3P step","Meaning","Example"],"rows":[["Perceive","Identify the hazards (use PAVE).","Gusty wind near a crowded park; battery only at 60%."],["Process","Evaluate the level of risk each hazard poses.","Wind plus crowd = high risk of injury if control is lost."],["Perform","Take action to mitigate or eliminate the risk.","Move the operation away from people, wait for calmer wind, or cancel."]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0004-0000-0000-000000000004', 'faa70610-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"Remember the chain: PAVE finds the risks → 3P (Perceive, Process, Perform) is the loop you run to manage them → DECIDE is your moment-to-moment decision loop in flight. IMSAFE is the ''Pilot'' part of PAVE."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0004-0000-0000-000000000005', 'faa70610-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: The PAVE checklist — four categories of risk to assess before every operation."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0004-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["PAVE identifies risk in four buckets: Pilot, Aircraft, enVironment, External pressures.","The ''Pilot'' element of PAVE is assessed with the IMSAFE checklist.","External pressure (''get-there-itis'') is a leading cause of unsafe decisions — set personal minimums and an ''out'' in advance.","The 3P model — Perceive, Process, Perform — is the loop used to manage identified risk."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70610-0000-0000-0000-000000000005', 'faa70000-0000-0000-0000-000000000006', 'Lesson 5: Radio Communications, Airport Operations & Traffic Patterns', '', ARRAY['CTAF is the self-announce frequency at non-towered airports (often the same as UNICOM); monitoring it builds traffic awareness.','Under 107.37 the remote pilot must yield the right of way to all aircraft and avoid creating a collision hazard.','Traffic-pattern legs in order: upwind, crosswind, downwind, base, final; standard turns are LEFT unless otherwise charted.','Aircraft take off and land into the wind; use a wind sock/tetrahedron/segmented circle to find the runway in use.','Watch especially for aircraft on departure and final approach — that''s where manned traffic flies low, near drone altitudes.']::text[], 5, 27, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Identify CTAF/UNICOM and use correct self-announce phraseology at a non-towered airport.','Name the legs of the standard traffic pattern and the standard direction of turns.','Determine the runway in use and avoid manned traffic on departure and final approach.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0005-0000-0000-000000000000', 'faa70610-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Why a drone pilot cares about airports</h3><p>Most sUAS sites are near <strong>non-towered (uncontrolled) airports</strong>, where there is no control tower sequencing traffic. Manned aircraft self-announce their intentions on a shared radio frequency, and a remote pilot who monitors that frequency gains powerful situational awareness — you can hear an aircraft announce it is on final approach or departing and keep your drone well clear. Remember: under <strong>107.37</strong> you must <strong>yield the right of way to all aircraft</strong> and never operate so close as to create a collision hazard.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0005-0000-0000-000000000001', 'faa70610-0000-0000-0000-000000000005', 'text', '{"html":"<h3>CTAF and UNICOM</h3><p>The <strong>CTAF (Common Traffic Advisory Frequency)</strong> is the frequency pilots use to self-announce position and intentions at a non-towered airport. It is often the same as the <strong>UNICOM</strong> (a non-government air/ground radio commonly 122.7, 122.8, 122.9, or 123.0). On a sectional chart, the CTAF is shown with a ''C'' in a magenta box near the airport data. A remote pilot is <em>not</em> required to transmit, but <strong>monitoring</strong> the CTAF to track manned traffic is excellent practice. Self-announce phraseology follows a consistent format: <em>''[Airport] traffic, [aircraft], [position/intentions], [Airport].''</em> — for example, ''Smithville traffic, Cessna Three-Four-X, on left base runway one-eight, Smithville.''</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0005-0000-0000-000000000002', 'faa70610-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"To fly in CONTROLLED airspace around a towered airport (Class B, C, D, or surface-area E) you need an airspace authorization (LAANC/DroneZone) in advance — monitoring the radio does not substitute for authorization."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0005-0000-0000-000000000003', 'faa70610-0000-0000-0000-000000000005', 'text', '{"html":"<h3>The standard traffic pattern</h3><p>Manned aircraft fly a rectangular <strong>traffic pattern</strong> around a runway. Knowing its shape tells you where to expect aircraft so you can keep your drone away from them. The legs, in order, are:</p><ul><li><strong>Upwind</strong> — climbing out aligned with the runway after takeoff.</li><li><strong>Crosswind</strong> — a 90° turn off the upwind leg.</li><li><strong>Downwind</strong> — flown parallel to the runway, opposite the landing direction (usually at pattern altitude, ~1,000 ft AGL for light aircraft).</li><li><strong>Base</strong> — a 90° turn from downwind toward the runway.</li><li><strong>Final</strong> — aligned with the runway, descending to land.</li></ul><p>Standard pattern turns are to the <strong>left</strong> unless the chart or airport markings specify right traffic. The greatest collision risk to a drone is from aircraft <strong>departing</strong> or on <strong>final approach</strong>, because that is where manned aircraft are low — in the altitude band where sUAS operate.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0005-0000-0000-000000000004', 'faa70610-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Standard left-hand traffic pattern — upwind, crosswind, downwind, base, final. Drones must avoid aircraft on departure and final, where manned traffic is low."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0005-0000-0000-000000000005', 'faa70610-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Determining the runway in use</h3><p>Aircraft take off and land <strong>into the wind</strong>, so the wind tells you which runway is active. At a non-towered field, wind direction is shown by a <strong>wind sock</strong>, a <strong>tetrahedron</strong>, or a <strong>segmented circle</strong> near the runway. If the wind sock points from the south, aircraft are likely using the south-facing runway — and you should expect departures and approaches along that line and stay clear.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0005-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["CTAF is the self-announce frequency at non-towered airports (often the same as UNICOM); monitoring it builds traffic awareness.","Under 107.37 the remote pilot must yield the right of way to all aircraft and avoid creating a collision hazard.","Traffic-pattern legs in order: upwind, crosswind, downwind, base, final; standard turns are LEFT unless otherwise charted.","Aircraft take off and land into the wind; use a wind sock/tetrahedron/segmented circle to find the runway in use.","Watch especially for aircraft on departure and final approach — that''s where manned traffic flies low, near drone altitudes."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70610-0000-0000-0000-000000000006', 'faa70000-0000-0000-0000-000000000006', 'Lesson 6: Maintenance, Preflight Inspection & Recordkeeping', '', ARRAY['Under 107.15 the sUAS must be in a condition for safe operation, and the RPIC must stop the flight if it becomes unsafe.','Follow the manufacturer''s maintenance schedule (or your own); inspect props, motors, airframe, battery, and control station; keep records.','Preflight under 107.49 covers environment/weather/airspace, crew briefing, control links, sufficient power, secured payload, and Remote ID.','Damaged props, swollen batteries, and failed links are no-go items — correct them before flight.']::text[], 6, 24, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Describe a proper sUAS maintenance program and what records to keep.','Perform a preflight inspection per 14 CFR 107.15 and 107.49.','Identify items to check before flight: aircraft condition, weather, airspace, power, and Remote ID.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0006-0000-0000-000000000000', 'faa70610-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Maintenance and condition for safe operation</h3><p>Under <strong>14 CFR 107.15</strong>, no person may operate a small UAS unless it is in a <strong>condition for safe operation</strong>, and the RPIC must <strong>discontinue the flight</strong> if it is no longer safe. Maintenance means keeping the aircraft and its components in working order. Follow the <strong>manufacturer''s maintenance instructions</strong> if provided; if none exist, establish your own scheduled-maintenance program. Inspect and service the items that wear or fail:</p><ul><li><strong>Propellers</strong> — check for cracks, nicks, chips, and warping; replace damaged props.</li><li><strong>Motors</strong> — listen and feel for roughness, grinding, or vibration.</li><li><strong>Airframe</strong> — check arms, frame, and mounts for cracks or loose hardware.</li><li><strong>Battery</strong> — inspect for swelling/puffing, damage, and correct charge; retire damaged packs.</li><li><strong>Control station, firmware, and software</strong> — keep firmware current and verify the link works.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0006-0000-0000-000000000001', 'faa70610-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"Keep maintenance and inspection RECORDS: what was done, when, and by whom. Good recordkeeping shows the aircraft was maintained and helps you spot recurring problems before they cause a failure."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0006-0000-0000-000000000002', 'faa70610-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Preflight: 107.49 familiarization, inspection, and actions</h3><p>Before each flight, <strong>14 CFR 107.49</strong> requires the RPIC to:</p><ul><li>Assess the <strong>operating environment</strong> — local weather, airspace and any flight restrictions, the location of persons and property on the surface, and other ground hazards.</li><li>Confirm that <strong>all persons</strong> directly participating understand the operation, weather, and emergency procedures (brief the crew).</li><li>Ensure all <strong>control links</strong> between the control station and the aircraft are working.</li><li>Verify there is <strong>enough power</strong> to operate for the intended time (sufficient battery, with reserve).</li><li>Confirm any object attached/carried is <strong>secure</strong> and won''t adversely affect flight.</li><li>Verify that <strong>Remote ID</strong> equipment is functioning (when required).</li></ul><p>The preflight <em>inspection</em> (107.15) confirms the airframe, props, battery, and control station are in condition for safe operation. If anything fails the check, don''t fly until it''s corrected.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0006-0000-0000-000000000003', 'faa70610-0000-0000-0000-000000000006', 'table', '{"headers":["Preflight area","Check"],"rows":[["Aircraft","Props, motors, airframe, battery (no swelling), secured payload, firmware current."],["Environment","Weather (wind, visibility, clouds), airspace class & authorizations, NOTAMs/TFRs, people/structures nearby."],["Power & links","Sufficient battery with reserve; control link verified; lost-link/RTH settings confirmed; Remote ID functioning."],["Crew & docs","Crew briefed on roles and emergencies; proof of registration available; certificate/recency in order."]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0006-0000-0000-000000000004', 'faa70610-0000-0000-0000-000000000006', 'callout', '{"type":"warning","text":"Use a written checklist for preflight. A swollen/puffed battery, a nicked prop, or a failed control link must ground the aircraft — these are not ''fly and see'' items."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0006-0000-0000-000000000005', 'faa70610-0000-0000-0000-000000000006', 'key_takeaways', '{"title":"Key Takeaways","items":["Under 107.15 the sUAS must be in a condition for safe operation, and the RPIC must stop the flight if it becomes unsafe.","Follow the manufacturer''s maintenance schedule (or your own); inspect props, motors, airframe, battery, and control station; keep records.","Preflight under 107.49 covers environment/weather/airspace, crew briefing, control links, sufficient power, secured payload, and Remote ID.","Damaged props, swollen batteries, and failed links are no-go items — correct them before flight."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70610-0000-0000-0000-000000000007', 'faa70000-0000-0000-0000-000000000006', 'Lesson 7: Emergency Procedures, Night Operations & Maintaining VLOS', '', ARRAY['Know your aircraft''s lost-link failsafe (RTH/hover/land) before launch; on low battery, land immediately; 107.21 lets you deviate from rules to meet an in-flight emergency.','Report to the FAA within 10 days (107.9) for serious injury / loss of consciousness or property damage over $500 (excluding the drone).','Fire classes: A combustibles, B liquids, C electrical, D metals; treat LiPo fires as electrical/metal and cool to prevent reignition.','Night flight needs anti-collision lighting visible 3 SM (107.29); allow ~30 min for dark adaptation, use off-center viewing, and watch for illusions like autokinesis.','Maintain unaided VLOS at all times (107.31) — FPV alone does not satisfy it; scan continuously, yield to all aircraft, and keep emergency landing zones away from people.']::text[], 7, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Respond correctly to lost link/flyaway, GPS loss, low battery, and fire emergencies.','Apply 107.9 reporting requirements and identify fire-extinguisher classes and basic first aid.','Conduct safe night operations, recognize visual illusions, and maintain visual line of sight.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000000', 'faa70610-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Planning for the emergency before it happens</h3><p>The remote PIC''s job in an emergency is to protect people and property on the ground. The single most important habit is to <strong>know your aircraft''s failsafe behavior</strong> before you launch and to position your operation so that, if control is lost, the aircraft comes down over the <strong>least-populated area</strong>. Common emergencies and the correct response:</p><ul><li><strong>Lost link / flyaway:</strong> If the radio link is lost, most aircraft execute a programmed <strong>failsafe</strong> — typically <em>return-to-home (RTH)</em>, hover, or land. Know which yours does and verify the RTH point and altitude before flight. If a true flyaway occurs, attempt to regain control and be ready to report it.</li><li><strong>Loss of GPS:</strong> The aircraft may drift or switch to a manual/attitude mode. Be prepared to fly it manually, keep it in sight, and land promptly in a clear area.</li><li><strong>Low battery:</strong> Land immediately at the nearest safe spot — don''t try to finish the mission. Always plan a battery <strong>reserve</strong> and never fly to 0%.</li><li><strong>In-flight emergency:</strong> 14 CFR 107.21 permits the RPIC to <strong>deviate from any rule of Part 107</strong> to the extent necessary to meet an in-flight emergency. If you do, you may be asked to send a written report to the FAA upon request.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000001', 'faa70610-0000-0000-0000-000000000007', 'callout', '{"type":"error","text":"Accident reporting (14 CFR 107.9): Report to the FAA within 10 calendar days if an operation results in serious injury or loss of consciousness, OR property damage (other than to the drone) where repair cost OR fair market value exceeds $500."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000002', 'faa70610-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Fire, first aid, and extinguisher classes</h3><p>LiPo batteries can enter <strong>thermal runaway</strong> — an intense, self-sustaining fire — if punctured, overcharged, over-discharged, or damaged. Keep a plan and a way to fight a small fire, and store packs in a fireproof container. Know the basic fire-extinguisher classes so you grab the right one:</p><ul><li><strong>Class A</strong> — ordinary combustibles (wood, paper, cloth).</li><li><strong>Class B</strong> — flammable liquids (fuel, oil).</li><li><strong>Class C</strong> — energized electrical equipment.</li><li><strong>Class D</strong> — combustible metals (including some lithium metal fires).</li></ul><p>Because drone fires involve electronics and lithium chemistry, an extinguisher rated for <strong>Class C (electrical)</strong> — and ideally Class D for metal fires — plus copious water/cooling to prevent reignition is the practical approach. Have basic <strong>first-aid</strong> supplies and knowledge on site; in any injury, care for people first, then preserve the scene and meet 107.9 reporting duties.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000003', 'faa70610-0000-0000-0000-000000000007', 'table', '{"headers":["Emergency","Correct response"],"rows":[["Lost link","Let the programmed failsafe (RTH/hover/land) run; know it in advance; attempt to regain control."],["Flyaway","Try to regain control; track the aircraft; be ready to report; ensure it endangers no one."],["GPS loss","Switch to manual flight, keep VLOS, land promptly in a clear area."],["Low battery","Land immediately at the nearest safe location; never push past reserve."],["Fire (LiPo)","Use a Class C/D-appropriate extinguisher; cool to prevent reignition; keep people clear."]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000004', 'faa70610-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Night operations and visual illusions</h3><p>Since the 2021 rule, night flight is allowed <strong>without a waiver</strong> if the aircraft has <strong>anti-collision lighting visible for at least 3 statute miles</strong> with a flash rate sufficient to avoid a collision (107.29), and the remote pilot has completed the required training. At night, plan for degraded human vision: <strong>night vision takes ~30 minutes to adapt</strong>, depth perception and the ability to judge the drone''s distance and attitude are reduced, and a steady light far away can be hard to distinguish from a moving one. Use <strong>off-center viewing and active scanning</strong>, survey the area in daylight beforehand, and verify all lighting works before launch. Watch for <strong>illusions</strong> — a single light against a dark background can appear to move (autokinesis), and isolated lights make distance hard to judge.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000005', 'faa70610-0000-0000-0000-000000000007', 'callout', '{"type":"warning","text":"Maintain Visual Line of Sight (107.31): The remote PIC, person manipulating the controls, and any VO must be able to see the unmanned aircraft with vision UNAIDED (corrective lenses allowed) throughout the flight. First-person-view (FPV) goggles do NOT satisfy VLOS — use a VO if you fly FPV. Keep the aircraft close enough to know its location, attitude, altitude, and direction, and to see and avoid traffic."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Visual scanning, VLOS, and operating near people</h3><p>Continuously and systematically <strong>scan the airspace</strong> for other aircraft — yield to all of them (107.37). Use a <strong>visual observer</strong> to extend your coverage on large or busy sites. Keep the aircraft within unaided VLOS at all times; if you momentarily lose sight, regain it immediately or land. When operating <strong>near people or structures</strong>, position yourself so the aircraft is never directly over non-participants unless you meet an Operations Over People category, keep a safe buffer, and plan your emergency landing zones away from crowds. Security matters too: be alert to <strong>suspicious activity</strong> near sensitive sites, respect restricted areas and TFRs, and protect any sensitive imagery you collect.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70620-0007-0000-0000-000000000007', 'faa70610-0000-0000-0000-000000000007', 'key_takeaways', '{"title":"Key Takeaways","items":["Know your aircraft''s lost-link failsafe (RTH/hover/land) before launch; on low battery, land immediately; 107.21 lets you deviate from rules to meet an in-flight emergency.","Report to the FAA within 10 days (107.9) for serious injury / loss of consciousness or property damage over $500 (excluding the drone).","Fire classes: A combustibles, B liquids, C electrical, D metals; treat LiPo fires as electrical/metal and cool to prevent reignition.","Night flight needs anti-collision lighting visible 3 SM (107.29); allow ~30 min for dark adaptation, use off-center viewing, and watch for illusions like autokinesis.","Maintain unaided VLOS at all times (107.31) — FPV alone does not satisfy it; scan continuously, yield to all aircraft, and keep emergency landing zones away from people."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000001', 'Crew Resource Management (CRM)', 'The effective use of all available resources — human (VO, crew, ATC), hardware, and information — to conduct a flight safely.', 'It''s about communication and situational awareness, not just having a big crew.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000002', 'Remote PIC authority (14 CFR 107.19)', 'The Remote Pilot in Command is directly responsible for, and is the final authority over, the operation; must ensure compliance and be able to direct/immediately control the aircraft.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000003', 'Visual Observer (VO)', 'An optional crew member (no certificate required) who helps the RPIC keep the aircraft in sight and scan for traffic; must be able to communicate with the RPIC.', 'Optional under 107.33.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000004', 'One-aircraft-per-pilot rule (107.35)', 'A person may not operate or act as remote PIC for more than one unmanned aircraft at the same time.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000005', '8 hours bottle-to-throttle (107.27/107.57)', 'A remote pilot may not operate within 8 hours of consuming alcohol, while under the influence, or with a blood-alcohol concentration of 0.04% or greater.', 'Two numbers: 8 hours and 0.04 BAC.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000006', 'IMSAFE checklist', 'A pilot self-assessment: Illness, Medication, Stress, Alcohol, Fatigue, Emotion.', 'It''s about the PILOT, not the aircraft.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000007', 'Hyperventilation', 'Abnormally rapid/deep breathing (often from stress) that expels too much CO2, causing dizziness, tingling, and visual impairment; corrected by slowing the breathing rate.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000008', 'Dark adaptation', 'Night vision takes about 30 minutes to fully develop and relies on off-center (peripheral) viewing; bright light destroys it quickly.', 'About 30 minutes.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000009', 'Fatigue', 'Acute or chronic tiredness that degrades attention, reaction time, and judgment — a leading human-factor hazard. Don''t fly tired.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000010', 'Aeronautical Decision-Making (ADM)', 'A systematic approach to consistently determining the best course of action in response to a given set of circumstances.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000011', 'Anti-Authority — antidote', 'Attitude: ''Don''t tell me!'' (the rules don''t apply to me). Antidote: ''Follow the rules. They are usually right.''', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000012', 'Impulsivity — antidote', 'Attitude: ''Do something quickly!'' (act on the first thought). Antidote: ''Not so fast. Think first.''', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000013', 'Invulnerability — antidote', 'Attitude: ''It won''t happen to me.'' Antidote: ''It could happen to me.''', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000014', 'Macho — antidote', 'Attitude: ''I can do it'' (prove I''m better, take risks). Antidote: ''Taking chances is foolish.''', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000015', 'Resignation — antidote', 'Attitude: ''What''s the use?'' (I''m not in control). Antidote: ''I''m not helpless. I can make a difference.''', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000016', 'DECIDE model', 'A decision loop: Detect, Estimate, Choose, Identify, Do, Evaluate.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000017', 'PAVE checklist', 'A risk-identification tool with four categories: Pilot, Aircraft, enVironment, and External pressures.', 'The ''P'' (Pilot) is checked with IMSAFE.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000018', '3P model', 'A risk-management process: Perceive the hazards, Process the level of risk, Perform a mitigating action.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000019', 'External pressures (the ''E'' in PAVE)', 'Outside influences — schedule, client, money, sunk cost — that push a pilot to fly when conditions say otherwise; the source of ''get-there-itis.''', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000020', 'Get-there-itis', 'The unsafe tendency to continue a flight to meet a deadline or goal despite increasing hazards; a product of external pressure.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000021', 'CTAF (Common Traffic Advisory Frequency)', 'The radio frequency used by pilots to self-announce position and intentions at a non-towered airport; often the same as the UNICOM frequency.', 'Shown as a ''C'' in a magenta box on a sectional.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000022', 'UNICOM', 'A non-government air/ground communication station at some airports (commonly 122.7/122.8/122.9/123.0); frequently serves as the CTAF.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000023', 'Traffic pattern legs', 'Upwind, crosswind, downwind, base, and final — the rectangular path manned aircraft fly around a runway; standard turns are to the left.', 'Five legs, left turns by default.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000024', 'Runway in use', 'Determined by wind direction (aircraft take off and land into the wind), indicated by a wind sock, tetrahedron, or segmented circle.', 'Into the wind.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000025', 'Right of way (107.37)', 'A remote pilot must yield the right of way to all other aircraft and may not operate so close as to create a collision hazard.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000026', 'Condition for safe operation (107.15)', 'No one may operate an sUAS unless it is in a condition for safe operation; the RPIC must discontinue the flight if it becomes unsafe.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000027', 'Preflight actions (107.49)', 'Before flight the RPIC must assess weather/airspace/ground hazards, brief crew, verify control links, ensure sufficient power, secure payloads, and confirm Remote ID is working.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000028', 'Propeller inspection', 'Check props for cracks, nicks, chips, and warping before each flight; replace any damaged propeller.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000029', 'Swollen (puffed) battery', 'A LiPo pack that has swelled is damaged and a fire risk — retire it immediately; never charge or fly a swollen battery.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000006', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000030', 'Lost link / failsafe', 'When the control link is lost, the aircraft runs its programmed failsafe — typically return-to-home, hover, or land. Know and verify this behavior before every flight.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000031', 'In-flight emergency deviation (107.21)', 'The remote PIC may deviate from any rule of Part 107 to the extent necessary to meet an in-flight emergency; a written report may be required upon FAA request.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000032', 'Accident reporting (107.9)', 'Report to the FAA within 10 calendar days for serious injury/loss of consciousness, or property damage (other than the drone) exceeding $500 in repair cost or fair market value.', '10 days / $500.', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000033', 'Fire-extinguisher classes', 'A = ordinary combustibles; B = flammable liquids; C = energized electrical; D = combustible metals. Drone/LiPo fires are treated as electrical (C) and/or metal (D).', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000034', 'Night anti-collision lighting (107.29)', 'For civil twilight and night operations, the aircraft must have anti-collision lighting visible for at least 3 statute miles with an adequate flash rate.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70640-0000-0000-0000-000000000035', 'Visual Line of Sight (107.31)', 'The RPIC, person manipulating controls, and any VO must keep the aircraft in sight with vision unaided (corrective lenses OK) throughout the flight; FPV alone does not satisfy VLOS.', NULL, 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000001', 'Who is directly responsible for, and the final authority over, a small UAS operation conducted under Part 107?', 'multiple_choice', '["The remote pilot in command (RPIC)","The person manipulating the flight controls","The visual observer"]'::jsonb, 'The remote pilot in command (RPIC)', 'Under 14 CFR 107.19, the RPIC is directly responsible for, and is the final authority over, the operation. A non-certificated person may manipulate the controls only under the RPIC''s direct supervision, and a VO only assists.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000002', 'Crew Resource Management (CRM) is best described as:', 'multiple_choice', '["The effective use of all available resources — people, hardware, and information — to operate safely","A requirement that every operation use at least two certificated remote pilots","The manufacturer''s recommended maintenance schedule for the aircraft"]'::jsonb, 'The effective use of all available resources — people, hardware, and information — to operate safely', 'CRM means making effective use of all resources available to conduct the flight safely. It does not require multiple pilots, and it is unrelated to a maintenance schedule.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000003', 'A person who does not hold a remote pilot certificate wishes to fly the drone. Under Part 107, this is permitted only if:', 'multiple_choice', '["A certificated remote PIC directly supervises and can immediately take direct control of the aircraft","The person has passed the TRUST recreational test","The flight stays below 100 feet AGL"]'::jsonb, 'A certificated remote PIC directly supervises and can immediately take direct control of the aircraft', 'A non-certificated person may manipulate the controls only when an RPIC supervises and can immediately take direct control. TRUST is for recreational flying, and altitude does not change the certification requirement.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000004', 'Under Part 107, a remote pilot may NOT operate a small UAS:', 'multiple_choice', '["Within 8 hours of consuming alcohol, while impaired, or with a blood-alcohol concentration of 0.04% or greater","Within 4 hours of consuming alcohol, or with a BAC of 0.08% or greater","Within 12 hours of consuming alcohol, or with a BAC of 0.02% or greater"]'::jsonb, 'Within 8 hours of consuming alcohol, while impaired, or with a blood-alcohol concentration of 0.04% or greater', '14 CFR 107.27/107.57 set the limits at 8 hours bottle-to-throttle, no operating while under the influence, and a BAC of 0.04% or greater. The other options use incorrect numbers.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000005', 'A remote pilot becomes anxious before a difficult job and begins breathing rapidly, then feels lightheaded and tingling in the fingers. The most likely cause and corrective action is:', 'multiple_choice', '["Hyperventilation; consciously slow the breathing rate until normal breathing returns","Hypoxia; descend the aircraft immediately","Dehydration; the pilot should stop scanning for traffic"]'::jsonb, 'Hyperventilation; consciously slow the breathing rate until normal breathing returns', 'Rapid breathing from stress expels too much carbon dioxide, causing lightheadedness and tingling — hyperventilation. The fix is to slow the breathing rate. Hypoxia (oxygen deficiency from altitude) and dehydration are different conditions.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000006', 'Which checklist is used by a pilot to assess his or her OWN fitness for flight?', 'multiple_choice', '["IMSAFE (Illness, Medication, Stress, Alcohol, Fatigue, Emotion)","PAVE (Pilot, Aircraft, enVironment, External pressures)","DECIDE (Detect, Estimate, Choose, Identify, Do, Evaluate)"]'::jsonb, 'IMSAFE (Illness, Medication, Stress, Alcohol, Fatigue, Emotion)', 'IMSAFE is the personal-fitness self-check. PAVE is a broader risk-identification tool (the pilot is only one element), and DECIDE is a decision-making loop.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000007', 'A pilot took an over-the-counter antihistamine for allergies an hour before a planned operation. What is the correct action?', 'multiple_choice', '["Do not fly if the medication could impair faculties in a way contrary to safety","Fly normally, because only prescription drugs are restricted under Part 107","Fly, but limit the operation to under 200 feet AGL"]'::jsonb, 'Do not fly if the medication could impair faculties in a way contrary to safety', 'Part 107 prohibits operating while using ANY drug — over-the-counter or prescription — that affects faculties contrary to safety. Many antihistamines cause drowsiness, so the pilot should not fly. Altitude does not mitigate impairment.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000008', 'Aeronautical Decision-Making (ADM) is best defined as:', 'multiple_choice', '["A systematic approach to consistently determining the best course of action for a given set of circumstances","A federal requirement to file a flight plan before every operation","The manufacturer''s procedure for calibrating the aircraft''s compass"]'::jsonb, 'A systematic approach to consistently determining the best course of action for a given set of circumstances', 'ADM is the systematic process pilots use to make sound decisions. It is not a flight-plan requirement or a calibration procedure.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000009', 'A remote pilot decides to fly in airspace that requires an authorization without obtaining one, reasoning that ''those rules are excessive for a quick job like this.'' Which hazardous attitude is this, and what is its antidote?', 'multiple_choice', '["Anti-Authority; ''Follow the rules. They are usually right.''","Macho; ''Taking chances is foolish.''","Resignation; ''I''m not helpless. I can make a difference.''"]'::jsonb, 'Anti-Authority; ''Follow the rules. They are usually right.''', 'Disregarding rules because they seem unnecessary is the Anti-Authority (''Don''t tell me!'') attitude; the antidote is ''Follow the rules. They are usually right.'' Macho is about proving skill; Resignation is feeling not in control.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000010', 'Which is the correct antidote for the MACHO hazardous attitude?', 'multiple_choice', '["Taking chances is foolish.","It could happen to me.","Not so fast. Think first."]'::jsonb, 'Taking chances is foolish.', 'Macho (''I can do it,'' taking unnecessary risks to prove skill) is countered by ''Taking chances is foolish.'' ''It could happen to me'' is the Invulnerability antidote; ''Not so fast. Think first.'' is the Impulsivity antidote.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000011', 'A pilot feels rushed by a waiting client and launches before completing the preflight, acting on the first idea that comes to mind. Which hazardous attitude is displayed, and what is its antidote?', 'multiple_choice', '["Impulsivity; ''Not so fast. Think first.''","Resignation; ''I''m not helpless. I can make a difference.''","Invulnerability; ''It could happen to me.''"]'::jsonb, 'Impulsivity; ''Not so fast. Think first.''', 'Acting immediately on the first thought without thinking it through is Impulsivity; the antidote is ''Not so fast. Think first.''', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000012', 'When a series of problems overwhelms a pilot and they think ''What''s the use? Whatever happens, happens,'' the correct antidote is:', 'multiple_choice', '["I''m not helpless. I can make a difference.","Follow the rules. They are usually right.","Taking chances is foolish."]'::jsonb, 'I''m not helpless. I can make a difference.', 'That thought is the Resignation attitude; its antidote is ''I''m not helpless. I can make a difference.'' The others are antidotes for Anti-Authority and Macho.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000013', 'The PAVE checklist divides risk into four categories. What do the letters represent?', 'multiple_choice', '["Pilot, Aircraft, enVironment, External pressures","Power, Altitude, Visibility, Endurance","Pilot, Airspace, Visibility, Equipment"]'::jsonb, 'Pilot, Aircraft, enVironment, External pressures', 'PAVE = Pilot, Aircraft, enVironment, and External pressures — a structured way to identify risk before and during flight.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000014', 'A remote pilot drove two hours to a job site and the client is pressing to finish today, even though winds are picking up beyond the pilot''s comfort level. Which element of PAVE is most directly creating risk, and what is the danger?', 'multiple_choice', '["External pressures; it can lead to ''get-there-itis'' and an unsafe go decision","Aircraft; the drone is not airworthy","Pilot; the pilot is intoxicated"]'::jsonb, 'External pressures; it can lead to ''get-there-itis'' and an unsafe go decision', 'Schedule, sunk cost, and client pressure are External pressures, the classic driver of ''get-there-itis.'' Nothing indicates the aircraft is unairworthy or the pilot is intoxicated.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000015', 'The 3P risk-management model consists of which three steps?', 'multiple_choice', '["Perceive, Process, Perform","Plan, Prepare, Proceed","Predict, Prevent, Protect"]'::jsonb, 'Perceive, Process, Perform', 'The 3P model is Perceive the hazards, Process the level of risk, and Perform a risk-mitigating action.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000016', 'While operating near a non-towered airport, the best way for a remote pilot to maintain awareness of nearby manned traffic is to:', 'multiple_choice', '["Monitor the CTAF (Common Traffic Advisory Frequency)","Call the nearest control tower for a clearance","File a flight plan with Flight Service"]'::jsonb, 'Monitor the CTAF (Common Traffic Advisory Frequency)', 'At a non-towered airport, pilots self-announce on the CTAF. Monitoring it lets the remote pilot anticipate manned traffic. There is no tower to call, and Part 107 does not require a flight plan.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000017', 'What are the legs of a standard airport traffic pattern, in order?', 'multiple_choice', '["Upwind, crosswind, downwind, base, final","Departure, transition, arrival, approach, landing","Final, base, downwind, crosswind, upwind, repeated clockwise"]'::jsonb, 'Upwind, crosswind, downwind, base, final', 'The standard pattern legs in sequence are upwind, crosswind, downwind, base, and final, with left turns unless otherwise charted.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000018', 'At a non-towered airport, how does a remote pilot determine which runway manned aircraft are most likely using?', 'multiple_choice', '["By the wind direction, shown by a wind sock, tetrahedron, or segmented circle (aircraft take off and land into the wind)","By the lowest-numbered runway, which is always active","By the magenta box on the sectional chart"]'::jsonb, 'By the wind direction, shown by a wind sock, tetrahedron, or segmented circle (aircraft take off and land into the wind)', 'Aircraft take off and land into the wind, so wind indicators reveal the runway in use. Runways are not chosen by number, and the magenta box denotes the CTAF, not the active runway.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000019', 'When operating a drone near an airport, manned aircraft pose the greatest collision risk when they are:', 'multiple_choice', '["On departure or final approach, where they fly low — near typical drone altitudes","At cruising altitude well above 400 feet AGL","Parked on the ramp"]'::jsonb, 'On departure or final approach, where they fly low — near typical drone altitudes', 'Aircraft are lowest during departure and final approach, putting them in the same altitude band as sUAS. The remote pilot must yield and stay clear there.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000005', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000020', 'Under 14 CFR 107.15, what must the remote PIC do if, during flight, the aircraft is no longer in a condition for safe operation?', 'multiple_choice', '["Discontinue the flight","Continue to the planned landing point regardless","Climb to 400 feet AGL and hover"]'::jsonb, 'Discontinue the flight', '107.15 requires the sUAS to be in a condition for safe operation, and the RPIC must discontinue the flight if it is no longer safe.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000021', 'During a preflight inspection, a remote pilot notices the LiPo battery is swollen (puffed). The correct action is to:', 'multiple_choice', '["Retire the battery immediately and not use it; do not charge or fly it","Fly a short mission to drain it, then dispose of it","Charge it fully first to reduce the swelling"]'::jsonb, 'Retire the battery immediately and not use it; do not charge or fly it', 'A swollen LiPo is damaged and a fire risk. It must be retired immediately — never charged or flown. Draining or charging it increases the danger.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000022', 'Which of the following is required as part of the preflight familiarization, inspection, and actions under 14 CFR 107.49?', 'multiple_choice', '["Assess the operating environment, ensure control links work, verify sufficient power, and confirm Remote ID is functioning","File a notice with the nearest air traffic control tower","Obtain a third-class medical certificate"]'::jsonb, 'Assess the operating environment, ensure control links work, verify sufficient power, and confirm Remote ID is functioning', '107.49 requires assessing weather/airspace/ground hazards, briefing crew, verifying control links and sufficient power, securing payloads, and confirming Remote ID. No tower notice or medical certificate is required under Part 107.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000006', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000023', 'A remote pilot loses the control link to the aircraft mid-flight. What should the pilot have done BEFORE launch to prepare for this?', 'multiple_choice', '["Know and verify the aircraft''s lost-link failsafe behavior (e.g., return-to-home altitude and point)","Disable the return-to-home feature to allow manual recovery","Plan to fly the drone to 0% battery to maximize coverage"]'::jsonb, 'Know and verify the aircraft''s lost-link failsafe behavior (e.g., return-to-home altitude and point)', 'Knowing the failsafe (RTH/hover/land) and verifying the RTH point and altitude before flight is essential. Disabling RTH and flying to 0% battery both increase risk.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000024', 'An operation results in a bystander being knocked unconscious. Under 14 CFR 107.9, the remote PIC must report this to the FAA within:', 'multiple_choice', '["10 calendar days","24 hours","30 calendar days"]'::jsonb, '10 calendar days', '107.9 requires reporting within 10 calendar days for any serious injury or loss of consciousness, or for property damage (other than to the drone) exceeding $500.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000025', 'A drone operation causes property damage to a parked car. The repair will cost $350 and the car''s fair market value far exceeds that. Must this be reported to the FAA under 107.9?', 'multiple_choice', '["No — the repair cost does not exceed $500 and no serious injury occurred","Yes — all property damage must always be reported","Yes — because a vehicle was involved"]'::jsonb, 'No — the repair cost does not exceed $500 and no serious injury occurred', 'Reporting is required only if there is serious injury/loss of consciousness or property damage over $500 (by repair cost or fair market value). A $350 repair with no injury does not trigger the report.', 'hard', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000026', 'Per 14 CFR 107.21, what may a remote PIC do when confronted with an in-flight emergency?', 'multiple_choice', '["Deviate from any rule of Part 107 to the extent necessary to meet the emergency","Continue the operation exactly as planned, since no deviation is ever allowed","Hand control to a non-certificated bystander"]'::jsonb, 'Deviate from any rule of Part 107 to the extent necessary to meet the emergency', '107.21 allows the RPIC to deviate from any rule of Part 107 to the extent necessary to meet an in-flight emergency; a written report may be required upon FAA request.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000027', 'To operate at night under Part 107 without a waiver, the small unmanned aircraft must:', 'multiple_choice', '["Have anti-collision lighting visible for at least 3 statute miles with a flash rate sufficient to avoid a collision","Be flown below 100 feet AGL at all times","Carry a landing light visible for 1 statute mile"]'::jsonb, 'Have anti-collision lighting visible for at least 3 statute miles with a flash rate sufficient to avoid a collision', 'Under 107.29, night and civil-twilight operations require anti-collision lighting visible for at least 3 statute miles with an adequate flash rate, plus completion of the required training.', 'easy', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000028', 'A remote pilot wants to fly using FPV (first-person-view) goggles. To remain compliant with the visual-line-of-sight rule (107.31), the pilot must:', 'multiple_choice', '["Use a visual observer who maintains unaided sight of the aircraft at all times","Simply keep the aircraft within 1,000 feet","Do nothing extra — FPV goggles satisfy the VLOS requirement"]'::jsonb, 'Use a visual observer who maintains unaided sight of the aircraft at all times', 'VLOS requires the aircraft be seen with vision unaided (corrective lenses OK). FPV goggles do not satisfy VLOS, so a visual observer must keep the aircraft in sight.', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000029', 'A small electrical fire starts in the drone''s electronics after a hard landing. Which extinguisher class is appropriate for energized electrical equipment?', 'multiple_choice', '["Class C","Class A","Class K"]'::jsonb, 'Class C', 'Class C extinguishers are rated for energized electrical fires. Class A is for ordinary combustibles; Class K is for cooking oils/fats. (Lithium-metal fires also involve Class D and require cooling to prevent reignition.)', 'medium', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70630-0000-0000-0000-000000000030', 'While maintaining VLOS at night, a remote pilot stares directly at the aircraft''s single light and it appears to drift, even though the drone is holding a steady hover. This illusion is best avoided by:', 'multiple_choice', '["Using off-center viewing and active scanning instead of staring at one fixed point","Increasing the brightness of the control-station screen","Removing corrective lenses to sharpen night vision"]'::jsonb, 'Using off-center viewing and active scanning instead of staring at one fixed point', 'Staring at a single light in the dark can produce autokinesis (apparent motion). Off-center viewing and active scanning preserve night vision and reduce the illusion. Bright screens destroy dark adaptation, and removing needed lenses degrades vision.', 'hard', 'faa70000-0000-0000-0000-000000000006', 'faa70610-0000-0000-0000-000000000007', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70710-0000-0000-0000-000000000001', 'faa70000-0000-0000-0000-000000000007', 'Lesson 1: How the UAG Exam Works & Test Strategy', '', ARRAY['The UAG exam is 60 multiple-choice questions, 3 options each, 120 minutes, 70% to pass, taken at a PSI center.','Pace at ~2 minutes per question; flag-and-return, answer easy questions first, and never leave a blank.','Eliminate distractors: knowing a hard number kills the plausible-but-wrong options.','Chart questions: locate the point, read the airspace color, decide if authorization is needed, scan for SUA/obstacles/TFRs.','METAR questions: decode left to right; convert Zulu to local; small temp–dewpoint spread means fog/low cloud likely.','It is closed-book; bring a photo ID, arrive early, and rely on memorized rules.']::text[], 1, 35, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['State the format, number of questions, passing score, time limit, and cost of the UAG knowledge exam.','Apply pacing, flag-and-return, and distractor-elimination strategies to maximize score.','Use a repeatable approach for chart-reading and METAR-decoding questions.','Identify what to bring to the testing center and what to expect on test day.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000000', 'faa70710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The test you are preparing for</h3><p>The exam that earns you a Remote Pilot Certificate is the <strong>Unmanned Aircraft General &ndash; Small (UAG)</strong> aeronautical knowledge test. It is an objective, <strong>multiple-choice</strong> test with a single correct answer and <strong>three options (A, B, C)</strong> per question. You take it in person at a <strong>PSI Services</strong> testing center, and the result is reported on a knowledge test report you will use to file your certificate application.</p><p>Everything in Modules 1&ndash;6 maps to one of the five FAA knowledge areas tested here. This module''s job is to consolidate that material, drill the high-yield numbers, and put you through a full-length practice pool so the real test feels familiar.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000001', 'faa70710-0000-0000-0000-000000000001', 'table', '{"headers":["Item","Value"],"rows":[["Test name / code","Unmanned Aircraft General – Small (UAG)"],["Number of questions","60 multiple-choice (3 options each)"],["Time limit","2 hours (120 minutes)"],["Passing score","70% (about 42 of 60 correct)"],["Pacing","~2 minutes per question"],["Where taken","PSI Services testing centers"],["Test fee","about $175 (set by PSI; subject to change)"],["Result validity","Knowledge test report valid 24 calendar months for applying"],["Retake after failing","Wait 14 calendar days to retake (as of this writing)"],["Prior pilot certificate","Not required for the initial UAG test"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000002', 'faa70710-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"You need 70% to pass, so you can miss up to 18 of 60 questions. Aim for consistently above 85% on practice tests before scheduling, so you have a comfortable margin on test day."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000003', 'faa70710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Clock management and flag-and-return</h3><p>Sixty questions in 120 minutes is roughly <strong>two minutes per question</strong>, which is generous if you do not stall. The single most common avoidable mistake is burning ten minutes on one hard chart question and then rushing the easy ones at the end. The fix is <strong>flag-and-return</strong>: if a question is not yielding within about a minute, pick your best guess, <em>flag it</em>, and move on. Make a fast first pass through the whole test capturing every easy point, then circle back to the flagged questions with the time you have left.</p><ul><li><strong>Never leave a question blank.</strong> There is no penalty for guessing, so a flagged question still gets your best answer in case you run out of time.</li><li><strong>Answer easy questions first.</strong> Banking the points you are sure of protects your score from a clock crunch.</li><li><strong>Trust your first instinct</strong> unless you find a concrete reason (a misread number, a rule you now recall) to change it.</li></ul>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000004', 'faa70710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Eliminate distractors</h3><p>With only three options, eliminating even one obviously wrong answer raises a guess from 33% to 50%. FAA distractors are usually <em>plausible</em> &mdash; they encode a common misconception or a number that is close but wrong (for example, \"500 ft AGL\" instead of \"400 ft AGL\", or \"5 statute miles\" instead of \"3 statute miles\"). When you know the hard number or the rule, the two wrong answers tend to fall away. When you are unsure:</p><ul><li>Cross out any option that violates a number you <em>do</em> know.</li><li>Watch for absolutes like \"always\" / \"never\" &mdash; aviation rules usually have conditions.</li><li>For \"which is required\" questions, ask whether the option is a legal requirement or merely a good practice; the exam distinguishes the two.</li></ul>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000005', 'faa70710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>A method for chart questions</h3><p>The UAG test now uses <strong>current, real-world chart excerpts</strong> (Sectional, Instrument Approach, and Low Altitude Enroute charts) that are not the legacy supplement figures, so you must be able to read live-style charts rather than memorize old figures. Use a fixed workflow for every chart question:</p><ol><li><strong>Locate the point</strong> the question asks about (by airport name or latitude/longitude tick marks).</li><li><strong>Identify the airspace</strong> at that point from the ring or vignette color (solid blue = B, solid magenta = C, dashed blue = D, dashed magenta = E to surface, faded magenta/blue = E floor at 700/1,200 ft AGL).</li><li><strong>Decide if authorization is needed</strong>: controlled airspace (B, C, D, surface-area E) requires an authorization; Class G does not.</li><li><strong>Scan for traps</strong>: special use airspace, obstacles, the Maximum Elevation Figure, and any TFR/NOTAM.</li></ol>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000006', 'faa70710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>A method for METAR questions</h3><p>Decode a METAR <strong>left to right, in order</strong>, and the question usually asks about just one element. Read the groups in sequence: report type, station, date/time (Zulu), modifier, <strong>wind</strong> (direction true / speed / gusts in knots), <strong>visibility</strong> (statute miles), weather phenomena, <strong>sky condition</strong> (heights in hundreds of feet AGL; ceiling = lowest BKN or OVC), <strong>temperature/dewpoint</strong> (°C, M = minus), and <strong>altimeter</strong> (inHg). Convert Zulu to local before answering time questions, and remember a small temperature&ndash;dewpoint spread signals fog or low cloud.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'table', '{"headers":["Bring to the test center","Why"],"rows":[["Government-issued photo ID","Required to check in; name must match your registration"],["Your FTN / IACRA confirmation (helpful)","Speeds linking your test result to your application"],["Knowledge of the rules; no notes allowed","It is a closed-book test; the FAA supplement is provided"],["Arrive early","Late arrival can forfeit your appointment and fee"]]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000008', 'faa70710-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"The test is closed-book. You may NOT bring your own notes, phone, or smartwatch into the testing room. PSI provides the official FAA Airman Knowledge Testing Supplement (the chart and figure booklet) and on-screen tools. Do not plan to look anything up."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0001-0000-0000-000000000009', 'faa70710-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The UAG exam is 60 multiple-choice questions, 3 options each, 120 minutes, 70% to pass, taken at a PSI center.","Pace at ~2 minutes per question; flag-and-return, answer easy questions first, and never leave a blank.","Eliminate distractors: knowing a hard number kills the plausible-but-wrong options.","Chart questions: locate the point, read the airspace color, decide if authorization is needed, scan for SUA/obstacles/TFRs.","METAR questions: decode left to right; convert Zulu to local; small temp–dewpoint spread means fog/low cloud likely.","It is closed-book; bring a photo ID, arrive early, and rely on memorized rules."]}'::jsonb, 9);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70710-0000-0000-0000-000000000002', 'faa70000-0000-0000-0000-000000000007', 'Lesson 2: Regulations & Operations Cram Sheet', '', ARRAY['Memorize 107.51: 400 ft AGL, 87 kt / 100 mph, 3 SM visibility, 500 below / 2,000 horizontal.','107.9: report within 10 calendar days for serious injury/loss of consciousness or over-$500 property damage (excluding the drone).','Alcohol: 8 hours bottle-to-throttle, BAC below 0.04%; one aircraft per pilot; yield to all other aircraft.','Operations over people: Cat 1 = 0.55 lb, Cat 2 = 11 ft-lb, Cat 3 = 25 ft-lb, Cat 4 = airworthiness certificate.','Know the five hazardous attitudes and antidotes verbatim; use IMSAFE/PAVE/DECIDE for risk decisions.','Register every drone individually, mark the number externally, and comply with Remote ID (since Sept 16, 2023).']::text[], 2, 40, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Recall the key Part 107 operating limitations and rule numbers from memory.','State the 107.9 accident-reporting thresholds and the alcohol/drug limits.','Reproduce the five hazardous attitudes and their antidotes verbatim.','Summarize PIC responsibilities, certification, registration, and Remote ID requirements.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000000', 'faa70710-0000-0000-0000-000000000002', 'text', '{"html":"<h3>The numbers the test loves</h3><p>Regulations and Operations together are the heart of the exam &mdash; Operations alone is the single largest knowledge area (roughly 35&ndash;45% of questions), and Regulations is another large block. Most of the points here come down to a small set of <strong>hard numbers</strong> and a handful of frameworks you can memorize cold. Drill the table below until each value is automatic.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000001', 'faa70710-0000-0000-0000-000000000002', 'table', '{"headers":["Limit / rule","Value","Rule"],"rows":[["Maximum altitude","400 ft AGL (or 400 ft above a structure within a 400-ft radius of it)","107.51"],["Maximum groundspeed","87 knots (100 mph)","107.51"],["Minimum flight visibility","3 statute miles from the control station","107.51"],["Cloud clearance","500 ft below and 2,000 ft horizontal","107.51"],["Anti-collision lighting (night/twilight)","Visible for at least 3 statute miles","107.29"],["Visual line of sight","RPIC/VO must see the aircraft unaided (corrective lenses OK)","107.31"],["Aircraft per pilot","One unmanned aircraft per remote pilot at a time","107.35"],["Right of way","Yield to all other aircraft (manned and unmanned)","107.37"],["Operation from moving vehicle","Only over a sparsely populated area","107.25"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000002', 'faa70710-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"High-yield trap: minimum visibility is 3 statute miles and cloud clearance is 500 ft below / 2,000 ft horizontal. Distractors swap these for ''5 SM'' or ''1,000 ft below'' — know the exact numbers."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000003', 'faa70710-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Accident reporting &mdash; 14 CFR 107.9</h3><p>This single rule shows up almost every test. Report to the FAA <strong>no later than 10 calendar days</strong> after any operation that results in <strong>at least</strong>:</p><ul><li><strong>Serious injury</strong> to any person, or <strong>any loss of consciousness</strong>; OR</li><li><strong>Damage to property other than the small unmanned aircraft itself</strong>, <em>unless</em> the cost of repair (materials plus labor) does not exceed <strong>$500</strong>, or the fair market value of the property does not exceed $500.</li></ul><p>Memory hook: <strong>10 days, $500, serious injury or loss of consciousness</strong>. Damage to the drone itself never triggers a report.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000004', 'faa70710-0000-0000-0000-000000000002', 'table', '{"headers":["Topic","Key value to memorize"],"rows":[["Accident report (107.9)","Within 10 calendar days if serious injury / loss of consciousness, or property damage over $500 (excluding the drone)"],["Alcohol (107.27/107.57)","8 hours bottle-to-throttle; BAC below 0.04%; never under the influence"],["Eligibility (107.61)","At least 16 years old; read/speak/write/understand English; sound physical & mental condition; TSA vetting"],["Recurrent training","Free online course every 24 calendar months to keep knowledge recency"],["Registration","Every Part 107 drone registered individually via FAADroneZone; mark number on the exterior; carry proof"],["Remote ID","Required since Sept 16, 2023: standard RID drone, broadcast module, or fly within a FRIA"],["Hazardous materials (107.36)","Carriage of hazardous material is prohibited"],["Dropping objects (107.23)","No careless/reckless operation; no dropping an object that creates a hazard"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000005', 'faa70710-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Operations over people &mdash; Categories 1&ndash;4</h3><p>Subpart D sorts flights over people by likely injury severity. Know the gateway criterion for each category.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000006', 'faa70710-0000-0000-0000-000000000002', 'table', '{"headers":["Category","Key criterion"],"rows":[["Category 1","Weighs 0.55 lb (250 g) or less, no exposed rotating parts that can lacerate, meets Remote ID"],["Category 2","Will not cause injury equal to or greater than an 11 ft-lb kinetic-energy transfer; FAA-accepted means of compliance"],["Category 3","Will not cause injury equal to or greater than a 25 ft-lb transfer; no sustained flight over open-air assemblies of people"],["Category 4","Has an airworthiness certificate and is operated per its approved Flight Manual"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Aeronautical Decision-Making and the five hazardous attitudes</h3><p>ADM is a systematic approach to consistently choosing the best course of action. Self-assessment tools include <strong>IMSAFE</strong> (Illness, Medication, Stress, Alcohol, Fatigue, Emotion), <strong>PAVE</strong> (Pilot, Aircraft, enVironment, External pressures), and the <strong>DECIDE</strong> model. The exam expects you to match each hazardous attitude to its antidote <em>verbatim</em> &mdash; these are easy points.</p>"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000008', 'faa70710-0000-0000-0000-000000000002', 'table', '{"headers":["Hazardous attitude","Antidote"],"rows":[["Anti-Authority (\"Don''t tell me!\")","Follow the rules. They are usually right."],["Impulsivity (\"Do something quickly!\")","Not so fast. Think first."],["Invulnerability (\"It won''t happen to me\")","It could happen to me."],["Macho (\"I can do it\")","Taking chances is foolish."],["Resignation (\"What''s the use?\")","I''m not helpless. I can make a difference."]]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000009', 'faa70710-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"CRM (Crew Resource Management) is using all available resources — people, hardware, and information — to operate safely. Brief the crew, define roles (RPIC vs. person manipulating controls vs. visual observer), and keep continuous communication."}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0002-0000-0000-000000000010', 'faa70710-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Memorize 107.51: 400 ft AGL, 87 kt / 100 mph, 3 SM visibility, 500 below / 2,000 horizontal.","107.9: report within 10 calendar days for serious injury/loss of consciousness or over-$500 property damage (excluding the drone).","Alcohol: 8 hours bottle-to-throttle, BAC below 0.04%; one aircraft per pilot; yield to all other aircraft.","Operations over people: Cat 1 = 0.55 lb, Cat 2 = 11 ft-lb, Cat 3 = 25 ft-lb, Cat 4 = airworthiness certificate.","Know the five hazardous attitudes and antidotes verbatim; use IMSAFE/PAVE/DECIDE for risk decisions.","Register every drone individually, mark the number externally, and comply with Remote ID (since Sept 16, 2023)."]}'::jsonb, 10);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70710-0000-0000-0000-000000000003', 'faa70000-0000-0000-0000-000000000007', 'Lesson 3: Airspace & Weather Cram Sheet', '', ARRAY['Class G needs no authorization up to 400 ft AGL; controlled airspace (B, C, D, surface-area E) requires one via LAANC or DroneZone.','Chart colors: solid blue = B, solid magenta = C, dashed blue = D, dashed magenta = E to surface, faded magenta/blue = E floor at 700/1,200 ft AGL.','Blue airport symbol = towered; magenta = non-towered. The MEF is the bold blue quadrangle number.','Decode METARs left to right; wind is degrees-true/knots, visibility in statute miles, heights in hundreds of feet AGL, time in Zulu.','A ceiling is the lowest BKN or OVC layer; a small temp–dewpoint spread means fog or low cloud is likely.','High, hot, and humid raise density altitude and degrade sUAS performance; avoid thunderstorms and microbursts.']::text[], 3, 40, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Identify airspace classes and the sectional-chart symbology that marks them.','Determine whether an airspace authorization is required for a given operation.','Decode each element of a METAR quickly using a reference table.','Recognize TAF change groups and key weather hazards affecting small UAS.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000000', 'faa70710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Reading the sky on paper</h3><p>Airspace and Weather together make up a large slice of the test, and most of those questions reward fast pattern recognition: the <em>color of a ring</em> tells you the airspace class, and the <em>position of a group</em> in a METAR tells you what it means. Use the tables in this lesson as flash-reference and drill them until recall is instant.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000001', 'faa70710-0000-0000-0000-000000000003', 'table', '{"headers":["Airspace class","Drone relevance","Authorization?"],"rows":[["Class A (18,000 ft MSL to FL600)","Not relevant — far above 400 ft AGL","N/A"],["Class B (busiest airports)","Surface up to ~10,000 ft MSL, upside-down wedding cake","Yes"],["Class C (busy airports)","Surface to ~4,000 ft AGL","Yes"],["Class D (towered airports)","Surface to ~2,500 ft AGL","Yes"],["Class E (controlled, lower floors)","Floor at surface, 700, or 1,200 ft AGL","Yes if surface-area E near an airport"],["Class G (uncontrolled)","Default legal sUAS airspace below 400 ft AGL","No"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000002', 'faa70710-0000-0000-0000-000000000003', 'table', '{"headers":["Sectional symbol","Meaning"],"rows":[["Solid blue rings","Class B airspace"],["Solid magenta rings","Class C airspace"],["Dashed blue line","Class D airspace; boxed number = ceiling in hundreds of feet MSL"],["Dashed magenta line","Class E to the surface"],["Faded magenta vignette (fades outward)","Class E floor begins at 700 ft AGL"],["Faded blue vignette","Class E floor begins at 1,200 ft AGL"],["Magenta airport symbol","Airport WITHOUT an operating control tower"],["Blue airport symbol","Airport WITH an operating control tower"],["Bold blue quadrangle number (e.g., 1²5)","Maximum Elevation Figure (MEF), in thousands + hundreds of ft MSL"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000003', 'faa70710-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: Sectional excerpt showing a Class B (solid blue), Class C (solid magenta), and Class D (dashed blue, with boxed ceiling) airport side by side, plus the faded magenta Class E 700-ft AGL vignette."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000004', 'faa70710-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"Authorization rule of thumb: you may fly in Class G up to 400 ft AGL with NO ATC authorization. To fly in controlled airspace (B, C, D, and surface-area E) you MUST obtain an authorization — typically through LAANC or FAADroneZone — before flying."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000005', 'faa70710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>LAANC, UAS Facility Maps, and DroneZone</h3><p><strong>LAANC</strong> (Low Altitude Authorization and Notification Capability) gives near-real-time authorization to fly in controlled airspace up to the altitude posted on the <strong>UAS Facility Map (UASFM)</strong> grid for that location. A <strong>\"0\" grid</strong> means automatic LAANC is unavailable there and a slower further-coordination request to the FAA is required. <strong>FAADroneZone</strong> handles authorizations where LAANC is not available, plus waivers and further coordination, but it is not near-real-time.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000006', 'faa70710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Special use airspace and restrictions</h3><p>Know the categories and what they mean for a drone: <strong>Prohibited Areas (P-)</strong> &mdash; flight prohibited; <strong>Restricted Areas (R-)</strong> &mdash; hazardous activity, enter only with the controlling agency''s permission; <strong>MOAs</strong> &mdash; military training, use caution; <strong>Warning Areas (W-)</strong> &mdash; like restricted but over international waters; <strong>Alert Areas (A-)</strong> &mdash; high training volume. A <strong>TFR</strong> (Temporary Flight Restriction), issued by FDC NOTAM, restricts a defined area (VIP movement, disasters, stadiums); drones must comply, and many TFRs prohibit all UAS. Always check NOTAMs and TFRs before every flight.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>METAR decode &mdash; quick reference</h3><p>A METAR is read left to right; each group has a fixed position. The example below is decoded element by element in the table that follows.</p><p><code>METAR KXYZ 121753Z AUTO 27015G25KT 10SM FEW050 SCT250 27/12 A2992 RMK AO2</code></p>"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000008', 'faa70710-0000-0000-0000-000000000003', 'table', '{"headers":["Group","Example","Meaning"],"rows":[["Report type","METAR","Routine hourly observation (SPECI = special, off-schedule)"],["Station","KXYZ","4-letter ICAO station identifier"],["Date/time","121753Z","12th day, 1753 Zulu (UTC) — aviation weather is in Zulu"],["Modifier","AUTO","Automated station (COR = corrected)"],["Wind","27015G25KT","From 270° true at 15 kt, gusting 25 kt (VRB = variable, 00000KT = calm)"],["Visibility","10SM","10 statute miles"],["Weather","(none shown)","e.g., RA rain, BR mist, FG fog, TS thunderstorm; - light, + heavy"],["Sky condition","FEW050 SCT250","FEW at 5,000 ft, SCT at 25,000 ft; heights in hundreds of ft AGL"],["Temp/Dewpoint","27/12","27°C / 12°C (M prefix = minus); small spread = fog/low cloud likely"],["Altimeter","A2992","29.92 inHg"],["Remarks","RMK AO2","Automated station with a precipitation sensor"]]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000009', 'faa70710-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"Sky-cover coverage: FEW = 1–2 oktas, SCT (scattered) = 3–4, BKN (broken) = 5–7, OVC (overcast) = 8. A CEILING is the lowest BKN or OVC layer. SCT and FEW layers are not ceilings."}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000010', 'faa70710-0000-0000-0000-000000000003', 'table', '{"headers":["TAF change group","Meaning"],"rows":[["FM (FROM)","Rapid, lasting change beginning at a stated time"],["BECMG","Gradual change over a period"],["TEMPO","Temporary fluctuations expected to last less than 1 hour each"],["PROB30 / PROB40","30% or 40% probability of the stated conditions"]]}'::jsonb, 10);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000011', 'faa70710-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"🖼️ Figure (to be added): Figure: A sample METAR with each group labeled (station, Zulu time, wind, visibility, sky condition, temp/dewpoint, altimeter) for quick visual reference."}'::jsonb, 11);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000012', 'faa70710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Weather hazards and density altitude</h3><p><strong>Density altitude</strong> is pressure altitude corrected for non-standard temperature &mdash; the altitude the aircraft \"feels.\" <strong>High, hot, and humid</strong> conditions raise density altitude, thinning the air so the drone makes less lift and thrust: shorter flight time, sluggish climb, reduced payload. Other hazards: <strong>thunderstorms</strong> (avoid entirely &mdash; turbulence, lightning, hail, and microbursts with violent wind shear), <strong>stable air</strong> (stratiform clouds, steady precip, poor visibility, smooth), <strong>unstable air</strong> (cumuliform clouds, showers, good visibility, turbulence), and <strong>fog</strong> when the temperature&ndash;dewpoint spread is small. Cold sharply reduces LiPo battery capacity.</p>"}'::jsonb, 12);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0003-0000-0000-000000000013', 'faa70710-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Class G needs no authorization up to 400 ft AGL; controlled airspace (B, C, D, surface-area E) requires one via LAANC or DroneZone.","Chart colors: solid blue = B, solid magenta = C, dashed blue = D, dashed magenta = E to surface, faded magenta/blue = E floor at 700/1,200 ft AGL.","Blue airport symbol = towered; magenta = non-towered. The MEF is the bold blue quadrangle number.","Decode METARs left to right; wind is degrees-true/knots, visibility in statute miles, heights in hundreds of feet AGL, time in Zulu.","A ceiling is the lowest BKN or OVC layer; a small temp–dewpoint spread means fog or low cloud is likely.","High, hot, and humid raise density altitude and degrade sUAS performance; avoid thunderstorms and microbursts."]}'::jsonb, 13);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('faa70710-0000-0000-0000-000000000004', 'faa70000-0000-0000-0000-000000000007', 'Lesson 4: Final Readiness Checklist & Next Steps', '', ARRAY['After passing, file Form 8710-13 in IACRA; TSA vetting runs automatically; you get a temporary certificate by email, then the permanent card by mail.','The certificate never expires, but you must renew knowledge recency every 24 calendar months via a free online recurrent course.','Recurrent training is online and free — there is no annual in-person retest; keep your completion certificate as proof.','Register every Part 107 drone individually, mark the number externally, carry proof, and comply with Remote ID.','Use B4UFLY, LAANC/DroneZone, and free FAA study materials (Study Guide, ACS, Chart Users'' Guide, AC 00-45) to fly safely and stay sharp.']::text[], 4, 30, '[]'::jsonb, '[]'::jsonb, ARRAY['faa-part107','drone','uas','remote-pilot']::text[], 'published', true, 'approved', true, NULL, ARRAY['Walk through the IACRA certificate application steps after passing the UAG test.','Explain TSA vetting, temporary vs. permanent certificate, and drone registration.','State how and when to complete recurrent training to maintain recency.','Identify free FAA resources and tools for finding where to fly.']::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000000', 'faa70710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>You passed &mdash; now what?</h3><p>Passing the UAG test is the hard part, but it is not the certificate. The knowledge test report is your ticket into the <strong>certificate application</strong>, which you file through <strong>IACRA</strong> (Integrated Airman Certification and Rating Application). This lesson is a checklist for everything between walking out of the test center and legally flying for hire.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000001', 'faa70710-0000-0000-0000-000000000004', 'table', '{"headers":["Step","What you do"],"rows":[["1. Get an FTN","Create an IACRA account to obtain your FAA Tracking Number (do this before or after the test)"],["2. Pass the UAG test","Take and pass at a PSI center; keep your knowledge test report"],["3. File Form 8710-13","Complete the remote pilot application in IACRA using your test report"],["4. TSA vetting","A security background check runs automatically during the application"],["5. Temporary certificate","Receive a temporary remote pilot certificate by email — you may fly once it is issued"],["6. Permanent certificate","The permanent card arrives by mail"],["7. Register the drone","Register each aircraft via FAADroneZone (separate from the certificate)"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000002', 'faa70710-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"Your remote pilot certificate does NOT expire and has no printed expiration date. What you must keep current is your aeronautical knowledge recency — every 24 calendar months."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000003', 'faa70710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Registration and Remote ID before you fly</h3><p>Before the first commercial flight, finish the aircraft-side requirements:</p><ul><li><strong>Register</strong> any sUAS over 0.55 lb (250 g) up to 55 lb. Under Part 107 <strong>every drone is registered individually</strong> with its own number (unlike recreational flyers, who can use one number for their whole fleet).</li><li><strong>Mark</strong> the registration number on the exterior so it is legible without tools, and <strong>carry proof</strong> of registration during operations.</li><li><strong>Comply with Remote ID</strong> (required since Sept 16, 2023): use a standard Remote ID drone, add a broadcast module, or fly within a FRIA.</li></ul>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000004', 'faa70710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Recurrent training &mdash; staying legal</h3><p>To keep flying under Part 107 you must maintain knowledge recency by completing a <strong>free online recurrent training course</strong> on FAASafety.gov <strong>every 24 calendar months</strong>. Since the 2021 rule change, this replaced the old in-person recurrent knowledge test &mdash; there is no retest at a PSI center. The course covers a <strong>night operations</strong> knowledge area. The FAA does not mail a new certificate after recurrent training; you must <strong>retain the course-completion certificate</strong> and be able to present it as proof of currency. \"24 calendar months\" means good through the last day of the 24th month after completion.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000005', 'faa70710-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Common misconception: there is no annual retest. Recurrent training is a FREE online course every 24 calendar months, not a paid in-person exam. Keep your completion certificate as proof — the FAA does not issue a new card."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000006', 'faa70710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Where to fly and free FAA resources</h3><p>Use FAA tools and free study materials to keep flying safely and to deepen your knowledge:</p><ul><li><strong>B4UFLY</strong> &mdash; an app (from FAA-approved providers) showing where you can fly, airspace restrictions, and active TFRs.</li><li><strong>LAANC / FAADroneZone</strong> &mdash; get airspace authorizations for controlled airspace and apply for waivers.</li><li><strong>Remote Pilot sUAS Study Guide (FAA-G-8082-22)</strong> and the <strong>ACS (FAA-S-ACS-10B)</strong> &mdash; the FAA''s own prep book and exact knowledge blueprint.</li><li><strong>UAG Sample Questions (PDF)</strong>, the <strong>Aeronautical Chart Users'' Guide</strong>, and <strong>AC 00-45 (Aviation Weather Services)</strong> &mdash; official, free, and exam-representative.</li></ul>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'link_reference', '{"links":[{"url":"https://www.faa.gov/uas/commercial_operators/become_a_drone_pilot","title":"FAA — Become a Certificated Remote Pilot","type":"website","description":"Authoritative step-by-step certification process."},{"url":"https://www.faa.gov/uas/getting_started/remote_id","title":"FAA — Remote Identification of Drones","type":"website","description":"Remote ID requirements and the three compliance options."},{"url":"https://www.faa.gov/uas/recreational_flyers","title":"FAA — Recreational Flyers & B4UFLY","type":"website","description":"Where-can-I-fly tools and recreational vs. Part 107 differences."}]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('faa70720-0004-0000-0000-000000000008', 'faa70710-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["After passing, file Form 8710-13 in IACRA; TSA vetting runs automatically; you get a temporary certificate by email, then the permanent card by mail.","The certificate never expires, but you must renew knowledge recency every 24 calendar months via a free online recurrent course.","Recurrent training is online and free — there is no annual in-person retest; keep your completion certificate as proof.","Register every Part 107 drone individually, mark the number externally, carry proof, and comply with Remote ID.","Use B4UFLY, LAANC/DroneZone, and free FAA study materials (Study Guide, ACS, Chart Users'' Guide, AC 00-45) to fly safely and stay sharp."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000001', 'UAG exam format', '60 multiple-choice questions, 3 options each, 120 minutes, 70% passing score, taken at a PSI testing center.', '60 / 120 / 70%.', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000002', 'Flag-and-return', 'A pacing strategy: if a question stalls past about a minute, mark your best guess, flag it, move on, and revisit flagged items after a full first pass.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000003', 'Knowledge test report validity', 'The UAG result is valid for 24 calendar months for the purpose of applying for the remote pilot certificate.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000004', 'Distractor elimination', 'Removing implausible or rule-violating answer options to improve guessing odds; knowing the exact rule number usually exposes the two wrong choices.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000005', 'Chart-question workflow', 'Locate the point, identify the airspace by ring/vignette color, decide if an authorization is required, then scan for SUA, obstacles, MEF, and TFRs/NOTAMs.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000006', '107.51 operating limits', '400 ft AGL max altitude, 87 kt (100 mph) max groundspeed, 3 SM minimum visibility, and 500 ft below / 2,000 ft horizontal cloud clearance.', '400 / 87 / 3 / 500-2000.', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000007', '107.9 reporting threshold', 'Report to the FAA within 10 calendar days for any serious injury, loss of consciousness, or property damage over $500 (excluding the drone itself).', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000008', 'Alcohol rule (107.27/107.57)', 'No operating within 8 hours of consuming alcohol, while under the influence, or with a blood-alcohol concentration of 0.04% or greater.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000009', 'Five hazardous attitudes', 'Anti-Authority, Impulsivity, Invulnerability, Macho, and Resignation — each with a memorized antidote.', 'A-I-I-M-R.', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000010', 'Operations over people categories', 'Cat 1 = 0.55 lb or less; Cat 2 = under 11 ft-lb injury; Cat 3 = under 25 ft-lb injury, no open-air assemblies; Cat 4 = airworthiness certificate.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000011', 'Remote ID compliance options', 'Standard Remote ID drone (built-in broadcast), a Remote ID broadcast module retrofit, or flying within a FRIA.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000012', 'Class G authorization', 'Uncontrolled airspace; a Part 107 pilot may fly up to 400 ft AGL with no ATC authorization. It is the default legal sUAS airspace.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000013', 'Sectional ring colors', 'Solid blue = Class B, solid magenta = Class C, dashed blue = Class D, dashed magenta = Class E to the surface.', 'Blue solid = B, magenta solid = C.', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000014', 'Towered vs. non-towered airport symbol', 'A blue airport symbol marks an airport with an operating control tower; a magenta symbol marks one without.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000015', 'METAR ceiling', 'The lowest broken (BKN) or overcast (OVC) cloud layer. FEW and SCT layers do not constitute a ceiling.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000016', 'Density altitude', 'Pressure altitude corrected for non-standard temperature. High, hot, and humid conditions raise it and reduce lift, thrust, and performance.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000017', 'LAANC', 'Low Altitude Authorization and Notification Capability — near-real-time authorization to fly in controlled airspace up to the UAS Facility Map grid altitude.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000018', 'IACRA', 'Integrated Airman Certification and Rating Application — the FAA system where you obtain an FTN and file Form 8710-13 for the remote pilot certificate.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000019', 'Temporary remote pilot certificate', 'Issued by email after the application and TSA vetting clear; lets you fly immediately while the permanent card is mailed.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000020', 'Recurrent training', 'A free online FAASafety.gov course completed every 24 calendar months to maintain aeronautical knowledge recency; replaced the old in-person retest in 2021.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000021', 'Part 107 registration', 'Each drone over 0.55 lb up to 55 lb is registered individually via FAADroneZone, with the number marked on the exterior and proof carried in operations.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('faa70740-0000-0000-0000-000000000022', 'B4UFLY', 'An FAA-approved app that shows where you can fly, airspace restrictions, and active TFRs for trip planning.', NULL, 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'part107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', 'beginner');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000001', 'How many questions are on the UAG knowledge exam, and what is the minimum passing score?', 'multiple_choice', '["60 questions, 70% to pass","50 questions, 80% to pass","100 questions, 70% to pass"]'::jsonb, '60 questions, 70% to pass', 'The UAG test is 60 multiple-choice questions with a 70% passing score (about 42 correct). The other options misstate the count and threshold.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000002', 'You have 120 minutes for 60 questions. About how much time does this allow per question, and what is the best strategy when one question stalls you?', 'multiple_choice', '["About 2 minutes each; flag it and return after a full first pass","About 5 minutes each; solve every question in order before moving on","About 30 seconds each; skip hard questions permanently and leave them blank"]'::jsonb, 'About 2 minutes each; flag it and return after a full first pass', '60 questions in 120 minutes is roughly 2 minutes each. Flag-and-return banks easy points first. Leaving blanks is never correct because there is no penalty for guessing.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000003', 'On a multiple-choice question with three options, why is eliminating one clearly wrong option valuable?', 'multiple_choice', '["It raises a guess from about 33% to about 50%","It is required by the FAA scoring rules","It removes the penalty for guessing"]'::jsonb, 'It raises a guess from about 33% to about 50%', 'With three options a blind guess is ~33%; eliminating one makes it ~50%. There is no guessing penalty to remove, and elimination is a strategy, not a scoring rule.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000004', 'When answering a sectional-chart question, what is the most reliable first step?', 'multiple_choice', '["Locate the specific point in question, then identify the airspace by its ring or vignette color","Assume the airspace is Class G unless a tower is drawn","Start by reading the Maximum Elevation Figure for the whole chart"]'::jsonb, 'Locate the specific point in question, then identify the airspace by its ring or vignette color', 'The workflow is locate the point, identify airspace by color, decide if authorization is needed, then scan for traps. Assuming Class G or starting with the MEF skips the airspace identification.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000005', 'Which item are you NOT allowed to use during the UAG test?', 'multiple_choice', '["Your own personal study notes","The FAA-provided testing supplement","A government-issued photo ID at check-in"]'::jsonb, 'Your own personal study notes', 'The test is closed-book; personal notes, phones, and smartwatches are prohibited. PSI provides the official FAA supplement, and a photo ID is required to check in.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000001', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000006', 'Under 14 CFR 107.51, what is the maximum altitude a small unmanned aircraft may generally be operated above the ground?', 'multiple_choice', '["400 feet AGL","500 feet AGL","1,000 feet AGL"]'::jsonb, '400 feet AGL', '107.51 caps altitude at 400 ft AGL, or up to 400 ft above a structure when within a 400-ft radius of it. 500 and 1,000 ft are common distractor values.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000007', 'What is the maximum allowable groundspeed for a small unmanned aircraft under Part 107?', 'multiple_choice', '["87 knots (100 mph)","100 knots (115 mph)","60 knots (69 mph)"]'::jsonb, '87 knots (100 mph)', '107.51 limits groundspeed to 87 knots, which equals 100 mph. The other values are plausible but incorrect.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000008', 'What is the minimum flight visibility required from the control station under Part 107?', 'multiple_choice', '["3 statute miles","5 statute miles","1 statute mile"]'::jsonb, '3 statute miles', '107.51 requires at least 3 statute miles of flight visibility. 5 SM is the common wrong answer carried over from other rules.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000009', 'What cloud clearance must a small unmanned aircraft maintain under Part 107?', 'multiple_choice', '["500 feet below and 2,000 feet horizontal","1,000 feet below and 2,000 feet horizontal","500 feet below and 1,000 feet horizontal"]'::jsonb, '500 feet below and 2,000 feet horizontal', '107.51 requires staying at least 500 ft below and 2,000 ft horizontally from clouds. The distractors swap in 1,000-ft values.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000010', 'A drone operation causes a person to suffer a serious injury. Within how many days must the remote PIC report this to the FAA?', 'multiple_choice', '["10 calendar days","30 calendar days","Immediately, within 24 hours"]'::jsonb, '10 calendar days', '14 CFR 107.9 requires reporting within 10 calendar days for serious injury, loss of consciousness, or over-$500 property damage. There is no 24-hour or 30-day requirement under 107.9.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000011', 'Your drone strikes a parked car, causing $700 in damage, and no one is injured. Does this require a report to the FAA under 107.9?', 'multiple_choice', '["Yes, because property damage exceeds $500","No, because no one was injured","No, because only the drone and the car were involved"]'::jsonb, 'Yes, because property damage exceeds $500', '107.9 requires a report for damage to property other than the drone when repair cost or fair market value exceeds $500. Injury is not the only trigger; the $700 damage exceeds the threshold.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000012', 'What is the maximum blood-alcohol concentration at which a person may act as remote PIC, and how long after drinking must they wait?', 'multiple_choice', '["Below 0.04% BAC and at least 8 hours after consuming alcohol","Below 0.08% BAC and at least 12 hours after consuming alcohol","Below 0.02% BAC and at least 4 hours after consuming alcohol"]'::jsonb, 'Below 0.04% BAC and at least 8 hours after consuming alcohol', 'Part 107 prohibits operating with a BAC of 0.04% or greater or within 8 hours of consuming alcohol (''8 hours bottle-to-throttle''). 0.08% is the common driving limit and is a distractor.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000013', 'How many small unmanned aircraft may one remote pilot operate at the same time under Part 107?', 'multiple_choice', '["One","Two","As many as the pilot can keep within visual line of sight"]'::jsonb, 'One', 'Under 107.35 a person may not act as remote PIC or manipulate the controls of more than one unmanned aircraft at a time — one aircraft per pilot.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000014', 'A manned helicopter approaches your area of operation. What must you do?', 'multiple_choice', '["Yield the right of way to the manned aircraft","Maintain your altitude and let the helicopter avoid you","Climb above the helicopter to stay clear"]'::jsonb, 'Yield the right of way to the manned aircraft', 'Under 107.37 the small UA must yield right of way to all other aircraft and must not create a collision hazard. The remote pilot always gives way.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000015', 'Which hazardous attitude is correctly paired with its antidote?', 'multiple_choice', '["Impulsivity — ''Not so fast. Think first.''","Macho — ''It could happen to me.''","Resignation — ''Follow the rules. They are usually right.''"]'::jsonb, 'Impulsivity — ''Not so fast. Think first.''', 'Impulsivity''s antidote is ''Not so fast. Think first.'' ''It could happen to me'' is the antidote to Invulnerability, and ''Follow the rules'' is the antidote to Anti-Authority.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000016', 'What is the antidote to the hazardous attitude of Invulnerability?', 'multiple_choice', '["It could happen to me.","Taking chances is foolish.","I''m not helpless. I can make a difference."]'::jsonb, 'It could happen to me.', 'Invulnerability (''it won''t happen to me'') is countered by ''It could happen to me.'' ''Taking chances is foolish'' answers Macho; ''I''m not helpless'' answers Resignation.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000017', 'A pilot thinks, ''The rules don''t apply to me.'' Which hazardous attitude is this, and what is its antidote?', 'multiple_choice', '["Anti-Authority; ''Follow the rules. They are usually right.''","Macho; ''Taking chances is foolish.''","Impulsivity; ''Not so fast. Think first.''"]'::jsonb, 'Anti-Authority; ''Follow the rules. They are usually right.''', '''Don''t tell me'' / ''the rules don''t apply to me'' is Anti-Authority, whose antidote is ''Follow the rules. They are usually right.''', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000018', 'What does the IMSAFE checklist help a remote pilot assess?', 'multiple_choice', '["The pilot''s own fitness to fly (Illness, Medication, Stress, Alcohol, Fatigue, Emotion)","The aircraft''s mechanical condition before flight","The weather and airspace for the operating area"]'::jsonb, 'The pilot''s own fitness to fly (Illness, Medication, Stress, Alcohol, Fatigue, Emotion)', 'IMSAFE is a personal self-assessment of the pilot''s fitness. Aircraft and environment are addressed by other tools such as PAVE and the preflight inspection.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000019', 'To conduct operations over people under Category 1, what is the key requirement for the small unmanned aircraft?', 'multiple_choice', '["It weighs 0.55 pound or less and has no exposed rotating parts that could lacerate skin","It has an airworthiness certificate and an approved Flight Manual","It will not transfer more than 25 ft-lb of kinetic energy on impact"]'::jsonb, 'It weighs 0.55 pound or less and has no exposed rotating parts that could lacerate skin', 'Category 1 requires the aircraft to weigh 0.55 lb (250 g) or less with no lacerating exposed parts and meet Remote ID. Airworthiness certificate is Category 4; 25 ft-lb is Category 3.', 'hard', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000020', 'Since what date has Remote ID broadcast been required for drones that must be registered (unless flown in a FRIA)?', 'multiple_choice', '["September 16, 2023","April 21, 2021","January 1, 2020"]'::jsonb, 'September 16, 2023', 'Remote ID broadcast enforcement began September 16, 2023. April 21, 2021 is the night/operations-over-people rule date, a plausible distractor.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000021', 'How does drone registration differ between recreational flyers and Part 107 operators?', 'multiple_choice', '["Part 107 requires each drone to be registered individually; recreational flyers may use one number for all their drones","Recreational flyers must register each drone individually; Part 107 operators register once","Neither recreational nor Part 107 operators must register drones under 0.55 lb for any purpose"]'::jsonb, 'Part 107 requires each drone to be registered individually; recreational flyers may use one number for all their drones', 'Under Part 107 every aircraft is registered individually. Recreational (44809) flyers may apply one registration number to all their drones. All Part 107 aircraft must be registered regardless of weight.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000022', 'Operating a small UAS from a moving vehicle is permitted under Part 107 under what condition?', 'multiple_choice', '["Only over a sparsely populated area","Only on a closed-course racetrack","Never, under any circumstances"]'::jsonb, 'Only over a sparsely populated area', 'Under 107.25, operating from a moving vehicle is allowed only over a sparsely populated area (and not while transporting property for compensation/hire).', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000023', 'Which of the following is a required action before flight under the preflight rules?', 'multiple_choice', '["Inspect the sUAS to ensure it is in a condition for safe operation","Notify the nearest control tower of every Class G operation","File a flight plan with Flight Service"]'::jsonb, 'Inspect the sUAS to ensure it is in a condition for safe operation', 'The RPIC must perform a preflight inspection to ensure the sUAS is in condition for safe operation. No tower notification or flight plan is required for routine Class G operations.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000024', 'What does CRM (Crew Resource Management) emphasize for a drone operation?', 'multiple_choice', '["Effective use of all available resources — people, hardware, and information — to operate safely","Operating multiple drones simultaneously to cover more area","Letting the most senior crew member make all decisions without input"]'::jsonb, 'Effective use of all available resources — people, hardware, and information — to operate safely', 'CRM is about using all available resources, briefing the crew, defining roles, and maintaining communication. It does not mean flying multiple drones or excluding crew input.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000025', 'A remote pilot feels pressure to finish a job before a storm and decides to push the flight quickly without checking the aircraft. Which hazardous attitude is most at play?', 'multiple_choice', '["Impulsivity","Resignation","Anti-Authority"]'::jsonb, 'Impulsivity', 'Acting on the first thought without proper consideration (''do something quickly'') is Impulsivity; the antidote is ''Not so fast. Think first.''', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000002', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000026', 'On a sectional chart, solid blue concentric rings around a busy airport indicate which class of airspace?', 'multiple_choice', '["Class B","Class C","Class D"]'::jsonb, 'Class B', 'Solid blue rings mark Class B airspace (the busiest airports, an upside-down wedding cake). Class C is solid magenta; Class D is a dashed blue line.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000027', 'A dashed blue line on a sectional chart depicts the lateral boundary of which airspace?', 'multiple_choice', '["Class D","Class E to the surface","Class C"]'::jsonb, 'Class D', 'Class D is shown by a dashed blue line, usually with a boxed ceiling number. Class E to the surface is dashed magenta; Class C is solid magenta.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000028', 'You plan to fly at 350 ft AGL in Class G airspace away from any airport. What authorization do you need?', 'multiple_choice', '["None — Class G up to 400 ft AGL requires no ATC authorization","A LAANC authorization before each flight","A waiver from FAADroneZone"]'::jsonb, 'None — Class G up to 400 ft AGL requires no ATC authorization', 'Class G is uncontrolled; a Part 107 pilot may fly up to 400 ft AGL there with no authorization. Authorizations apply to controlled airspace (B, C, D, surface-area E).', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000029', 'You want to fly in Class D airspace near a towered airport. What must you obtain first?', 'multiple_choice', '["An airspace authorization, typically through LAANC or FAADroneZone","Nothing, as long as you stay below 400 ft AGL","A Remote ID broadcast module only"]'::jsonb, 'An airspace authorization, typically through LAANC or FAADroneZone', 'Controlled airspace (B, C, D, surface-area E) requires an airspace authorization before flying, usually via LAANC or DroneZone. Staying low does not exempt you, and Remote ID is unrelated to airspace access.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000030', 'On a UAS Facility Map, a grid showing ''0'' means what for a LAANC request?', 'multiple_choice', '["Automatic LAANC authorization is unavailable there; a further-coordination request to the FAA is required","You may fly up to 0 ft, meaning no flight is ever allowed","The airspace is Class G and no authorization is needed"]'::jsonb, 'Automatic LAANC authorization is unavailable there; a further-coordination request to the FAA is required', 'A ''0'' grid means automatic LAANC will not approve operations there; the pilot must submit a slower further-coordination request to the FAA. It does not mean flight is banned or that the airspace is Class G.', 'hard', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000031', 'A magenta airport symbol on a sectional chart indicates what about that airport?', 'multiple_choice', '["It does not have an operating control tower","It is a Class C airport","It is restricted to military traffic"]'::jsonb, 'It does not have an operating control tower', 'A magenta airport symbol marks a non-towered airport; a blue symbol marks a towered one. Color of the airport symbol indicates tower status, not airspace class or military use.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000032', 'In the METAR group ''27015G25KT'', what does the wind information mean?', 'multiple_choice', '["Wind from 270 degrees true at 15 knots, gusting to 25 knots","Wind from 027 degrees at 15 knots for 25 minutes","Wind variable between 270 and 025 degrees at 15 knots"]'::jsonb, 'Wind from 270 degrees true at 15 knots, gusting to 25 knots', 'The first three digits are direction in degrees true (270), the next two are speed (15 kt), and ''G25'' is the gust to 25 kt. ''KT'' confirms knots.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000033', 'In a METAR, the time group ''121753Z'' represents what?', 'multiple_choice', '["The 12th day of the month at 1753 Zulu (UTC)","12:17:53 local time","December 17 at 53 minutes past the hour"]'::jsonb, 'The 12th day of the month at 1753 Zulu (UTC)', 'The first two digits are the day (12), the next four are the time in Zulu/UTC (1753), and ''Z'' confirms Zulu. Aviation weather is always reported in UTC.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000034', 'In the METAR sky condition ''BKN015'', what is the cloud height and is it a ceiling?', 'multiple_choice', '["Broken layer at 1,500 ft AGL, and yes it is a ceiling","Broken layer at 15,000 ft AGL, and it is not a ceiling","Broken layer at 150 ft AGL, and it is not a ceiling"]'::jsonb, 'Broken layer at 1,500 ft AGL, and yes it is a ceiling', 'Heights are in hundreds of feet AGL, so ''015'' is 1,500 ft. A broken (BKN) or overcast (OVC) layer is a ceiling; this is the lowest such layer, so it is the ceiling.', 'hard', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000035', 'A METAR reports a temperature and dewpoint that are very close together (a small spread). What weather is most likely?', 'multiple_choice', '["Fog or low clouds","Clear skies with strong gusty winds","Thunderstorms and hail"]'::jsonb, 'Fog or low clouds', 'A small temperature–dewpoint spread means the air is near saturation, favoring fog and low cloud formation. It does not by itself indicate gusty clear conditions or thunderstorms.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000036', 'In a TAF, what does the change indicator ''TEMPO'' signify?', 'multiple_choice', '["Temporary fluctuations expected to last less than 1 hour each","A permanent, rapid change beginning at a stated time","A 40% probability of the stated conditions"]'::jsonb, 'Temporary fluctuations expected to last less than 1 hour each', 'TEMPO marks temporary conditions lasting under an hour. ''FM'' marks a rapid lasting change; ''PROB40'' marks a 40% probability.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000037', 'Which set of conditions produces a HIGH density altitude and degrades drone performance?', 'multiple_choice', '["High elevation, high temperature, and high humidity","Low elevation, cold temperature, and dry air","Sea level, standard temperature, and standard pressure"]'::jsonb, 'High elevation, high temperature, and high humidity', 'High, hot, and humid conditions raise density altitude, thinning the air so the drone produces less lift and thrust. Cold, low, dry conditions lower density altitude and improve performance.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000038', 'Which weather hazard involves an intense, localized downdraft with dangerous, rapidly shifting wind shear that can slam a small UA to the ground?', 'multiple_choice', '["A microburst","A temperature inversion","Radiation fog"]'::jsonb, 'A microburst', 'A microburst is a violent localized downdraft, often associated with thunderstorms, producing severe wind shear. Inversions trap haze; radiation fog reduces visibility but is not a downdraft hazard.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000039', 'A boxed number near a dashed blue ring on a sectional chart most likely indicates what?', 'multiple_choice', '["The ceiling of the Class D airspace in hundreds of feet MSL","The maximum drone altitude allowed there","The CTAF frequency for the airport"]'::jsonb, 'The ceiling of the Class D airspace in hundreds of feet MSL', 'A dashed blue ring is Class D; the boxed number is its ceiling in hundreds of feet MSL. It is not a drone altitude limit or a frequency.', 'hard', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000040', 'A bold blue number such as ''1 5'' (with a smaller second digit) printed in a quadrangle on a sectional chart is the:', 'multiple_choice', '["Maximum Elevation Figure (MEF) for that quadrangle, in thousands and hundreds of feet MSL","Magnetic variation for that region","Pattern altitude for the nearest airport"]'::jsonb, 'Maximum Elevation Figure (MEF) for that quadrangle, in thousands and hundreds of feet MSL', 'The bold blue quadrangle number is the MEF — the highest terrain or obstacle in that block, in thousands and hundreds of feet MSL. It is not magnetic variation or pattern altitude.', 'hard', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000041', 'A Temporary Flight Restriction (TFR) is issued by which mechanism, and how should a drone pilot treat it?', 'multiple_choice', '["By an FDC NOTAM; the drone must comply, and many TFRs prohibit all UAS","By a sectional chart revision only; drones are exempt","By the local airport manager; it applies only to manned aircraft"]'::jsonb, 'By an FDC NOTAM; the drone must comply, and many TFRs prohibit all UAS', 'TFRs are issued via FDC NOTAMs and must be checked before every flight. Drones must comply; many TFRs (e.g., stadiums, VIP movement) prohibit all UAS.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000003', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000042', 'After passing the UAG test, what system do you use to apply for the remote pilot certificate?', 'multiple_choice', '["IACRA (Integrated Airman Certification and Rating Application)","FAADroneZone registration portal","The PSI testing scheduler"]'::jsonb, 'IACRA (Integrated Airman Certification and Rating Application)', 'You file Form 8710-13 through IACRA using your knowledge test report. FAADroneZone is for aircraft registration; PSI schedules the test.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000043', 'What background check runs automatically as part of the remote pilot certificate application?', 'multiple_choice', '["A TSA security vetting","An FBI fingerprint check at a PSI center","A DMV driving-record review"]'::jsonb, 'A TSA security vetting', 'TSA security vetting runs automatically during the IACRA application. There is no separate fingerprinting or DMV review for the certificate.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000044', 'How often must a Part 107 remote pilot complete recurrent training to maintain aeronautical knowledge recency?', 'multiple_choice', '["Every 24 calendar months","Every 12 calendar months","Every 36 calendar months"]'::jsonb, 'Every 24 calendar months', 'Knowledge recency must be renewed every 24 calendar months via a free online recurrent course. 12 and 36 months are distractors.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000045', 'How is current Part 107 recurrent training completed?', 'multiple_choice', '["A free online course on FAASafety.gov","A paid in-person retest at a PSI center","A check ride with an FAA examiner"]'::jsonb, 'A free online course on FAASafety.gov', 'Since the 2021 rule change, recurrency is a free online course; the old paid in-person recurrent knowledge test was eliminated. There is no check ride for sUAS recency.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000046', 'Which statement about the remote pilot certificate''s expiration is correct?', 'multiple_choice', '["The certificate does not expire, but knowledge recency must be renewed every 24 calendar months","The certificate expires after 2 years and a new one is mailed automatically","The certificate expires after 5 years and requires a new UAG test"]'::jsonb, 'The certificate does not expire, but knowledge recency must be renewed every 24 calendar months', 'The certificate has no expiration date; what must stay current is knowledge recency (every 24 calendar months). No new certificate is issued after recurrent training.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000047', 'Under Part 107, how must drones be registered, and what is the weight threshold for required registration?', 'multiple_choice', '["Each drone is registered individually; registration is required for drones over 0.55 lb up to 55 lb","All drones share one registration number; only drones over 5 lb need registration","Registration is optional for commercial operations under 1 lb"]'::jsonb, 'Each drone is registered individually; registration is required for drones over 0.55 lb up to 55 lb', 'Part 107 requires individual registration of each aircraft; drones over 0.55 lb (250 g) up to 55 lb must be registered, and all Part 107 aircraft must be registered regardless of weight.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000048', 'After completing the online recurrent training, what must the remote pilot keep as proof of currency?', 'multiple_choice', '["The course-completion certificate, which they must be able to present","A newly mailed plastic remote pilot certificate from the FAA","A receipt from PSI for the recurrent test fee"]'::jsonb, 'The course-completion certificate, which they must be able to present', 'The FAA does not issue a new certificate after recurrent training; the pilot must retain the course-completion certificate and present it as proof. There is no PSI fee for the online course.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000049', 'Which free tool helps a remote pilot quickly see where they can fly and check active airspace restrictions and TFRs?', 'multiple_choice', '["The B4UFLY app","The IACRA portal","The PSI scheduling site"]'::jsonb, 'The B4UFLY app', 'B4UFLY (from FAA-approved providers) shows where you can fly plus restrictions and active TFRs. IACRA is for applications; PSI schedules tests.', 'easy', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('faa70730-0000-0000-0000-000000000050', 'After your application clears, how do you typically receive authorization to begin flying before your permanent card arrives?', 'multiple_choice', '["A temporary remote pilot certificate is issued by email","You must wait for the permanent card in the mail before flying","You receive a printed certificate at the PSI testing center"]'::jsonb, 'A temporary remote pilot certificate is issued by email', 'Once the application and TSA vetting clear, a temporary certificate is emailed so you can fly immediately; the permanent card follows by mail. PSI does not issue the certificate.', 'medium', 'faa70000-0000-0000-0000-000000000007', 'faa70710-0000-0000-0000-000000000004', 'PART107', ARRAY['faa-part107','drone','uas','remote-pilot']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
